import React, { useEffect, useState } from 'react';
import { supabase } from './supabaseClient';
import { ViewState, Member, Role, Division, Program } from './types';
import { Auth } from './components/Auth';
import { Dashboard } from './pages/Dashboard';
import { Members } from './pages/Members';
import { Divisions } from './pages/Divisions';
import { Programs } from './pages/Programs';
import { Help } from './components/Help';
import { LayoutDashboard, Users, Layers, Briefcase, LogOut } from './components/ui/Icons';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [view, setView] = useState<ViewState>('DASHBOARD');

  // Data State
  const [members, setMembers] = useState<Member[]>([]);
  const [roles, setRoles] = useState<Role[]>([]);
  const [divisions, setDivisions] = useState<Division[]>([]);
  const [programs, setPrograms] = useState<Program[]>([]);
  const [loadingData, setLoadingData] = useState(false);
  const [dbError, setDbError] = useState(false);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
    });

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    return () => subscription.unsubscribe();
  }, []);

  const fetchData = async () => {
    if (!session) return;
    setLoadingData(true);
    setDbError(false);

    try {
      const [membersRes, rolesRes, divisionsRes, programsRes] = await Promise.all([
        supabase.from('members').select('*'),
        supabase.from('roles').select('*'),
        supabase.from('divisions').select('*'),
        supabase.from('programs').select('*')
      ]);

      if (membersRes.error || rolesRes.error || divisionsRes.error || programsRes.error) {
        throw new Error('Database Error');
      }

      setMembers(membersRes.data || []);
      setRoles(rolesRes.data || []);
      setDivisions(divisionsRes.data || []);
      setPrograms(programsRes.data || []);

    } catch (error) {
      console.error('Error fetching data:', error);
      setDbError(true);
    } finally {
      setLoadingData(false);
    }
  };

  useEffect(() => {
    if (session) {
      fetchData();
    }
  }, [session]);

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  if (!session) {
    return <Auth onLogin={() => {}} />;
  }

  const NavItem = ({ id, label, icon: Icon }: { id: ViewState; label: string; icon: any }) => (
    <button
      onClick={() => setView(id)}
      className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition text-sm font-medium ${
        view === id 
          ? 'bg-primary-50 text-primary-700' 
          : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900'
      }`}
    >
      <Icon size={20} />
      <span>{label}</span>
    </button>
  );

  return (
    <div className="flex min-h-screen bg-gray-50">
      {/* Sidebar */}
      <aside className="w-64 bg-white border-r border-gray-200 fixed inset-y-0 left-0 z-20 hidden md:flex flex-col">
        <div className="p-6 border-b border-gray-100">
          <div className="flex items-center space-x-2 text-primary-600">
            <div className="bg-primary-600 p-1.5 rounded-lg text-white">
              <Layers size={20} />
            </div>
            <span className="text-xl font-bold tracking-tight text-gray-900">E-Yayasan</span>
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-1 overflow-y-auto">
          <div className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-2 px-4 mt-2">Menu Utama</div>
          <NavItem id="DASHBOARD" label="Dashboard" icon={LayoutDashboard} />
          <NavItem id="MEMBERS" label="Anggota & Role" icon={Users} />
          <NavItem id="DIVISIONS" label="Bidang" icon={Layers} />
          <NavItem id="PROGRAMS" label="Program Kerja" icon={Briefcase} />
        </nav>

        <div className="p-4 border-t border-gray-100">
          <button
            onClick={handleLogout}
            className="w-full flex items-center space-x-3 px-4 py-2 text-gray-600 hover:text-red-600 hover:bg-red-50 rounded-lg transition text-sm font-medium"
          >
            <LogOut size={20} />
            <span>Keluar</span>
          </button>
        </div>
      </aside>

      {/* Mobile Header (Visible only on small screens) */}
      <div className="md:hidden fixed top-0 w-full bg-white border-b border-gray-200 z-20 px-4 py-3 flex justify-between items-center">
        <span className="font-bold text-gray-900">E-Yayasan</span>
        <button onClick={handleLogout} className="text-gray-500">
          <LogOut size={20} />
        </button>
      </div>

      {/* Main Content */}
      <main className="flex-1 md:ml-64 p-4 md:p-8 mt-12 md:mt-0 overflow-y-auto">
        {dbError && (
           <div className="mb-6 bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg">
             <p className="font-bold">Koneksi Database Gagal</p>
             <p className="text-sm">Gagal mengambil data dari Supabase. Pastikan tabel telah dibuat.</p>
             <Help />
           </div>
        )}

        {!dbError && loadingData ? (
          <div className="flex items-center justify-center h-64 text-gray-400">
            Memuat data...
          </div>
        ) : (
          <div className="max-w-7xl mx-auto animate-in fade-in duration-300">
            {view === 'DASHBOARD' && (
              <Dashboard members={members} programs={programs} divisions={divisions} />
            )}
            {view === 'MEMBERS' && (
              <Members 
                data={members} 
                roles={roles} 
                divisions={divisions} 
                onRefresh={fetchData} 
              />
            )}
            {view === 'DIVISIONS' && (
              <Divisions 
                data={divisions} 
                onRefresh={fetchData} 
              />
            )}
            {view === 'PROGRAMS' && (
              <Programs 
                data={programs} 
                divisions={divisions} 
                onRefresh={fetchData} 
              />
            )}
          </div>
        )}
      </main>

      {/* Mobile Bottom Nav */}
      <div className="md:hidden fixed bottom-0 w-full bg-white border-t border-gray-200 z-20 flex justify-around p-2">
        <button onClick={() => setView('DASHBOARD')} className={`p-2 rounded ${view === 'DASHBOARD' ? 'text-primary-600' : 'text-gray-400'}`}><LayoutDashboard size={24}/></button>
        <button onClick={() => setView('MEMBERS')} className={`p-2 rounded ${view === 'MEMBERS' ? 'text-primary-600' : 'text-gray-400'}`}><Users size={24}/></button>
        <button onClick={() => setView('DIVISIONS')} className={`p-2 rounded ${view === 'DIVISIONS' ? 'text-primary-600' : 'text-gray-400'}`}><Layers size={24}/></button>
        <button onClick={() => setView('PROGRAMS')} className={`p-2 rounded ${view === 'PROGRAMS' ? 'text-primary-600' : 'text-gray-400'}`}><Briefcase size={24}/></button>
      </div>
    </div>
  );
};

export default App;

