);

-- 4. Buat Tabel Programs (Program Kerja)
create table if not exists public.programs (
  id uuid default gen_random_uuid() primary key,
  name text not null,
  cost numeric default 0,
  month text,
  status text check (status in ('Planned', 'In Progress', 'Completed')),
  division_id uuid references public.divisions(id) on delete cascade
);

-- 5. Mengaktifkan Row Level Security (RLS) dan Policy
-- Catatan: Policy ini membuka akses penuh (public).
-- Untuk produksi, ganti 'true' dengan kondisi auth yang sesuai, misal: auth.role() = 'authenticated'

alter table public.roles enable row level security;
create policy "Enable all access for roles" on public.roles for all using (true) with check (true);

alter table public.divisions enable row level security;
create policy "Enable all access for divisions" on public.divisions for all using (true) with check (true);

alter table public.members enable row level security;
create policy "Enable all access for members" on public.members for all using (true) with check (true);

alter table public.programs enable row level security;
create policy "Enable all access for programs" on public.programs for all using (true) with check (true);

