import React, { useState } from 'react';
import { supabase } from '../supabaseClient';
import { Organization } from '../types';
import { Plus, Edit, Trash2, Building2 } from '../components/ui/Icons';
import { Modal } from '../components/Modal';

interface OrganizationsProps {
  data: Organization[];
  onRefresh: () => void;
}

export const Organizations: React.FC<OrganizationsProps> = ({ data, onRefresh }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<Organization | null>(null);

  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [loading, setLoading] = useState(false);

  const handleOpen = (org?: Organization) => {
    if (org) {
      setEditingItem(org);
      setName(org.name);
      setDescription(org.description || '');
    } else {
      setEditingItem(null);
      setName('');
      setDescription('');
    }
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    const payload = { name, description };

    try {
