import React, { useEffect, useState } from 'react';
import { supabase } from './supabaseClient';
import { ViewState, Member, Role, Division, Program, Organization } from './types';
import { Auth } from './components/Auth';
import { Dashboard } from './pages/Dashboard';
import { Members } from './pages/Members';
import { Divisions } from './pages/Divisions';
import { Organizations } from './pages/Organizations';
import { Programs } from './pages/Programs';
import { Roles } from './pages/Roles';
import { Help } from './components/Help';
import { 
  LayoutDashboard, 
  Users, 
  Layers, 
  Briefcase, 
  LogOut, 
  Sun, 
  Moon, 
  Building2, 
  ShieldCheck,
  ChevronLeft,
  ChevronRight
} from './components/ui/Icons';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [view, setView] = useState<ViewState>('DASHBOARD');
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);

  // Theme State
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('theme') as 'light' | 'dark' || 'light';
    }
    return 'light';
  });

  // Data State
  const [members, setMembers] = useState<Member[]>([]);
  const [roles, setRoles] = useState<Role[]>([]);
  const [divisions, setDivisions] = useState<Division[]>([]);
  const [organizations, setOrganizations] = useState<Organization[]>([]);
  const [programs, setPrograms] = useState<Program[]>([]);
  const [loadingData, setLoadingData] = useState(false);
  const [dbError, setDbError] = useState(false);

  // Theme Effect
  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
    });

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    return () => subscription.unsubscribe();
  }, []);

  const fetchData = async () => {
    if (!session) return;
    setLoadingData(true);
    setDbError(false);

    try {
      const [membersRes, rolesRes, divisionsRes, programsRes, orgsRes] = await Promise.all([
        supabase.from('members').select('*'),
        supabase.from('roles').select('*'),
        supabase.from('divisions').select('*'),
        supabase.from('programs').select('*'),
        supabase.from('organizations').select('*')
      ]);

      if (membersRes.error || rolesRes.error || divisionsRes.error || programsRes.error || orgsRes.error) {
        throw new Error('Database Error');
      }

      setMembers(membersRes.data || []);
      setRoles(rolesRes.data || []);
      setDivisions(divisionsRes.data || []);
      setPrograms(programsRes.data || []);
      setOrganizations(orgsRes.data || []);

    } catch (error) {
      console.error('Error fetching data:', error);
      setDbError(true);
    } finally {
      setLoadingData(false);
    }
  };

  useEffect(() => {
    if (session) {
      fetchData();
    }
  }, [session]);

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  if (!session) {
    return <Auth onLogin={() => {}} />;
  }

  const NavItem = ({ id, label, icon: Icon }: { id: ViewState; label: string; icon: any }) => (
    <button
      onClick={() => setView(id)}
      title={isSidebarCollapsed ? label : ''}
      className={`w-full flex items-center ${isSidebarCollapsed ? 'justify-center px-2' : 'space-x-3 px-4'} py-3 rounded-lg transition text-sm font-medium ${
        view === id 
          ? 'bg-primary-50 dark:bg-primary-900/30 text-primary-700 dark:text-primary-400' 
          : 'text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 hover:text-gray-900 dark:hover:text-gray-200'
      }`}
    >
      <Icon size={20} className="shrink-0" />
      {!isSidebarCollapsed && <span>{label}</span>}
    </button>
  );

  return (
    <div className="flex min-h-screen bg-gray-50 dark:bg-dark-bg transition-colors duration-200">
      {/* Sidebar (Desktop) */}
      <aside 
        className={`${isSidebarCollapsed ? 'w-20' : 'w-64'} bg-white dark:bg-dark-card border-r border-gray-200 dark:border-dark-border fixed inset-y-0 left-0 z-20 hidden md:flex flex-col transition-all duration-300 ease-in-out`}
      >
        <div className={`p-6 border-b border-gray-100 dark:border-dark-border flex items-center ${isSidebarCollapsed ? 'justify-center' : 'justify-between'}`}>
          {!isSidebarCollapsed && (
            <div className="flex items-center space-x-2 text-primary-600 dark:text-primary-400 animate-in fade-in duration-300">
              <div className="bg-primary-600 dark:bg-primary-500 p-1.5 rounded-lg text-white">
                <Layers size={20} />
              </div>
              <span className="text-xl font-bold tracking-tight text-gray-900 dark:text-white">E-Yayasan</span>
            </div>
          )}
          {isSidebarCollapsed && (
             <div className="bg-primary-600 dark:bg-primary-500 p-1.5 rounded-lg text-white">
                <Layers size={20} />
             </div>
          )}
        </div>

        {/* Toggle Button */}
        <button 
            onClick={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
            className="absolute -right-3 top-20 bg-white dark:bg-gray-700 border border-gray-200 dark:border-gray-600 rounded-full p-1 shadow-sm hover:bg-gray-50 dark:hover:bg-gray-600 text-gray-500 dark:text-gray-300"
        >
            {isSidebarCollapsed ? <ChevronRight size={14} /> : <ChevronLeft size={14} />}
        </button>

        <nav className="flex-1 p-3 space-y-2 overflow-y-auto overflow-x-hidden mt-4">
          {!isSidebarCollapsed && (
            <div className="text-xs font-semibold text-gray-400 dark:text-gray-500 uppercase tracking-wider mb-2 px-4 transition-opacity duration-300">
              Menu Utama
            </div>
          )}
          <NavItem id="DASHBOARD" label="Dashboard" icon={LayoutDashboard} />
          <NavItem id="ORGANIZATIONS" label="Organisasi" icon={Building2} />
          <NavItem id="MEMBERS" label="Anggota" icon={Users} />
          <NavItem id="ROLES" label="Role / Peran" icon={ShieldCheck} />
          <NavItem id="DIVISIONS" label="Bidang" icon={Layers} />
          <NavItem id="PROGRAMS" label="Program Kerja" icon={Briefcase} />
        </nav>

        <div className="p-4 border-t border-gray-100 dark:border-dark-border space-y-2">
          <button
            onClick={toggleTheme}
            title={isSidebarCollapsed ? (theme === 'light' ? 'Mode Gelap' : 'Mode Terang') : ''}
            className={`w-full flex items-center ${isSidebarCollapsed ? 'justify-center px-2' : 'space-x-3 px-4'} py-2 text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded-lg transition text-sm font-medium`}
          >
            {theme === 'light' ? <Moon size={20} /> : <Sun size={20} />}
            {!isSidebarCollapsed && <span>{theme === 'light' ? 'Mode Gelap' : 'Mode Terang'}</span>}
          </button>

          <button
            onClick={handleLogout}
            title={isSidebarCollapsed ? 'Keluar' : ''}
            className={`w-full flex items-center ${isSidebarCollapsed ? 'justify-center px-2' : 'space-x-3 px-4'} py-2 text-gray-600 dark:text-gray-400 hover:text-red-600 dark:hover:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition text-sm font-medium`}
          >
            <LogOut size={20} />
            {!isSidebarCollapsed && <span>Keluar</span>}
          </button>
        </div>
      </aside>

      {/* Mobile Header (Visible only on small screens) */}
      <div className="md:hidden fixed top-0 w-full bg-white dark:bg-dark-card border-b border-gray-200 dark:border-dark-border z-20 px-4 py-3 flex justify-between items-center transition-colors duration-200">
        <span className="font-bold text-gray-900 dark:text-white">E-Yayasan</span>
        <div className="flex gap-2">
           <button onClick={toggleTheme} className="text-gray-500 dark:text-gray-400">
             {theme === 'light' ? <Moon size={20} /> : <Sun size={20} />}
           </button>
           <button onClick={handleLogout} className="text-gray-500 dark:text-gray-400">
            <LogOut size={20} />
          </button>
        </div>
      </div>

      {/* Main Content */}
      <main className={`flex-1 ${isSidebarCollapsed ? 'md:ml-20' : 'md:ml-64'} p-4 md:p-8 mt-12 md:mt-0 overflow-y-auto transition-all duration-300 ease-in-out`}>
        {dbError && (
           <div className="mb-6 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 text-red-700 dark:text-red-400 px-4 py-3 rounded-lg">
             <p className="font-bold">Koneksi Database Gagal</p>
             <p className="text-sm">Gagal mengambil data dari Supabase. Pastikan tabel telah dibuat.</p>
             <Help />
           </div>
        )}

        {!dbError && loadingData ? (
          <div className="flex items-center justify-center h-64 text-gray-400">
            Memuat data...
          </div>
        ) : (
          <div className="max-w-7xl mx-auto animate-in fade-in duration-300">
            {view === 'DASHBOARD' && (
              <Dashboard members={members} programs={programs} divisions={divisions} isDarkMode={theme === 'dark'} />
            )}
            {view === 'ORGANIZATIONS' && (
              <Organizations 
                data={organizations} 
                onRefresh={fetchData} 
              />
            )}
            {view === 'MEMBERS' && (
              <Members 
                data={members} 
                roles={roles} 
                divisions={divisions} 
                organizations={organizations}
                onRefresh={fetchData} 
                currentUserEmail={session?.user?.email}
              />
            )}
            {view === 'ROLES' && (
              <Roles 
                data={roles} 
                onRefresh={fetchData} 
              />
            )}
            {view === 'DIVISIONS' && (
              <Divisions 
                data={divisions} 
                onRefresh={fetchData} 
              />
            )}
            {view === 'PROGRAMS' && (
              <Programs 
                data={programs} 
                divisions={divisions} 
                organizations={organizations}
                onRefresh={fetchData} 
              />
            )}
          </div>
        )}
      </main>

      {/* Mobile Bottom Nav */}
      <div className="md:hidden fixed bottom-0 w-full bg-white dark:bg-dark-card border-t border-gray-200 dark:border-dark-border z-20 flex justify-around p-2 transition-colors duration-200 overflow-x-auto">
        <button onClick={() => setView('DASHBOARD')} className={`p-2 rounded ${view === 'DASHBOARD' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><LayoutDashboard size={20}/></button>
        <button onClick={() => setView('ORGANIZATIONS')} className={`p-2 rounded ${view === 'ORGANIZATIONS' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><Building2 size={20}/></button>
        <button onClick={() => setView('MEMBERS')} className={`p-2 rounded ${view === 'MEMBERS' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><Users size={20}/></button>
        <button onClick={() => setView('PROGRAMS')} className={`p-2 rounded ${view === 'PROGRAMS' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><Briefcase size={20}/></button>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { supabase } from '../supabaseClient';
import { Program, Division, Organization } from '../types';
import { Plus, Edit, Trash2, Calendar, Briefcase, Wallet, Filter, AlertTriangle, X, Layers, CheckSquare, Square, Building2 } from '../components/ui/Icons';
import { Modal } from '../components/Modal';

interface ProgramsProps {
  data: Program[];
  divisions: Division[];
  organizations: Organization[];
  onRefresh: () => void;
}

export const Programs: React.FC<ProgramsProps> = ({ data, divisions, organizations, onRefresh }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<Program | null>(null);

  // Description View Modal
  const [descModal, setDescModal] = useState<{isOpen: boolean, text: string, title: string}>({ isOpen: false, text: '', title: '' });

  // Filter State
  const [filterDivisionId, setFilterDivisionId] = useState('');
  const [filterOrgId, setFilterOrgId] = useState('');
  const [filterYear, setFilterYear] = useState<number | ''>('');
  const [filterMonths, setFilterMonths] = useState<string[]>([]); // Multi select

  // Delete Confirmation State
  const [deleteConfirm, setDeleteConfirm] = useState<{isOpen: boolean, id: string | null}>({ isOpen: false, id: null });

  // Form State
  const [name, setName] = useState('');
  const [description, setDescription] = useState(''); // New State
  const [costPerMonth, setCostPerMonth] = useState<number>(0);
  const [selectedMonths, setSelectedMonths] = useState<string[]>([]);
  const [divisionId, setDivisionId] = useState('');
  const [organizationId, setOrganizationId] = useState('');
  const [year, setYear] = useState<number>(new Date().getFullYear());
  const [status, setStatus] = useState<'Planned' | 'In Progress' | 'Completed'>('Planned');
  const [loading, setLoading] = useState(false);

  const allMonths = [
    'Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni', 
    'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'
  ];

  // Get unique years for filter
  const availableYears = useMemo(() => {
    const years = new Set(data.map(p => p.year || 2024));
    return Array.from(years).sort((a: number, b: number) => b - a);
  }, [data]);

  // Helper: Parse Month
  const parseMonths = (monthStr: string): string[] => {
    try {
      const parsed = JSON.parse(monthStr);
      return Array.isArray(parsed) ? parsed : [monthStr];
    } catch (e) {
      return monthStr ? [monthStr] : [];
    }
  };

  // --- FILTERING & STATISTICS LOGIC ---

  const filteredData = useMemo(() => {
    return data.filter(item => {
      const itemMonths = parseMonths(item.month);

      const matchDivision = filterDivisionId ? item.division_id === filterDivisionId : true;
      const matchOrg = filterOrgId ? item.organization_id === filterOrgId : true;
      const matchYear = filterYear ? (item.year || 2024) === Number(filterYear) : true;

      // Filter Month logic: If filter has selected months, show items that have AT LEAST ONE of those months
      const matchMonth = filterMonths.length > 0 
        ? itemMonths.some(m => filterMonths.includes(m))
        : true;

      return matchDivision && matchOrg && matchYear && matchMonth;
    });
  }, [data, filterDivisionId, filterOrgId, filterYear, filterMonths]);

  const stats = useMemo(() => {
    const totalCost = filteredData.reduce((acc, curr) => acc + curr.cost, 0);
    const totalPrograms = filteredData.length;
    // Get unique division names involved in the filtered view
    const uniqueDivisionIds = new Set(filteredData.map(p => p.division_id));
    const divisionNames = Array.from(uniqueDivisionIds)
      .map(id => divisions.find(d => d.id === id)?.name)
      .filter(Boolean)
      .join(', ');

    return { totalCost, totalPrograms, divisionNames };
  }, [filteredData, divisions]);

  // --- HANDLERS ---

  const handleOpen = (program?: Program) => {
    if (program) {
      setEditingItem(program);
      setName(program.name);
      setDescription(program.description || '');

      const months = parseMonths(program.month);
      setSelectedMonths(months);

      const count = months.length || 1;
      setCostPerMonth(program.cost / count);

      setDivisionId(program.division_id);
      setOrganizationId(program.organization_id || '');
      setYear(program.year || new Date().getFullYear());
      setStatus(program.status);
    } else {
      setEditingItem(null);
      setName('');
      setDescription('');
      setCostPerMonth(0);
      setSelectedMonths([allMonths[new Date().getMonth()]]);
      setDivisionId(divisions[0]?.id || '');
      setOrganizationId(organizations[0]?.id || '');
      setYear(new Date().getFullYear());
      setStatus('Planned');
    }
    setIsModalOpen(true);
  };

  const toggleMonthSelection = (month: string, isFilter: boolean = false) => {
    const setState = isFilter ? setFilterMonths : setSelectedMonths;
    const currentState = isFilter ? filterMonths : selectedMonths;

    if (currentState.includes(month)) {
        setState(currentState.filter(m => m !== month));
    } else {
        const newSelection = [...currentState, month];
        // Sort chronologically
        setState(newSelection.sort((a, b) => allMonths.indexOf(a) - allMonths.indexOf(b)));
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    if (selectedMonths.length === 0) {
      alert("Pilih setidaknya satu bulan.");
      setLoading(false);
      return;
    }

    const totalCost = costPerMonth * selectedMonths.length;
    const monthString = JSON.stringify(selectedMonths);

    const payload = {
      name,
      description,
      cost: totalCost,
      month: monthString,
      division_id: divisionId,
      organization_id: organizationId || null,
      year: year,
      status
    };

    try {
      if (editingItem) {
        const { error } = await supabase.from('programs').update(payload).eq('id', editingItem.id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from('programs').insert([payload]);
        if (error) throw error;
      }
      onRefresh();
      setIsModalOpen(false);
    } catch (error: any) {
      alert('Error: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  // Custom Delete Handler
  const confirmDelete = (id: string) => {
    setDeleteConfirm({ isOpen: true, id });
  };

  const executeDelete = async () => {
    if (!deleteConfirm.id) return;
    try {
      const { error } = await supabase.from('programs').delete().eq('id', deleteConfirm.id);
      if (error) throw error;
      onRefresh();
      setDeleteConfirm({ isOpen: false, id: null });
    } catch (error: any) {
      alert('Error: ' + error.message);
    }
  };

  const formatCurrency = (val: number) => new Intl.NumberFormat('id-ID', { style: 'currency', currency: 'IDR', maximumFractionDigits: 0 }).format(val);

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'Completed': return 'bg-green-100 dark:bg-green-900/40 text-green-800 dark:text-green-300';
      case 'In Progress': return 'bg-blue-100 dark:bg-blue-900/40 text-blue-800 dark:text-blue-300';
      default: return 'bg-gray-100 dark:bg-gray-700 text-gray-800 dark:text-gray-300';
    }
  };

  const resetFilters = () => {
    setFilterDivisionId('');
    setFilterOrgId('');
    setFilterYear('');
    setFilterMonths([]);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
          <Briefcase className="text-primary-600 dark:text-primary-400" /> Program Kerja
        </h2>
        <button
          onClick={() => handleOpen()}
          className="bg-primary-600 hover:bg-primary-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition shadow-sm w-full sm:w-auto justify-center"
        >
          <Plus size={18} /> Tambah Program
        </button>
      </div>

      {/* --- STATS SUMMARY & FILTERS --- */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* Left: Summary Cards */}
        <div className="lg:col-span-2 grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="bg-gradient-to-br from-blue-500 to-blue-600 dark:from-blue-600 dark:to-blue-800 p-5 rounded-xl text-white shadow-md">
            <div className="flex justify-between items-start">
               <div>
                  <p className="text-blue-100 text-sm font-medium mb-1">Total Anggaran (Tersaring)</p>
                  <h3 className="text-3xl font-bold">{formatCurrency(stats.totalCost)}</h3>
               </div>
               <div className="p-2 bg-white/20 rounded-lg">
                 <Wallet size={24} className="text-white" />
               </div>
            </div>
            <p className="text-sm text-blue-100 mt-4 flex items-center gap-1">
              <Layers size={14} /> 
              {stats.divisionNames ? `Bidang: ${stats.divisionNames}` : 'Semua Bidang'}
            </p>
          </div>

          <div className="bg-white dark:bg-dark-card p-5 rounded-xl border border-gray-100 dark:border-dark-border shadow-sm flex flex-col justify-center">
             <div className="flex items-center gap-3 mb-2">
               <div className="p-2 bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400 rounded-lg">
                 <Briefcase size={20} />
               </div>
               <span className="text-gray-500 dark:text-gray-400 text-sm">Jumlah Program</span>
             </div>
             <p className="text-2xl font-bold text-gray-800 dark:text-white pl-1">{stats.totalPrograms} <span className="text-sm font-normal text-gray-500">Program</span></p>
             <p className="text-xs text-gray-400 mt-2 pl-1">
                {(filterDivisionId || filterOrgId || filterYear || filterMonths.length > 0) ? 'Hasil filter diterapkan' : 'Menampilkan semua data'}
             </p>
          </div>
        </div>

        {/* Right: Filters */}
        <div className="bg-white dark:bg-dark-card p-5 rounded-xl border border-gray-100 dark:border-dark-border shadow-sm">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-2 text-gray-800 dark:text-white font-semibold">
              <Filter size={18} /> Filter Data
            </div>
            {(filterDivisionId || filterOrgId || filterYear || filterMonths.length > 0) && (
               <button 
                 onClick={resetFilters}
                 className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1"
               >
                 <X size={12} /> Reset
               </button>
             )}
          </div>

          <div className="space-y-3">
             <div className="grid grid-cols-2 gap-2">
                <div>
                   <label className="text-xs text-gray-500 dark:text-gray-400 mb-1 block">Tahun</label>
                   <select 
                      className="w-full text-sm bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg px-2 py-2 text-gray-700 dark:text-gray-200 focus:ring-2 focus:ring-primary-500 outline-none"
                      value={filterYear}
                      onChange={(e) => setFilterYear(Number(e.target.value) || '')}
                    >
                      <option value="">Semua</option>
                      {availableYears.map(y => (
                        <option key={y} value={y}>{y}</option>
                      ))}
                   </select>
                </div>
                <div>
                    <label className="text-xs text-gray-500 dark:text-gray-400 mb-1 block">Organisasi</label>
                    <select 
                        className="w-full text-sm bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg px-2 py-2 text-gray-700 dark:text-gray-200 focus:ring-2 focus:ring-primary-500 outline-none"
                        value={filterOrgId}
                        onChange={(e) => setFilterOrgId(e.target.value)}
                        >
                        <option value="">Semua</option>
                        {organizations.map(o => (
                            <option key={o.id} value={o.id}>{o.name}</option>
                        ))}
                    </select>
                </div>
             </div>

             <div>
               <label className="text-xs text-gray-500 dark:text-gray-400 mb-1 block">Bidang</label>
               <select 
                  className="w-full text-sm bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg px-3 py-2 text-gray-700 dark:text-gray-200 focus:ring-2 focus:ring-primary-500 outline-none"
                  value={filterDivisionId}
                  onChange={(e) => setFilterDivisionId(e.target.value)}
                >
                  <option value="">Semua Bidang</option>
                  {divisions.map(d => (
                    <option key={d.id} value={d.id}>{d.name}</option>
                  ))}
               </select>
             </div>

             <div>
                <label className="text-xs text-gray-500 dark:text-gray-400 mb-1 block">Filter Bulan (Multi Select)</label>
                <div className="flex flex-wrap gap-1 max-h-24 overflow-y-auto">
                    {allMonths.map(m => {
                        const isSelected = filterMonths.includes(m);
                        return (
                            <button
                                key={m}
                                onClick={() => toggleMonthSelection(m, true)}
                                className={`text-[10px] px-2 py-1 rounded-full border ${
                                    isSelected 
                                    ? 'bg-blue-100 border-blue-200 text-blue-700 dark:bg-blue-900/40 dark:border-blue-800 dark:text-blue-300' 
                                    : 'bg-gray-50 border-gray-200 text-gray-600 dark:bg-gray-800 dark:border-gray-700 dark:text-gray-400'
                                }`}
                            >
                                {m.substring(0, 3)}
                            </button>
                        )
                    })}
                </div>
             </div>
          </div>
        </div>
      </div>

      {/* --- TABLE --- */}
      <div className="bg-white dark:bg-dark-card rounded-xl shadow-sm border border-gray-100 dark:border-dark-border overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-gray-50 dark:bg-gray-800 text-gray-600 dark:text-gray-400 text-xs uppercase font-semibold">
              <tr>
                <th className="px-6 py-4">Nama Program</th>
                <th className="px-6 py-4">Tahun & Org</th>
                <th className="px-6 py-4">Jadwal</th>
                <th className="px-6 py-4">Biaya</th>
                <th className="px-6 py-4">Bidang</th>
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4 text-right">Aksi</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-dark-border">
              {filteredData.map((item) => {
                const months = parseMonths(item.month);
                const monthsCount = months.length;
                const unitCost = item.cost / (monthsCount || 1);

                return (
                <tr key={item.id} className="hover:bg-gray-50 dark:hover:bg-gray-800/50 transition">
                  <td className="px-6 py-4">
                    <div className="font-medium text-gray-900 dark:text-white">{item.name}</div>
                    {item.description && (
                        <div 
                          className="text-xs text-gray-500 dark:text-gray-400 mt-1 line-clamp-2 max-w-xs cursor-pointer hover:text-blue-600 dark:hover:text-blue-400 hover:underline"
                          onClick={() => setDescModal({isOpen: true, text: item.description || '', title: item.name})}
                        >
                            {item.description}
                        </div>
                    )}
                  </td>
                  <td className="px-6 py-4">
                    <div className="text-sm font-semibold text-gray-900 dark:text-white">{item.year || 2024}</div>
                    <div className="text-xs text-gray-500 dark:text-gray-400 mt-1">
                        {organizations.find(o => o.id === item.organization_id)?.name || 'N/A'}
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm text-gray-600 dark:text-gray-300 min-w-[160px]">
                    <div className="flex flex-wrap gap-1">
                      {months.map(m => (
                        <span key={m} className={`px-1.5 py-0.5 rounded text-xs ${
                          filterMonths.includes(m)
                            ? 'bg-primary-100 text-primary-700 dark:bg-primary-900/50 dark:text-primary-300 font-bold ring-1 ring-primary-200' 
                            : 'bg-gray-100 dark:bg-gray-700'
                        }`}>
                          {m.substring(0, 3)}
                        </span>
                      ))}
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm">
                    <div className="font-bold text-gray-800 dark:text-white">{formatCurrency(item.cost)}</div>
                    <div className="text-xs text-gray-500 dark:text-gray-400">
                      {formatCurrency(unitCost)} x {monthsCount} bln
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm text-gray-600 dark:text-gray-400">
                    {divisions.find(d => d.id === item.division_id)?.name || '-'}
                  </td>
                  <td className="px-6 py-4">
                    <span className={`px-2 py-1 rounded-full text-xs font-semibold ${getStatusColor(item.status)}`}>
                      {item.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex justify-end gap-2">
                      <button onClick={() => handleOpen(item)} className="text-gray-400 hover:text-blue-600 dark:hover:text-blue-400">
                        <Edit size={18} />
                      </button>
                      <button onClick={() => confirmDelete(item.id)} className="text-gray-400 hover:text-red-600 dark:hover:text-red-400">
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </td>
                </tr>
              )})}
              {filteredData.length === 0 && (
                <tr>
                  <td colSpan={7} className="px-6 py-12 text-center text-gray-500 dark:text-gray-400">
                    <div className="flex flex-col items-center justify-center">
                      <Briefcase size={40} className="text-gray-300 dark:text-gray-600 mb-2" />
                      <p>Tidak ada program yang ditemukan.</p>
                      {(filterDivisionId || filterOrgId || filterYear || filterMonths.length > 0) && <p className="text-xs mt-1">Coba reset filter anda.</p>}
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* --- FORM MODAL --- */}
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={editingItem ? 'Edit Program' : 'Tambah Program'}>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Nama Program</label>
            <input
              type="text"
              required
              value={name}
              onChange={e => setName(e.target.value)}
              className="mt-1 block w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 dark:text-white px-3 py-2 focus:border-primary-500 focus:ring-primary-500 outline-none"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Keterangan</label>
            <textarea
              rows={2}
              value={description}
              onChange={e => setDescription(e.target.value)}
              className="mt-1 block w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 dark:text-white px-3 py-2 focus:border-primary-500 focus:ring-primary-500 outline-none"
              placeholder="Tambahkan detail program..."
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Tahun</label>
                <input
                type="number"
                required
                value={year}
                onChange={e => setYear(Number(e.target.value))}
                className="mt-1 block w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 dark:text-white px-3 py-2 focus:border-primary-500 focus:ring-primary-500 outline-none"
                />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Organisasi</label>
              <select
                value={organizationId}
                onChange={e => setOrganizationId(e.target.value)}
                className="mt-1 block w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 dark:text-white px-3 py-2 focus:border-primary-500 focus:ring-primary-500 outline-none"
              >
                <option value="">Pilih Organisasi</option>
                {organizations.map(o => <option key={o.id} value={o.id}>{o.name}</option>)}
              </select>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Estimasi Biaya (Per Bulan)</label>
              <div className="relative">
                <span className="absolute inset-y-0 left-0 pl-3 flex items-center text-gray-500 dark:text-gray-400">Rp</span>
                <input
                  type="number"
                  min="0"
                  required
                  value={costPerMonth}
                  onChange={e => setCostPerMonth(Number(e.target.value))}
                  className="block w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 dark:text-white pl-10 pr-3 py-2 focus:border-primary-500 focus:ring-primary-500 outline-none"
                />
              </div>
            </div>

            <div className="bg-blue-50 dark:bg-blue-900/20 p-3 rounded-lg border border-blue-100 dark:border-blue-800">
              <label className="block text-xs font-semibold text-blue-800 dark:text-blue-300 uppercase mb-1">Total Biaya</label>
              <div className="flex items-center gap-2">
                <Wallet size={16} className="text-blue-600 dark:text-blue-400" />
                <span className="text-lg font-bold text-blue-700 dark:text-blue-300">
                  {formatCurrency(costPerMonth * selectedMonths.length)}
                </span>
              </div>
              <p className="text-xs text-blue-600 dark:text-blue-400 mt-1">
                {selectedMonths.length} bulan terpilih
              </p>
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Pilih Bulan Pelaksanaan</label>
            <div className="grid grid-cols-3 sm:grid-cols-4 gap-2">
              {allMonths.map(m => {
                const isSelected = selectedMonths.includes(m);
                return (
                  <button
                    key={m}
                    type="button"
                    onClick={() => toggleMonthSelection(m, false)}
                    className={`text-xs sm:text-sm py-2 px-1 rounded border transition-colors flex items-center justify-center gap-1 ${
                      isSelected 
                        ? 'bg-primary-600 border-primary-600 text-white' 
                        : 'bg-white dark:bg-gray-800 border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-gray-700'
                    }`}
                  >
                    {isSelected ? <CheckSquare size={12}/> : <Square size={12}/>} {m}
                  </button>
                );
              })}
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Bidang Penanggung Jawab</label>
              <select
                value={divisionId}
                onChange={e => setDivisionId(e.target.value)}
                required
                className="mt-1 block w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 dark:text-white px-3 py-2 focus:border-primary-500 focus:ring-primary-500 outline-none"
              >
                <option value="">Pilih Bidang</option>
                {divisions.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
              </select>
            </div>
             <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Status</label>
              <select
                value={status}
                onChange={e => setStatus(e.target.value as any)}
                className="mt-1 block w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 dark:text-white px-3 py-2 focus:border-primary-500 focus:ring-primary-500 outline-none"
              >
                <option value="Planned">Planned</option>
                <option value="In Progress">In Progress</option>
                <option value="Completed">Completed</option>
              </select>
            </div>
          </div>

          <div className="pt-4 flex justify-end gap-3">
            <button
              type="button"
              onClick={() => setIsModalOpen(false)}
              className="px-4 py-2 text-sm font-medium text-gray-700 dark:text-gray-300 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-md hover:bg-gray-50 dark:hover:bg-gray-600"
            >
              Batal
            </button>
            <button
              type="submit"
              disabled={loading}
              className="px-4 py-2 text-sm font-medium text-white bg-primary-600 rounded-md hover:bg-primary-700 disabled:opacity-50"
            >
              {loading ? 'Menyimpan...' : 'Simpan'}
            </button>
          </div>
        </form>
      </Modal>

      {/* --- DESCRIPTION MODAL --- */}
      <Modal 
        isOpen={descModal.isOpen} 
        onClose={() => setDescModal({isOpen: false, text: '', title: ''})} 
        title={descModal.title || 'Keterangan'}
      >
        <div className="space-y-4">
            <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-lg border border-gray-100 dark:border-gray-700 max-h-[60vh] overflow-y-auto">
                <p className="text-gray-700 dark:text-gray-300 whitespace-pre-line leading-relaxed">
                    {descModal.text || 'Tidak ada keterangan.'}
                </p>
            </div>
            <div className="flex justify-end">
                <button
                    onClick={() => setDescModal({isOpen: false, text: '', title: ''})}
                    className="px-4 py-2 text-sm font-medium text-white bg-primary-600 rounded-md hover:bg-primary-700"
                >
                    Tutup
                </button>
            </div>
        </div>
      </Modal>

      {/* --- DELETE CONFIRMATION MODAL --- */}
      <Modal 
        isOpen={deleteConfirm.isOpen} 
        onClose={() => setDeleteConfirm({isOpen: false, id: null})} 
        title="Konfirmasi Hapus"
      >
        <div className="text-center sm:text-left">
          <div className="flex flex-col items-center gap-4 mb-4">
             <div className="p-3 bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400 rounded-full">
               <AlertTriangle size={32} />
             </div>
             <div>
                <p className="text-gray-700 dark:text-gray-300">
                  Apakah Anda yakin ingin menghapus program kerja ini? Tindakan ini tidak dapat dibatalkan.
                </p>
             </div>
          </div>
          <div className="flex justify-center sm:justify-end gap-3 mt-6">
            <button
              onClick={() => setDeleteConfirm({isOpen: false, id: null})}
              className="px-4 py-2 text-sm font-medium text-gray-700 dark:text-gray-300 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-md hover:bg-gray-50 dark:hover:bg-gray-600"
            >
              Batal
            </button>
            <button
              onClick={executeDelete}
              className="px-4 py-2 text-sm font-medium text-white bg-red-600 rounded-md hover:bg-red-700"
            >
              Ya, Hapus
            </button>
          </div>
        </div>
      </Modal>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { supabase } from '../supabaseClient';
import { Program, Division, Organization } from '../types';
import { Plus, Edit, Trash2, Calendar, Briefcase, Wallet, Filter, AlertTriangle, X, Layers, CheckSquare, Square, Building2, ChevronRight } from '../components/ui/Icons';
import { Modal } from '../components/Modal';

interface ProgramsProps {
  data: Program[];
  divisions: Division[];
  organizations: Organization[];
  onRefresh: () => void;
}

export const Programs: React.FC<ProgramsProps> = ({ data, divisions, organizations, onRefresh }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<Program | null>(null);

  // Description View Modal
  const [descModal, setDescModal] = useState<{isOpen: boolean, text: string, title: string}>({ isOpen: false, text: '', title: '' });

  // Filter State
  const [filterDivisionId, setFilterDivisionId] = useState('');
  const [filterOrgId, setFilterOrgId] = useState('');
  const [filterYear, setFilterYear] = useState<number | ''>('');
  const [filterMonths, setFilterMonths] = useState<string[]>([]); // Multi select

  // Delete Confirmation State
  const [deleteConfirm, setDeleteConfirm] = useState<{isOpen: boolean, id: string | null}>({ isOpen: false, id: null });

  // Form State
  const [name, setName] = useState('');
  const [description, setDescription] = useState(''); // New State
  const [costPerMonth, setCostPerMonth] = useState<number>(0);
  const [selectedMonths, setSelectedMonths] = useState<string[]>([]);
  const [divisionId, setDivisionId] = useState('');
  const [organizationId, setOrganizationId] = useState('');
  const [year, setYear] = useState<number>(new Date().getFullYear());
  const [status, setStatus] = useState<'Planned' | 'In Progress' | 'Completed'>('Planned');
  const [loading, setLoading] = useState(false);

  const allMonths = [
    'Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni', 
    'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'
  ];

  // Get unique years for filter
  const availableYears = useMemo(() => {
    const years = new Set(data.map(p => p.year || 2024));
    return Array.from(years).sort((a: number, b: number) => b - a);
  }, [data]);

  // Helper: Parse Month
  const parseMonths = (monthStr: string): string[] => {
    try {
      const parsed = JSON.parse(monthStr);
      return Array.isArray(parsed) ? parsed : [monthStr];
    } catch (e) {
      return monthStr ? [monthStr] : [];
    }
  };

  // --- FILTERING & STATISTICS LOGIC ---

  const filteredData = useMemo(() => {
    return data.filter(item => {
      const itemMonths = parseMonths(item.month);

      const matchDivision = filterDivisionId ? item.division_id === filterDivisionId : true;
      const matchOrg = filterOrgId ? item.organization_id === filterOrgId : true;
      const matchYear = filterYear ? (item.year || 2024) === Number(filterYear) : true;

      // Filter Month logic: If filter has selected months, show items that have AT LEAST ONE of those months
      const matchMonth = filterMonths.length > 0 
        ? itemMonths.some(m => filterMonths.includes(m))
        : true;

      return matchDivision && matchOrg && matchYear && matchMonth;
    });
  }, [data, filterDivisionId, filterOrgId, filterYear, filterMonths]);

  const stats = useMemo(() => {
    const totalCost = filteredData.reduce((acc, curr) => acc + curr.cost, 0);
    const totalPrograms = filteredData.length;
    // Get unique division names involved in the filtered view
    const uniqueDivisionIds = new Set(filteredData.map(p => p.division_id));
    const divisionNames = Array.from(uniqueDivisionIds)
      .map(id => divisions.find(d => d.id === id)?.name)
      .filter(Boolean)
      .join(', ');

    return { totalCost, totalPrograms, divisionNames };
  }, [filteredData, divisions]);

  // --- HANDLERS ---

  const handleOpen = (program?: Program) => {
    if (program) {
      setEditingItem(program);
      setName(program.name);
      setDescription(program.description || '');

      const months = parseMonths(program.month);
      setSelectedMonths(months);

      const count = months.length || 1;
      setCostPerMonth(program.cost / count);

      setDivisionId(program.division_id);
      setOrganizationId(program.organization_id || '');
      setYear(program.year || new Date().getFullYear());
      setStatus(program.status);
    } else {
      setEditingItem(null);
      setName('');
      setDescription('');
      setCostPerMonth(0);
      setSelectedMonths([allMonths[new Date().getMonth()]]);
      setDivisionId(divisions[0]?.id || '');
      setOrganizationId(organizations[0]?.id || '');
      setYear(new Date().getFullYear());
      setStatus('Planned');
    }
    setIsModalOpen(true);
  };

  const toggleMonthSelection = (month: string, isFilter: boolean = false) => {
    const setState = isFilter ? setFilterMonths : setSelectedMonths;
    const currentState = isFilter ? filterMonths : selectedMonths;

    if (currentState.includes(month)) {
        setState(currentState.filter(m => m !== month));
    } else {
        const newSelection = [...currentState, month];
        // Sort chronologically
        setState(newSelection.sort((a, b) => allMonths.indexOf(a) - allMonths.indexOf(b)));
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    if (selectedMonths.length === 0) {
      alert("Pilih setidaknya satu bulan.");
      setLoading(false);
      return;
    }

    const totalCost = costPerMonth * selectedMonths.length;
    const monthString = JSON.stringify(selectedMonths);

    const payload = {
      name,
      description,
      cost: totalCost,
      month: monthString,
      division_id: divisionId,
      organization_id: organizationId || null,
      year: year,
      status
    };

    try {
      if (editingItem) {
        const { error } = await supabase.from('programs').update(payload).eq('id', editingItem.id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from('programs').insert([payload]);
        if (error) throw error;
      }
      onRefresh();
      setIsModalOpen(false);
    } catch (error: any) {
      alert('Error: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  // Custom Delete Handler
  const confirmDelete = (id: string) => {
    setDeleteConfirm({ isOpen: true, id });
  };

  const executeDelete = async () => {
    if (!deleteConfirm.id) return;
    try {
      const { error } = await supabase.from('programs').delete().eq('id', deleteConfirm.id);
      if (error) throw error;
      onRefresh();
      setDeleteConfirm({ isOpen: false, id: null });
    } catch (error: any) {
      alert('Error: ' + error.message);
    }
  };

  const formatCurrency = (val: number) => new Intl.NumberFormat('id-ID', { style: 'currency', currency: 'IDR', maximumFractionDigits: 0 }).format(val);

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'Completed': return 'bg-green-100 dark:bg-green-900/40 text-green-800 dark:text-green-300';
      case 'In Progress': return 'bg-blue-100 dark:bg-blue-900/40 text-blue-800 dark:text-blue-300';
      default: return 'bg-gray-100 dark:bg-gray-700 text-gray-800 dark:text-gray-300';
    }
  };

  const resetFilters = () => {
    setFilterDivisionId('');
    setFilterOrgId('');
    setFilterYear('');
    setFilterMonths([]);
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
          <Briefcase className="text-primary-600 dark:text-primary-400" /> Program Kerja
        </h2>
        <button
          onClick={() => handleOpen()}
          className="bg-primary-600 hover:bg-primary-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition shadow-sm w-full sm:w-auto justify-center"
        >
          <Plus size={18} /> Tambah Program
        </button>
      </div>

      {/* --- STATS SUMMARY & FILTERS --- */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* Left: Summary Cards */}
        <div className="lg:col-span-2 grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="bg-gradient-to-br from-blue-500 to-blue-600 dark:from-blue-600 dark:to-blue-800 p-5 rounded-xl text-white shadow-md">
            <div className="flex justify-between items-start">
               <div>
                  <p className="text-blue-100 text-sm font-medium mb-1">Total Anggaran (Tersaring)</p>
                  <h3 className="text-3xl font-bold">{formatCurrency(stats.totalCost)}</h3>
               </div>
               <div className="p-2 bg-white/20 rounded-lg">
                 <Wallet size={24} className="text-white" />
               </div>
            </div>
            <p className="text-sm text-blue-100 mt-4 flex items-center gap-1">
              <Layers size={14} /> 
              {stats.divisionNames ? `Bidang: ${stats.divisionNames}` : 'Semua Bidang'}
            </p>
          </div>

          <div className="bg-white dark:bg-dark-card p-5 rounded-xl border border-gray-100 dark:border-dark-border shadow-sm flex flex-col justify-center">
             <div className="flex items-center gap-3 mb-2">
               <div className="p-2 bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400 rounded-lg">
                 <Briefcase size={20} />
               </div>
               <span className="text-gray-500 dark:text-gray-400 text-sm">Jumlah Program</span>
             </div>
             <p className="text-2xl font-bold text-gray-800 dark:text-white pl-1">{stats.totalPrograms} <span className="text-sm font-normal text-gray-500">Program</span></p>
             <p className="text-xs text-gray-400 mt-2 pl-1">
                {(filterDivisionId || filterOrgId || filterYear || filterMonths.length > 0) ? 'Hasil filter diterapkan' : 'Menampilkan semua data'}
             </p>
          </div>
        </div>

        {/* Right: Filters */}
        <div className="bg-white dark:bg-dark-card p-5 rounded-xl border border-gray-100 dark:border-dark-border shadow-sm">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-2 text-gray-800 dark:text-white font-semibold">
              <Filter size={18} /> Filter Data
            </div>
            {(filterDivisionId || filterOrgId || filterYear || filterMonths.length > 0) && (
               <button 
                 onClick={resetFilters}
                 className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1"
               >
                 <X size={12} /> Reset
               </button>
             )}
          </div>

          <div className="space-y-3">
             <div className="grid grid-cols-2 gap-2">
                <div>
                   <label className="text-xs text-gray-500 dark:text-gray-400 mb-1 block">Tahun</label>
                   <select 
                      className="w-full text-sm bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg px-2 py-2 text-gray-700 dark:text-gray-200 focus:ring-2 focus:ring-primary-500 outline-none"
                      value={filterYear}
                      onChange={(e) => setFilterYear(Number(e.target.value) || '')}
                    >
                      <option value="">Semua</option>
                      {availableYears.map(y => (
                        <option key={y} value={y}>{y}</option>
                      ))}
                   </select>
                </div>
                <div>
                    <label className="text-xs text-gray-500 dark:text-gray-400 mb-1 block">Organisasi</label>
                    <select 
                        className="w-full text-sm bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg px-2 py-2 text-gray-700 dark:text-gray-200 focus:ring-2 focus:ring-primary-500 outline-none"
                        value={filterOrgId}
                        onChange={(e) => setFilterOrgId(e.target.value)}
                        >
                        <option value="">Semua</option>
                        {organizations.map(o => (
                            <option key={o.id} value={o.id}>{o.name}</option>
                        ))}
                    </select>
                </div>
             </div>

             <div>
               <label className="text-xs text-gray-500 dark:text-gray-400 mb-1 block">Bidang</label>
               <select 
                  className="w-full text-sm bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg px-3 py-2 text-gray-700 dark:text-gray-200 focus:ring-2 focus:ring-primary-500 outline-none"
                  value={filterDivisionId}
                  onChange={(e) => setFilterDivisionId(e.target.value)}
                >
                  <option value="">Semua Bidang</option>
                  {divisions.map(d => (
                    <option key={d.id} value={d.id}>{d.name}</option>
                  ))}
               </select>
             </div>

             <div>
                <label className="text-xs text-gray-500 dark:text-gray-400 mb-1 block">Filter Bulan (Multi Select)</label>
                <div className="flex flex-wrap gap-1 max-h-24 overflow-y-auto">
                    {allMonths.map(m => {
                        const isSelected = filterMonths.includes(m);
                        return (
                            <button
                                key={m}
                                onClick={() => toggleMonthSelection(m, true)}
                                className={`text-[10px] px-2 py-1 rounded-full border ${
                                    isSelected 
                                    ? 'bg-blue-100 border-blue-200 text-blue-700 dark:bg-blue-900/40 dark:border-blue-800 dark:text-blue-300' 
                                    : 'bg-gray-50 border-gray-200 text-gray-600 dark:bg-gray-800 dark:border-gray-700 dark:text-gray-400'
                                }`}
                            >
                                {m.substring(0, 3)}
