              <div className="flex items-center gap-2">
                <Wallet size={16} className="text-blue-600 dark:text-blue-400" />
                <span className="text-lg font-bold text-blue-700 dark:text-blue-300">
                  {formatCurrency(costPerMonth * selectedMonths.length)}
                </span>
              </div>
              <p className="text-xs text-blue-600 dark:text-blue-400 mt-1">
                {selectedMonths.length} bulan terpilih
              </p>
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Pilih Bulan Pelaksanaan</label>
            <div className="grid grid-cols-3 sm:grid-cols-4 gap-2">
              {allMonths.map(m => {
                const isSelected = selectedMonths.includes(m);
                return (
                  <button
                    key={m}
                    type="button"
                    onClick={() => toggleMonthSelection(m, false)}
                    className={`text-xs sm:text-sm py-2 px-1 rounded border transition-colors flex items-center justify-center gap-1 ${
                      isSelected 
                        ? 'bg-primary-600 border-primary-600 text-white' 
