-- ==========================================
-- SEEDER ANGGOTA & BIDANG (EXISTING YAYASAN)
-- ==========================================
DO $$
DECLARE
    v_org_id uuid;
    v_role_id uuid;
    v_div_id uuid;
    r record;
BEGIN
    -- 1. Set Organisasi Default (Yayasan Pusat)
    SELECT id INTO v_org_id FROM organizations WHERE name = 'Yayasan Pusat' LIMIT 1;
    -- Fallback jika belum ada
    IF v_org_id IS NULL THEN
        INSERT INTO organizations (name) VALUES ('Yayasan Pusat') RETURNING id INTO v_org_id;
    END IF;

    -- 2. Set Role Default (Anggota)
    SELECT id INTO v_role_id FROM roles WHERE name = 'Anggota' LIMIT 1;
    IF v_role_id IS NULL THEN
         INSERT INTO roles (name) VALUES ('Anggota') RETURNING id INTO v_role_id;
    END IF;

    -- 3. Loop Data Anggota
    -- Format: (Nama Bidang, Nama Anggota)
    FOR r IN SELECT * FROM (VALUES
        -- HARIAN
        ('HARIAN', 'AWIT KURNIAWAN'),
        ('HARIAN', 'H. HARI DANAH W.'),
        ('HARIAN', 'H. ARI SRI M.'),
        ('HARIAN', 'ISMAIL MARJUKI'),
        ('HARIAN', 'EKO ANDRI W.'),
        ('HARIAN', 'ALENOVAN W. P.'),
        ('HARIAN', 'HARIANTO'),
        ('HARIAN', 'RISKA RAHMAWATI'),
        ('HARIAN', 'H. ANDI NUROHMAN'),
        ('HARIAN', 'H. ARIEF WIBOWO'),
        ('HARIAN', 'H. IDA YUSIANINGSIH'),

        -- PENDIDIKAN & KURIKULUM
        ('PENDIDIKAN & KURIKULUM', 'SRI KARMINI'),
        ('PENDIDIKAN & KURIKULUM', 'H. AHMAD HIDAYAT'),
        ('PENDIDIKAN & KURIKULUM', 'GRENADA TRI K.'),

        -- KESISWAAN & TENDIK
        ('KESISWAAN & TENDIK', 'ROICHANAH INSAFI'),
        ('KESISWAAN & TENDIK', 'H. DANI MUSTOFA'),
        ('KESISWAAN & TENDIK', 'YOLLA SETYO A.'),

        -- SARPRAS & PERLENGKAPAN
        ('SARPRAS & PERLENGKAPAN', 'FARIZ ALKHAN F.'),
        ('SARPRAS & PERLENGKAPAN', 'AHMAD RISKY F.'),
        ('SARPRAS & PERLENGKAPAN', 'ABDUL KHAFID'),

        -- BK
        ('BK', 'H. SA''I'), -- Escape single quote
        ('BK', 'INESTHA LUNA R. S.'),

        -- KEAMANAN
        ('KEAMANAN', 'IRFAN FAQIH A.'),

        -- HUMAS
        ('HUMAS', 'TORIQ PRIA D.'),
        ('HUMAS', 'SONI ZAED A. R.'),
        ('HUMAS', 'LUHUR SUSENO'),
        ('HUMAS', 'FERRY FERDIANSYAH'),
        ('HUMAS', 'ROYKHAN MALVIN B.'),

        -- PEMBANGUNAN & PENGEMBANGAN
        ('PEMBANGUNAN & PENGEMBANGAN', 'WINDU ABDILLAH'),
        ('PEMBANGUNAN & PENGEMBANGAN', 'H. ISKANDAR'),
        ('PEMBANGUNAN & PENGEMBANGAN', 'FARIZ ALKHAN'), -- Note: Duplicate name in list, handled as unique entry
        ('PEMBANGUNAN & PENGEMBANGAN', 'RIYADIN'),
        ('PEMBANGUNAN & PENGEMBANGAN', 'H. ANDI NURROHMAN'),

        -- KONSUMSI
        ('KONSUMSI', 'H. KHOIRUL HADI B.'),

        -- KESEHATAN
        ('KESEHATAN', 'SUNARNI'),
        ('KESEHATAN', 'ELISA D. K.'),

        -- SDIT
        ('SDIT', 'AUVA DINA NAJA R.'),
        ('SDIT', 'FISCANIA DWI S.'),
        ('SDIT', 'UFIK ISMAWATI')

    ) AS t(div_name, member_name)
    LOOP
        -- A. Cek/Buat Divisi
        SELECT id INTO v_div_id FROM divisions WHERE name = r.div_name LIMIT 1;

        IF v_div_id IS NULL THEN
            INSERT INTO divisions (name) VALUES (r.div_name) RETURNING id INTO v_div_id;
        END IF;

        -- B. Masukkan Anggota (Cek duplikasi nama)
        IF NOT EXISTS (SELECT 1 FROM members WHERE full_name = r.member_name) THEN
            INSERT INTO members (full_name, email, role_id, division_id, organization_id)
            VALUES (
                r.member_name, 
                -- Generate Email Dummy: nama.tanpa.spasi@yayasan.seeder
                LOWER(REGEXP_REPLACE(r.member_name, '[^a-zA-Z0-9]', '.', 'g')) || '@yayasan.seeder', 
                v_role_id, 
                v_div_id, 
                v_org_id
            );
        END IF;
    END LOOP;
END $$;

-- ==========================================
-- SEEDER PROGRAM KERJA (ALL ORGS)
-- ==========================================
DO $$
DECLARE
    v_org_yayasan uuid;
    v_org_tk uuid;
    v_div_id uuid;
BEGIN
    -- Get Organization IDs
    SELECT id INTO v_org_yayasan FROM organizations WHERE name = 'Yayasan Pusat' LIMIT 1;
    SELECT id INTO v_org_tk FROM organizations WHERE name = 'TK & KB' LIMIT 1;

    -- ========================
    -- 1. YAYASAN - HARIAN
    -- ========================
    SELECT id INTO v_div_id FROM divisions WHERE name = 'HARIAN' LIMIT 1;
    IF v_div_id IS NOT NULL AND v_org_yayasan IS NOT NULL THEN
         INSERT INTO programs (name, description, cost, month, year, status, division_id, organization_id)
        SELECT 'Musyawaroh besar Yayasan bersama Lembaga Pendidikan', 'Sinkronisasi program dan pelaporan keuangan Lembaga-pendidikan', 3600000, '["Januari", "Februari", "Maret", "April", "Mei", "Juni", "Juli", "Agustus", "September", "Oktober", "November", "Desember"]', 2025, 'Planned', v_div_id, v_org_yayasan
        WHERE NOT EXISTS (SELECT 1 FROM programs WHERE name = 'Musyawaroh besar Yayasan bersama Lembaga Pendidikan');

        INSERT INTO programs (name, description, cost, month, year, status, division_id, organization_id)
        SELECT 'Musyawaroh Harian Yayasan', '', 1800000, '["Januari", "Februari", "Maret", "April", "Mei", "Juni", "Juli", "Agustus", "September", "Oktober", "November", "Desember"]', 2025, 'Planned', v_div_id, v_org_yayasan
        WHERE NOT EXISTS (SELECT 1 FROM programs WHERE name = 'Musyawaroh Harian Yayasan');
    END IF;

    -- (Existing Yayasan Programs Omitted for brevity, but logic should be here if running fresh)
    -- Asumsi user sudah menjalankan script sebelumnya untuk Yayasan, kita fokus ke TK & KB

    -- =======================================================
    -- ORGANISASI: TK & KB
    -- =======================================================

    IF v_org_tk IS NOT NULL THEN

        -- --- BIDANG: UMUM ---
        SELECT id INTO v_div_id FROM divisions WHERE name = 'UMUM' LIMIT 1;
        IF v_div_id IS NOT NULL THEN
            INSERT INTO programs (name, description, cost, month, year, status, division_id, organization_id)
            SELECT 'Rapat Intern dengan yayasan', 'SEBULAN 1 KALI', 0, '["Januari", "Februari", "Maret", "April", "Mei", "Juni", "Juli", "Agustus", "September", "Oktober", "November", "Desember"]', 2025, 'Planned', v_div_id, v_org_tk
            WHERE NOT EXISTS (SELECT 1 FROM programs WHERE name LIKE 'Rapat Intern%' AND organization_id = v_org_tk);

            INSERT INTO programs (name, description, cost, month, year, status, division_id, organization_id)
