import React, { useState } from 'react';
import { supabase } from '../supabaseClient';
import { Event, EventAttendance, Member } from '../types';
import { 
  Plus, Edit, Trash2, CalendarDays, MapPin, 
  ClipboardCheck, CheckCircle2, XCircle, HelpCircle, 
  Clock, CheckSquare, Search, ChevronLeft
} from '../components/ui/Icons';
import { Modal } from '../components/Modal';

interface EventsProps {
  events: Event[];
  members: Member[];
  attendance: EventAttendance[];
  onRefresh: () => void;
}

export const Events: React.FC<EventsProps> = ({ events, members, attendance, onRefresh }) => {
  const [view, setView] = useState<'LIST' | 'ATTENDANCE'>('LIST');
  const [selectedEvent, setSelectedEvent] = useState<Event | null>(null);

  // Modal & Form State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<Event | null>(null);
  const [name, setName] = useState('');
  const [date, setDate] = useState('');
  const [time, setTime] = useState('');
  const [location, setLocation] = useState('');
  const [description, setDescription] = useState('');
  const [status, setStatus] = useState<'Upcoming' | 'Completed' | 'Cancelled'>('Upcoming');
  const [loading, setLoading] = useState(false);

  // Attendance Filter State
  const [attendanceSearch, setAttendanceSearch] = useState('');

  // --- CRUD HANDLERS ---
  const handleOpenModal = (event?: Event) => {
    if (event) {
      setEditingItem(event);
      setName(event.name);

      const dt = new Date(event.date);
      setDate(dt.toISOString().split('T')[0]);
      setTime(dt.toTimeString().split(' ')[0].substring(0, 5));

      setLocation(event.location || '');
      setDescription(event.description || '');
      setStatus(event.status);
    } else {
      setEditingItem(null);
      setName('');
      setDate(new Date().toISOString().split('T')[0]);
      setTime('09:00');
      setLocation('');
      setDescription('');
      setStatus('Upcoming');
    }
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    const fullDate = new Date(`${date}T${time}:00`);

    const payload = {
      name,
      date: fullDate.toISOString(),
      location,
      description,
      status
    };

    try {
      if (editingItem) {
        const { error } = await supabase.from('events').update(payload).eq('id', editingItem.id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from('events').insert([payload]);
        if (error) throw error;
      }
      onRefresh();
      setIsModalOpen(false);
    } catch (error: any) {
      alert('Error: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Apakah Anda yakin ingin menghapus acara ini? Data absensi terkait akan hilang.')) return;
    try {
      const { error } = await supabase.from('events').delete().eq('id', id);
      if (error) throw error;
      onRefresh();
    } catch (error: any) {
      alert('Error: ' + error.message);
    }
  };

  // --- ATTENDANCE HANDLERS ---
  const openAttendance = (event: Event) => {
    setSelectedEvent(event);
    setView('ATTENDANCE');
  };

  const handleAttendanceChange = async (memberId: string, newStatus: 'Present' | 'Absent' | 'Excused') => {
    if (!selectedEvent) return;

    // Check if record exists locally first to prevent UI flicker
    const existing = attendance.find(a => a.event_id === selectedEvent.id && a.member_id === memberId);

    // Optimistic UI Update (Optional, skipping for simplicity and reliability)

    try {
       const { error } = await supabase
        .from('event_attendance')
        .upsert(
            { 
                event_id: selectedEvent.id, 
                member_id: memberId, 
                status: newStatus 
            }, 
            { onConflict: 'event_id, member_id' }
        );

       if (error) throw error;
       onRefresh(); // Refresh global state
    } catch (error: any) {
        alert('Gagal update absensi: ' + error.message);
    }
  };

  const getAttendanceStats = (eventId: string) => {
    const eventAtt = attendance.filter(a => a.event_id === eventId);
    const present = eventAtt.filter(a => a.status === 'Present').length;
    const excused = eventAtt.filter(a => a.status === 'Excused').length;
    const absent = eventAtt.filter(a => a.status === 'Absent').length;
    // Unmarked are members count - existing records. 
    // Usually for simple logic we just treat no record as 'Belum Absen'
    return { present, excused, absent };
  };

  const filteredMembers = members.filter(m => 
    m.full_name.toLowerCase().includes(attendanceSearch.toLowerCase())
  );

  // Sort events by date descending
  const sortedEvents = [...events].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  // --- RENDER VIEW: LIST ---
  if (view === 'LIST') {
    return (
      <div>
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
            <CalendarDays className="text-primary-600 dark:text-primary-400" /> Agenda & Acara
          </h2>
          <button
            onClick={() => handleOpenModal()}
            className="bg-primary-600 hover:bg-primary-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition"
          >
            <Plus size={18} /> Buat Acara
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {sortedEvents.map(item => {
            const stats = getAttendanceStats(item.id);
            const eventDate = new Date(item.date);

            return (
              <div key={item.id} className="bg-white dark:bg-dark-card rounded-xl shadow-sm border border-gray-100 dark:border-dark-border overflow-hidden hover:shadow-md transition flex flex-col">
                <div className={`h-2 w-full ${item.status === 'Upcoming' ? 'bg-blue-500' : item.status === 'Completed' ? 'bg-green-500' : 'bg-red-500'}`}></div>
                <div className="p-5 flex-1 flex flex-col">
                  <div className="flex justify-between items-start mb-2">
                    <span className={`px-2 py-1 rounded text-[10px] uppercase font-bold tracking-wide ${
                        item.status === 'Upcoming' ? 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300' :
                        item.status === 'Completed' ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-300' :
                        'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-300'
                    }`}>
                        {item.status}
                    </span>
                    <div className="flex gap-2">
                        <button onClick={() => handleOpenModal(item)} className="text-gray-400 hover:text-blue-600"><Edit size={16}/></button>
                        <button onClick={() => handleDelete(item.id)} className="text-gray-400 hover:text-red-600"><Trash2 size={16}/></button>
                    </div>
                  </div>

                  <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-1 line-clamp-1">{item.name}</h3>
                  <div className="text-sm text-gray-500 dark:text-gray-400 space-y-1 mb-4">
                     <div className="flex items-center gap-2">
                        <CalendarDays size={14} /> 
                        <span>{eventDate.toLocaleDateString('id-ID', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</span>
                     </div>
                     <div className="flex items-center gap-2">
                        <Clock size={14} /> 
                        <span>{eventDate.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' })} WIB</span>
                     </div>
                     {item.location && (
                        <div className="flex items-center gap-2">
                            <MapPin size={14} /> 
                            <span className="truncate">{item.location}</span>
                        </div>
                     )}
                  </div>

                  <div className="mt-auto pt-4 border-t border-gray-100 dark:border-gray-700">
                     <div className="flex justify-between text-xs text-gray-500 dark:text-gray-400 mb-2">
                        <span>Kehadiran:</span>
                        <span className="font-semibold text-gray-700 dark:text-gray-200">{stats.present} Hadir</span>
                     </div>
                     <button 
                        onClick={() => openAttendance(item)}
                        className="w-full py-2 bg-gray-50 hover:bg-gray-100 dark:bg-gray-800 dark:hover:bg-gray-700 text-gray-700 dark:text-gray-200 text-sm font-medium rounded-lg flex items-center justify-center gap-2 border border-gray-200 dark:border-gray-600 transition"
                     >
                        <ClipboardCheck size={16} /> Kelola Absensi
                     </button>
                  </div>
                </div>
              </div>
            );
          })}
          {events.length === 0 && (
             <div className="col-span-full text-center py-12 text-gray-500 dark:text-gray-400 bg-white dark:bg-dark-card rounded-xl border border-dashed border-gray-200 dark:border-dark-border">
                Belum ada acara yang dijadwalkan.
             </div>
          )}
        </div>

        {/* Modal Form */}
        <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={editingItem ? 'Edit Acara' : 'Buat Acara Baru'}>
            <form onSubmit={handleSubmit} className="space-y-4">
                <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Nama Acara</label>
                    <input type="text" required value={name} onChange={e => setName(e.target.value)} className="input-field mt-1 w-full p-2 border rounded dark:bg-gray-800 dark:text-white dark:border-gray-600" />
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Tanggal</label>
                        <input type="date" required value={date} onChange={e => setDate(e.target.value)} className="input-field mt-1 w-full p-2 border rounded dark:bg-gray-800 dark:text-white dark:border-gray-600" />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Jam</label>
                        <input type="time" required value={time} onChange={e => setTime(e.target.value)} className="input-field mt-1 w-full p-2 border rounded dark:bg-gray-800 dark:text-white dark:border-gray-600" />
                    </div>
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Lokasi</label>
                    <input type="text" value={location} onChange={e => setLocation(e.target.value)} className="input-field mt-1 w-full p-2 border rounded dark:bg-gray-800 dark:text-white dark:border-gray-600" />
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Deskripsi</label>
                    <textarea rows={3} value={description} onChange={e => setDescription(e.target.value)} className="input-field mt-1 w-full p-2 border rounded dark:bg-gray-800 dark:text-white dark:border-gray-600" />
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Status</label>
                    <select value={status} onChange={e => setStatus(e.target.value as any)} className="input-field mt-1 w-full p-2 border rounded dark:bg-gray-800 dark:text-white dark:border-gray-600">
                        <option value="Upcoming">Upcoming (Akan Datang)</option>
                        <option value="Completed">Completed (Selesai)</option>
                        <option value="Cancelled">Cancelled (Dibatalkan)</option>
                    </select>
                </div>
                <div className="pt-4 flex justify-end gap-3">
                    <button type="button" onClick={() => setIsModalOpen(false)} className="px-4 py-2 bg-gray-200 dark:bg-gray-700 rounded text-gray-800 dark:text-white">Batal</button>
                    <button type="submit" disabled={loading} className="px-4 py-2 bg-primary-600 text-white rounded hover:bg-primary-700">{loading ? 'Simpan...' : 'Simpan'}</button>
                </div>
            </form>
        </Modal>
      </div>
    );
  }

  // --- RENDER VIEW: ATTENDANCE ---
  if (view === 'ATTENDANCE' && selectedEvent) {
    const stats = getAttendanceStats(selectedEvent.id);
    const eventDate = new Date(selectedEvent.date);

    return (
        <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
            {/* Header */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div className="flex items-start gap-4">
                    <button 
                        onClick={() => setView('LIST')}
                        className="p-2 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg text-gray-500 hover:text-primary-600 transition"
                    >
                        <ChevronLeft size={24} />
                    </button>
                    <div>
                        <div className="flex items-center gap-2 mb-1">
                            <h2 className="text-xl font-bold text-gray-900 dark:text-white">{selectedEvent.name}</h2>
                            <span className={`px-2 py-0.5 rounded text-[10px] uppercase font-bold ${
                                selectedEvent.status === 'Upcoming' ? 'bg-blue-100 text-blue-700' : 'bg-green-100 text-green-700'
                            }`}>
                                {selectedEvent.status}
                            </span>
                        </div>
                        <p className="text-sm text-gray-500 dark:text-gray-400 flex items-center gap-3">
                            <span className="flex items-center gap-1"><CalendarDays size={14}/> {eventDate.toLocaleDateString('id-ID')}</span>
                            <span className="flex items-center gap-1"><Clock size={14}/> {eventDate.toLocaleTimeString('id-ID', {hour: '2-digit', minute:'2-digit'})}</span>
                        </p>
                    </div>
                </div>

                {/* Stats */}
                <div className="flex gap-2">
                    <div className="px-4 py-2 bg-green-50 dark:bg-green-900/20 border border-green-100 dark:border-green-800 rounded-lg text-center">
                        <div className="text-xs text-green-600 dark:text-green-400 font-semibold">HADIR</div>
                        <div className="text-lg font-bold text-green-700 dark:text-green-300">{stats.present}</div>
                    </div>
                    <div className="px-4 py-2 bg-yellow-50 dark:bg-yellow-900/20 border border-yellow-100 dark:border-yellow-800 rounded-lg text-center">
                        <div className="text-xs text-yellow-600 dark:text-yellow-400 font-semibold">IZIN</div>
                        <div className="text-lg font-bold text-yellow-700 dark:text-yellow-300">{stats.excused}</div>
                    </div>
                    <div className="px-4 py-2 bg-red-50 dark:bg-red-900/20 border border-red-100 dark:border-red-800 rounded-lg text-center">
                        <div className="text-xs text-red-600 dark:text-red-400 font-semibold">ALPHA</div>
                        <div className="text-lg font-bold text-red-700 dark:text-red-300">{stats.absent}</div>
                    </div>
                </div>
            </div>

            {/* List */}
            <div className="bg-white dark:bg-dark-card rounded-xl shadow-sm border border-gray-100 dark:border-dark-border overflow-hidden">
                <div className="p-4 border-b border-gray-100 dark:border-dark-border flex items-center gap-2">
                    <div className="relative flex-1 max-w-md">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                        <input 
                            type="text" 
                            placeholder="Cari anggota..." 
                            value={attendanceSearch}
                            onChange={(e) => setAttendanceSearch(e.target.value)}
                            className="w-full pl-9 pr-4 py-2 text-sm border border-gray-200 dark:border-gray-700 rounded-lg bg-gray-50 dark:bg-gray-800 dark:text-white focus:outline-none focus:ring-2 focus:ring-primary-500"
                        />
                    </div>
                    <div className="text-xs text-gray-500 italic ml-auto hidden sm:block">
                        *Klik tombol status untuk mengubah
                    </div>
                </div>

                <div className="overflow-x-auto">
                    <table className="w-full text-left">
                        <thead className="bg-gray-50 dark:bg-gray-800 text-gray-600 dark:text-gray-400 text-xs uppercase font-semibold">
                            <tr>
                                <th className="px-6 py-4">Nama Anggota</th>
                                <th className="px-6 py-4 text-center">Hadir</th>
                                <th className="px-6 py-4 text-center">Izin</th>
                                <th className="px-6 py-4 text-center">Alpha / Absen</th>
                                <th className="px-6 py-4 text-right">Status Saat Ini</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100 dark:divide-dark-border">
                            {filteredMembers.map(member => {
                                const record = attendance.find(a => a.event_id === selectedEvent.id && a.member_id === member.id);
                                const currentStatus = record?.status; // undefined means Belum Absen

                                return (
                                    <tr key={member.id} className="hover:bg-gray-50 dark:hover:bg-gray-800/50">
                                        <td className="px-6 py-4">
                                            <div className="font-medium text-gray-900 dark:text-white">{member.full_name}</div>
                                            <div className="text-xs text-gray-500 dark:text-gray-400">{member.divisions?.name || 'Tanpa Bidang'}</div>
                                        </td>
                                        <td className="px-6 py-4 text-center">
                                            <button 
                                                onClick={() => handleAttendanceChange(member.id, 'Present')}
                                                className={`p-2 rounded-full transition ${currentStatus === 'Present' ? 'bg-green-100 text-green-600 ring-2 ring-green-500' : 'text-gray-300 hover:bg-green-50 hover:text-green-500'}`}
                                            >
                                                <CheckCircle2 size={24} />
                                            </button>
                                        </td>
                                        <td className="px-6 py-4 text-center">
                                            <button 
                                                onClick={() => handleAttendanceChange(member.id, 'Excused')}
                                                className={`p-2 rounded-full transition ${currentStatus === 'Excused' ? 'bg-yellow-100 text-yellow-600 ring-2 ring-yellow-500' : 'text-gray-300 hover:bg-yellow-50 hover:text-yellow-500'}`}
                                            >
                                                <HelpCircle size={24} />
                                            </button>
                                        </td>
                                        <td className="px-6 py-4 text-center">
                                            <button 
                                                onClick={() => handleAttendanceChange(member.id, 'Absent')}
                                                className={`p-2 rounded-full transition ${currentStatus === 'Absent' ? 'bg-red-100 text-red-600 ring-2 ring-red-500' : 'text-gray-300 hover:bg-red-50 hover:text-red-500'}`}
                                            >
                                                <XCircle size={24} />
                                            </button>
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            {currentStatus ? (
                                                <span className={`px-3 py-1 rounded-full text-xs font-bold ${
                                                    currentStatus === 'Present' ? 'bg-green-100 text-green-700' :
                                                    currentStatus === 'Excused' ? 'bg-yellow-100 text-yellow-700' :
                                                    'bg-red-100 text-red-700'
                                                }`}>
                                                    {currentStatus === 'Present' ? 'HADIR' : currentStatus === 'Excused' ? 'IZIN' : 'ALPHA'}
                                                </span>
                                            ) : (
                                                <span className="text-xs text-gray-400 italic">Belum Absen</span>
                                            )}
                                        </td>
                                    </tr>
                                )
                            })}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
  }

  return null;
};

import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, AreaChart, Area } from 'recharts';
import { Wallet, Users, Layers, Briefcase, CalendarDays, ClipboardCheck, Clock } from '../components/ui/Icons';
import { Member, Program, Division, Event, EventAttendance } from '../types';

interface DashboardProps {
  members: Member[];
  programs: Program[];
  divisions: Division[];
  events: Event[];
  attendance: EventAttendance[];
  isDarkMode: boolean;
}

export const Dashboard: React.FC<DashboardProps> = ({ members, programs, divisions, events, attendance, isDarkMode }) => {

  // Statistics
  const totalCost = useMemo(() => programs.reduce((acc, curr) => acc + curr.cost, 0), [programs]);
  const activePrograms = programs.filter(p => p.status === 'In Progress').length;
  const upcomingEvents = events.filter(e => e.status === 'Upcoming').length;

  // Chart Data: Cost per Division
  const costPerDivision = useMemo(() => {
    const data: Record<string, number> = {};
    programs.forEach(p => {
      const divName = divisions.find(d => d.id === p.division_id)?.name || 'Unknown';
      data[divName] = (data[divName] || 0) + p.cost;
    });
    return Object.entries(data).map(([name, value]) => ({ name, value }));
  }, [programs, divisions]);

  // Chart Data: Programs per Status
  const statusData = useMemo(() => {
    const counts: Record<string, number> = { Planned: 0, 'In Progress': 0, Completed: 0 };
    programs.forEach(p => {
      if (counts[p.status] !== undefined) counts[p.status]++;
    });
    return Object.entries(counts).map(([name, value]) => ({ name, value }));
  }, [programs]);

  // Chart Data: Attendance Rate (Last 5 Completed Events)
  const attendanceTrend = useMemo(() => {
      // 1. Get completed events sorted by date
      const completedEvents = events
        .filter(e => e.status === 'Completed')
        .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
        .slice(-5); // Take last 5

      // 2. Calculate percentage per event
      return completedEvents.map(event => {
          const records = attendance.filter(a => a.event_id === event.id);
          const presentCount = records.filter(a => a.status === 'Present').length;
          // Assume total members is consistent, or use attendance count if larger (should handle active members ideally)
          const totalMembers = members.length || 1; 
          const percentage = Math.round((presentCount / totalMembers) * 100);

          return {
              name: event.name.length > 15 ? event.name.substring(0, 15) + '...' : event.name,
              fullDate: new Date(event.date).toLocaleDateString(),
              percentage: percentage,
              present: presentCount
          }
      });
  }, [events, attendance, members]);

  // List: Upcoming 3 Events
  const upcomingList = useMemo(() => {
      return events
        .filter(e => e.status === 'Upcoming')
        .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
        .slice(0, 3);
  }, [events]);


  const COLORS = ['#94a3b8', '#3b82f6', '#10b981'];

  const formatCurrency = (value: number) => 
    new Intl.NumberFormat('id-ID', { style: 'currency', currency: 'IDR', maximumFractionDigits: 0 }).format(value);

  const tooltipStyle = isDarkMode ? {
    backgroundColor: '#1e293b',
    borderColor: '#334155',
    color: '#f1f5f9'
  } : undefined;

  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold text-gray-800 dark:text-white">Dashboard Overview</h2>

      {/* Stat Cards Row 1: General */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border flex items-center space-x-4">
          <div className="p-3 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-lg">
            <Users size={24} />
          </div>
          <div>
            <p className="text-sm text-gray-500 dark:text-gray-400">Total Anggota</p>
            <p className="text-2xl font-bold text-gray-900 dark:text-white">{members.length}</p>
          </div>
        </div>

        <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border flex items-center space-x-4">
          <div className="p-3 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 rounded-lg">
            <CalendarDays size={24} />
          </div>
          <div>
            <p className="text-sm text-gray-500 dark:text-gray-400">Acara Mendatang</p>
            <p className="text-2xl font-bold text-gray-900 dark:text-white">{upcomingEvents}</p>
          </div>
        </div>

        <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border flex items-center space-x-4">
          <div className="p-3 bg-green-50 dark:bg-green-900/30 text-green-600 dark:text-green-400 rounded-lg">
            <Briefcase size={24} />
          </div>
          <div>
            <p className="text-sm text-gray-500 dark:text-gray-400">Program Aktif</p>
            <p className="text-2xl font-bold text-gray-900 dark:text-white">{activePrograms}</p>
          </div>
        </div>

        <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border flex items-center space-x-4">
          <div className="p-3 bg-amber-50 dark:bg-amber-900/30 text-amber-600 dark:text-amber-400 rounded-lg">
            <Wallet size={24} />
          </div>
          <div>
            <p className="text-sm text-gray-500 dark:text-gray-400">Total Anggaran</p>
            <p className="text-lg font-bold text-gray-900 dark:text-white truncate">{formatCurrency(totalCost)}</p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Main Chart: Cost */}
          <div className="lg:col-span-2 bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border">
            <h3 className="text-lg font-semibold text-gray-800 dark:text-white mb-4">Alokasi Anggaran per Bidang</h3>
            <div className="h-72">
                <ResponsiveContainer width="100%" height="100%">
                <BarChart data={costPerDivision}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? '#334155' : '#e5e7eb'} />
                    <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 12, fill: isDarkMode ? '#94a3b8' : '#666'}} />
                    <YAxis axisLine={false} tickLine={false} tickFormatter={(val) => `Rp${val/1000}k`} tick={{fontSize: 12, fill: isDarkMode ? '#94a3b8' : '#666'}} />
                    <Tooltip 
                    formatter={(value: number) => formatCurrency(value)} 
                    contentStyle={tooltipStyle}
                    />
                    <Bar dataKey="value" fill="#3b82f6" radius={[4, 4, 0, 0]} />
                </BarChart>
                </ResponsiveContainer>
            </div>
         </div>

         {/* Side: Upcoming Events List */}
         <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border flex flex-col">
            <h3 className="text-lg font-semibold text-gray-800 dark:text-white mb-4 flex items-center gap-2">
                <CalendarDays size={20} className="text-indigo-500" /> Agenda Terdekat
            </h3>
            <div className="flex-1 space-y-4">
                {upcomingList.map(event => (
                    <div key={event.id} className="p-4 rounded-lg bg-gray-50 dark:bg-gray-800/50 border border-gray-100 dark:border-gray-700 flex flex-col gap-1">
                        <div className="flex justify-between items-start">
                             <span className="font-semibold text-gray-800 dark:text-white line-clamp-1">{event.name}</span>
                        </div>
                        <div className="text-xs text-gray-500 dark:text-gray-400 flex items-center gap-2">
                             <Clock size={12} />
                             {new Date(event.date).toLocaleDateString('id-ID', { day: 'numeric', month: 'short', year: 'numeric', hour: '2-digit', minute: '2-digit'})}
                        </div>
                        <div className="mt-2 text-xs font-medium text-blue-600 dark:text-blue-400 bg-blue-50 dark:bg-blue-900/20 py-1 px-2 rounded w-fit">
                            {event.status}
                        </div>
                    </div>
                ))}
                {upcomingList.length === 0 && (
                    <div className="h-full flex flex-col items-center justify-center text-gray-400 text-sm">
                        <p>Tidak ada agenda mendatang.</p>
                    </div>
                )}
            </div>
         </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Attendance Trend Area Chart */}
        <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border">
             <h3 className="text-lg font-semibold text-gray-800 dark:text-white mb-4 flex items-center gap-2">
                <ClipboardCheck size={20} className="text-green-500" /> Tren Kehadiran (5 Acara Terakhir)
            </h3>
            <div className="h-64">
                {attendanceTrend.length > 0 ? (
                    <ResponsiveContainer width="100%" height="100%">
                        <AreaChart data={attendanceTrend}>
                        <defs>
                            <linearGradient id="colorPv" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#10b981" stopOpacity={0.8}/>
                            <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                            </linearGradient>
                        </defs>
                        <XAxis dataKey="name" tick={{fontSize: 10}} interval={0} />
                        <YAxis unit="%" />
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? '#334155' : '#e5e7eb'}/>
                        <Tooltip contentStyle={tooltipStyle} formatter={(val: number) => `${val}% Hadir`} labelFormatter={(label, payload) => payload[0]?.payload.fullDate} />
                        <Area type="monotone" dataKey="percentage" stroke="#10b981" fillOpacity={1} fill="url(#colorPv)" />
                        </AreaChart>
                    </ResponsiveContainer>
                ) : (
                    <div className="h-full flex items-center justify-center text-gray-400 text-sm">
                        Belum ada data acara yang selesai.
                    </div>
                )}
            </div>
        </div>

        {/* Status Pie Chart */}
        <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border">
          <h3 className="text-lg font-semibold text-gray-800 dark:text-white mb-4">Status Program Kerja</h3>
          <div className="flex items-center">
            <div className="h-64 w-2/3">
                <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                    <Pie
                    data={statusData}
                    cx="50%"
                    cy="50%"
                    innerRadius={60}
                    outerRadius={80}
                    paddingAngle={5}
                    dataKey="value"
                    >
                    {statusData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                    </Pie>
                    <Tooltip contentStyle={tooltipStyle} />
                </PieChart>
                </ResponsiveContainer>
            </div>
            <div className="w-1/3 flex flex-col gap-3">
                 {statusData.map((entry, index) => (
                    <div key={entry.name}>
                        <div className="flex items-center text-xs text-gray-500 mb-1">
                            <span className="w-2 h-2 rounded-full mr-2" style={{ backgroundColor: COLORS[index] }}></span>
                            {entry.name}
                        </div>
                        <div className="text-xl font-bold text-gray-800 dark:text-white">{entry.value}</div>
                    </div>
                ))}
            </div>
          </div>
        </div>

      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { supabase } from './supabaseClient';
import { ViewState, Member, Role, Division, Program, Organization, Event, EventAttendance } from './types';
import { Auth } from './components/Auth';
import { Dashboard } from './pages/Dashboard';
import { Members } from './pages/Members';
import { Divisions } from './pages/Divisions';
import { Organizations } from './pages/Organizations';
import { Programs } from './pages/Programs';
import { Events } from './pages/Events';
import { Roles } from './pages/Roles';
import { Help } from './components/Help';
import { 
  LayoutDashboard, 
  Users, 
  Layers, 
  Briefcase, 
  LogOut, 
  Sun, 
  Moon, 
  Building2, 
  ShieldCheck,
  ChevronLeft,
  ChevronRight,
  CalendarDays
} from './components/ui/Icons';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [view, setView] = useState<ViewState>('DASHBOARD');
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);

  // Theme State
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('theme') as 'light' | 'dark' || 'light';
    }
    return 'light';
  });

  // Data State
  const [members, setMembers] = useState<Member[]>([]);
  const [roles, setRoles] = useState<Role[]>([]);
  const [divisions, setDivisions] = useState<Division[]>([]);
  const [organizations, setOrganizations] = useState<Organization[]>([]);
  const [programs, setPrograms] = useState<Program[]>([]);
  const [events, setEvents] = useState<Event[]>([]);
  const [attendance, setAttendance] = useState<EventAttendance[]>([]);

  const [loadingData, setLoadingData] = useState(false);
  const [dbError, setDbError] = useState(false);

  // Theme Effect
  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
    });

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    return () => subscription.unsubscribe();
  }, []);

  const fetchData = async () => {
    if (!session) return;
    setLoadingData(true);
    setDbError(false);

    try {
      const [membersRes, rolesRes, divisionsRes, programsRes, orgsRes, eventsRes, attendRes] = await Promise.all([
        supabase.from('members').select('*, divisions(name), roles(name)'), // Join basic info
        supabase.from('roles').select('*'),
        supabase.from('divisions').select('*'),
        supabase.from('programs').select('*'),
        supabase.from('organizations').select('*'),
        supabase.from('events').select('*'),
        supabase.from('event_attendance').select('*')
      ]);

      if (membersRes.error || rolesRes.error || divisionsRes.error || programsRes.error || orgsRes.error) {
        throw new Error('Database Error');
      }

      setMembers(membersRes.data || []);
      setRoles(rolesRes.data || []);
      setDivisions(divisionsRes.data || []);
      setPrograms(programsRes.data || []);
      setOrganizations(orgsRes.data || []);
      setEvents(eventsRes.data || []);
      setAttendance(attendRes.data || []);

    } catch (error) {
      console.error('Error fetching data:', error);
      // Suppress error if tables don't exist yet (for new events feature)
      // setDbError(true); 
    } finally {
      setLoadingData(false);
    }
  };

  useEffect(() => {
    if (session) {
      fetchData();
    }
  }, [session]);

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  if (!session) {
    return <Auth onLogin={() => {}} />;
  }

  const NavItem = ({ id, label, icon: Icon }: { id: ViewState; label: string; icon: any }) => (
    <button
      onClick={() => setView(id)}
      title={isSidebarCollapsed ? label : ''}
      className={`w-full flex items-center ${isSidebarCollapsed ? 'justify-center px-2' : 'space-x-3 px-4'} py-3 rounded-lg transition text-sm font-medium ${
        view === id 
          ? 'bg-primary-50 dark:bg-primary-900/30 text-primary-700 dark:text-primary-400' 
          : 'text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 hover:text-gray-900 dark:hover:text-gray-200'
      }`}
    >
      <Icon size={20} className="shrink-0" />
      {!isSidebarCollapsed && <span>{label}</span>}
    </button>
  );

  return (
    <div className="flex min-h-screen bg-gray-50 dark:bg-dark-bg transition-colors duration-200">
      {/* Sidebar (Desktop) */}
      <aside 
        className={`${isSidebarCollapsed ? 'w-20' : 'w-64'} bg-white dark:bg-dark-card border-r border-gray-200 dark:border-dark-border fixed inset-y-0 left-0 z-20 hidden md:flex flex-col transition-all duration-300 ease-in-out`}
      >
        <div className={`p-6 border-b border-gray-100 dark:border-dark-border flex items-center ${isSidebarCollapsed ? 'justify-center' : 'justify-between'}`}>
          {!isSidebarCollapsed && (
            <div className="flex items-center space-x-2 text-primary-600 dark:text-primary-400 animate-in fade-in duration-300">
              <div className="bg-primary-600 dark:bg-primary-500 p-1.5 rounded-lg text-white">
                <Layers size={20} />
              </div>
              <span className="text-xl font-bold tracking-tight text-gray-900 dark:text-white">E-Yayasan</span>
            </div>
          )}
          {isSidebarCollapsed && (
             <div className="bg-primary-600 dark:bg-primary-500 p-1.5 rounded-lg text-white">
                <Layers size={20} />
             </div>
          )}
        </div>

        {/* Toggle Button */}
        <button 
            onClick={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
            className="absolute -right-3 top-20 bg-white dark:bg-gray-700 border border-gray-200 dark:border-gray-600 rounded-full p-1 shadow-sm hover:bg-gray-50 dark:hover:bg-gray-600 text-gray-500 dark:text-gray-300"
        >
            {isSidebarCollapsed ? <ChevronRight size={14} /> : <ChevronLeft size={14} />}
        </button>

        <nav className="flex-1 p-3 space-y-2 overflow-y-auto overflow-x-hidden mt-4">
          {!isSidebarCollapsed && (
            <div className="text-xs font-semibold text-gray-400 dark:text-gray-500 uppercase tracking-wider mb-2 px-4 transition-opacity duration-300">
              Menu Utama
            </div>
          )}
          <NavItem id="DASHBOARD" label="Dashboard" icon={LayoutDashboard} />
          <NavItem id="EVENTS" label="Acara & Absensi" icon={CalendarDays} />
          <NavItem id="ORGANIZATIONS" label="Organisasi" icon={Building2} />
          <NavItem id="MEMBERS" label="Anggota" icon={Users} />
          <NavItem id="ROLES" label="Role / Peran" icon={ShieldCheck} />
          <NavItem id="DIVISIONS" label="Bidang" icon={Layers} />
          <NavItem id="PROGRAMS" label="Program Kerja" icon={Briefcase} />
        </nav>

        <div className="p-4 border-t border-gray-100 dark:border-dark-border space-y-2">
          <button
            onClick={toggleTheme}
            title={isSidebarCollapsed ? (theme === 'light' ? 'Mode Gelap' : 'Mode Terang') : ''}
            className={`w-full flex items-center ${isSidebarCollapsed ? 'justify-center px-2' : 'space-x-3 px-4'} py-2 text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded-lg transition text-sm font-medium`}
          >
            {theme === 'light' ? <Moon size={20} /> : <Sun size={20} />}
            {!isSidebarCollapsed && <span>{theme === 'light' ? 'Mode Gelap' : 'Mode Terang'}</span>}
          </button>

          <button
            onClick={handleLogout}
            title={isSidebarCollapsed ? 'Keluar' : ''}
            className={`w-full flex items-center ${isSidebarCollapsed ? 'justify-center px-2' : 'space-x-3 px-4'} py-2 text-gray-600 dark:text-gray-400 hover:text-red-600 dark:hover:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition text-sm font-medium`}
          >
            <LogOut size={20} />
            {!isSidebarCollapsed && <span>Keluar</span>}
          </button>
        </div>
      </aside>

      {/* Mobile Header (Visible only on small screens) */}
      <div className="md:hidden fixed top-0 w-full bg-white dark:bg-dark-card border-b border-gray-200 dark:border-dark-border z-20 px-4 py-3 flex justify-between items-center transition-colors duration-200">
        <span className="font-bold text-gray-900 dark:text-white">E-Yayasan</span>
        <div className="flex gap-2">
           <button onClick={toggleTheme} className="text-gray-500 dark:text-gray-400">
             {theme === 'light' ? <Moon size={20} /> : <Sun size={20} />}
           </button>
           <button onClick={handleLogout} className="text-gray-500 dark:text-gray-400">
            <LogOut size={20} />
          </button>
        </div>
      </div>

      {/* Main Content */}
      <main className={`flex-1 ${isSidebarCollapsed ? 'md:ml-20' : 'md:ml-64'} p-4 md:p-8 mt-12 md:mt-0 overflow-y-auto transition-all duration-300 ease-in-out`}>
        {dbError && (
           <div className="mb-6 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 text-red-700 dark:text-red-400 px-4 py-3 rounded-lg">
             <p className="font-bold">Koneksi Database Gagal</p>
             <p className="text-sm">Gagal mengambil data dari Supabase. Pastikan tabel telah dibuat.</p>
             <Help />
           </div>
        )}

        {!dbError && loadingData ? (
          <div className="flex items-center justify-center h-64 text-gray-400">
            Memuat data...
          </div>
        ) : (
          <div className="max-w-7xl mx-auto animate-in fade-in duration-300">
            {view === 'DASHBOARD' && (
              <Dashboard 
                members={members} 
                programs={programs} 
                divisions={divisions} 
                events={events}
                attendance={attendance}
                isDarkMode={theme === 'dark'} 
              />
            )}
            {view === 'EVENTS' && (
              <Events 
                events={events}
                members={members}
                attendance={attendance}
                onRefresh={fetchData}
              />
            )}
            {view === 'ORGANIZATIONS' && (
              <Organizations 
                data={organizations} 
                onRefresh={fetchData} 
              />
            )}
            {view === 'MEMBERS' && (
              <Members 
                data={members} 
                roles={roles} 
                divisions={divisions} 
                organizations={organizations}
                onRefresh={fetchData} 
                currentUserEmail={session?.user?.email}
              />
            )}
            {view === 'ROLES' && (
              <Roles 
                data={roles} 
                onRefresh={fetchData} 
              />
            )}
            {view === 'DIVISIONS' && (
              <Divisions 
                data={divisions} 
                onRefresh={fetchData} 
              />
            )}
            {view === 'PROGRAMS' && (
              <Programs 
                data={programs} 
                divisions={divisions} 
                organizations={organizations}
                members={members}
                onRefresh={fetchData} 
              />
            )}
          </div>
        )}
      </main>

      {/* Mobile Bottom Nav */}
      <div className="md:hidden fixed bottom-0 w-full bg-white dark:bg-dark-card border-t border-gray-200 dark:border-dark-border z-20 flex justify-around p-2 transition-colors duration-200 overflow-x-auto">
        <button onClick={() => setView('DASHBOARD')} className={`p-2 rounded ${view === 'DASHBOARD' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><LayoutDashboard size={20}/></button>
        <button onClick={() => setView('EVENTS')} className={`p-2 rounded ${view === 'EVENTS' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><CalendarDays size={20}/></button>
        <button onClick={() => setView('MEMBERS')} className={`p-2 rounded ${view === 'MEMBERS' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><Users size={20}/></button>
        <button onClick={() => setView('PROGRAMS')} className={`p-2 rounded ${view === 'PROGRAMS' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><Briefcase size={20}/></button>
      </div>
    </div>
  );
};

export default App;

export interface Role {
  id: string;
  name: string;
}

export interface Division {
  id: string;
  name: string;
  description?: string;
}

export interface Organization {
  id: string;
  name: string;
  description?: string;
}

export interface Member {
  id: string;
  full_name: string;
  email: string;
  phone?: string;
  role_id?: string;
  division_id?: string;
  organization_id?: string;
  // Joins
  roles?: Role;
  divisions?: Division;
  organizations?: Organization;
}

export interface Program {
  id: string;
  name: string;
  description?: string;
  cost: number; 
  month: string; // JSON string of array
  year: number;
  division_id: string;
  organization_id?: string;
  status: 'Planned' | 'In Progress' | 'Completed';
  // Joins
  divisions?: Division;
  organizations?: Organization;
}

export interface Event {
  id: string;
  name: string;
  date: string; // ISO Date string
  location?: string;
  description?: string;
  status: 'Upcoming' | 'Completed' | 'Cancelled';
}

export interface EventAttendance {
  id: string;
  event_id: string;
  member_id: string;
  status: 'Present' | 'Excused' | 'Absent';
  notes?: string;
}

export type ViewState = 'DASHBOARD' | 'MEMBERS' | 'DIVISIONS' | 'ORGANIZATIONS' | 'PROGRAMS' | 'ROLES' | 'EVENTS' | 'FINANCE';

import React, { useState, useMemo } from 'react';
import { Program, Division, Organization } from '../types';
import { FileText, Printer, Filter, Wallet, Building2, Calendar } from '../components/ui/Icons';

interface FinanceProps {
  programs: Program[];
  divisions: Division[];
  organizations: Organization[];
}

export const Finance: React.FC<FinanceProps> = ({ programs, divisions, organizations }) => {
  // Filter States
  const [selectedYear, setSelectedYear] = useState<number>(new Date().getFullYear());
  const [selectedMonth, setSelectedMonth] = useState<string>(''); // Empty means "All Months" (Yearly Report)
  const [selectedDivision, setSelectedDivision] = useState<string>(''); // Empty means "All Divisions"
  const [selectedOrg, setSelectedOrg] = useState<string>('');

  const allMonths = [
    'Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni', 
    'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'
  ];

  // Helper: Parse JSON Months
  const parseMonths = (monthStr: string): string[] => {
    try {
      const parsed = JSON.parse(monthStr);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      return [];
    }
  };

  // --- FILTER LOGIC ---
  const reportData = useMemo(() => {
    return programs.filter(p => {
      // 1. Filter Year
      if ((p.year || 2024) !== selectedYear) return false;

      // 2. Filter Organization
      if (selectedOrg && p.organization_id !== selectedOrg) return false;

      // 3. Filter Division
      if (selectedDivision && p.division_id !== selectedDivision) return false;

      // 4. Filter Month (Crucial Logic)
      if (selectedMonth) {
        const programMonths = parseMonths(p.month);
        // Program must include the selected month
        return programMonths.includes(selectedMonth);
      }

      return true;
    }).map(p => {
        // Calculate Cost to Show
        const programMonths = parseMonths(p.month);
        const duration = programMonths.length || 1;

        // If a specific month is selected, we assume we only submit cost for THAT month (Unit Cost)
        // If no month selected (Yearly), we show Total Cost
        const displayCost = selectedMonth ? (p.cost / duration) : p.cost;

        return {
            ...p,
            displayCost
        };
    }).sort((a, b) => {
        // Sort by Division then Name
        const divA = divisions.find(d => d.id === a.division_id)?.name || '';
        const divB = divisions.find(d => d.id === b.division_id)?.name || '';
        if (divA < divB) return -1;
        if (divA > divB) return 1;
        return a.name.localeCompare(b.name);
    });
  }, [programs, selectedYear, selectedMonth, selectedDivision, selectedOrg, divisions]);

  // Group by Division for the Report
  const groupedData = useMemo(() => {
      const groups: Record<string, typeof reportData> = {};
      reportData.forEach(item => {
          const divName = divisions.find(d => d.id === item.division_id)?.name || 'Lain-lain';
          if (!groups[divName]) groups[divName] = [];
          groups[divName].push(item);
      });
      return groups;
  }, [reportData, divisions]);

  const totalEstimate = reportData.reduce((acc, curr) => acc + curr.displayCost, 0);

  const formatCurrency = (val: number) => new Intl.NumberFormat('id-ID', { style: 'currency', currency: 'IDR', maximumFractionDigits: 0 }).format(val);

  // --- PRINT FUNCTION ---
  const handlePrint = () => {
    const orgName = organizations.find(o => o.id === selectedOrg)?.name || 'YAYASAN PENDIDIKAN';
    const titleTime = selectedMonth ? `BULAN ${selectedMonth.toUpperCase()} ${selectedYear}` : `TAHUN ${selectedYear}`;
    const divName = selectedDivision ? divisions.find(d => d.id === selectedDivision)?.name?.toUpperCase() : 'SEMUA BIDANG';

    const printWindow = window.open('', '', 'height=800,width=800');
    if (!printWindow) return;

    const rowsHtml = Object.entries(groupedData).map(([divName, items], idx) => {
        const itemsHtml = items.map((item, i) => `
            <tr>
                <td style="text-align: center;">${i + 1}</td>
                <td>${item.name}</td>
                <td>${item.description || '-'}</td>
                <td style="text-align: right;">${formatCurrency(item.displayCost)}</td>
            </tr>
        `).join('');

        const subTotal = items.reduce((acc, curr) => acc + curr.displayCost, 0);

        return `
            <tr style="background-color: #f3f4f6; font-weight: bold;">
                <td colspan="4" style="padding: 8px;">BIDANG: ${divName}</td>
            </tr>
            ${itemsHtml}
            <tr style="font-weight: bold;">
                <td colspan="3" style="text-align: right; padding-right: 10px;">Subtotal ${divName}</td>
                <td style="text-align: right;">${formatCurrency(subTotal)}</td>
            </tr>
        `;
    }).join('');

    printWindow.document.write(`
      <html>
        <head>
          <title>Laporan Pengajuan Keuangan</title>
          <style>
            body { font-family: 'Times New Roman', serif; padding: 40px; }
            .header { text-align: center; margin-bottom: 30px; border-bottom: 2px solid black; padding-bottom: 10px; }
            .header h1 { margin: 0; font-size: 18pt; text-transform: uppercase; }
            .header h2 { margin: 5px 0; font-size: 14pt; font-weight: normal; }
            .header p { margin: 0; font-size: 10pt; font-style: italic; }

            .report-title { text-align: center; margin-bottom: 20px; text-decoration: underline; font-weight: bold; font-size: 12pt; }

            table { width: 100%; border-collapse: collapse; margin-bottom: 20px; font-size: 11pt; }
            th, td { border: 1px solid black; padding: 6px 8px; vertical-align: top; }
            th { background-color: #e5e7eb; }

            .signatures { margin-top: 50px; display: flex; justify-content: space-between; page-break-inside: avoid; }
            .sig-block { text-align: center; width: 30%; }
            .sig-line { margin-top: 60px; border-top: 1px solid black; }
          </style>
        </head>
        <body>
          <div class="header">
            <h1>${orgName}</h1>
            <h2>PENGAJUAN ANGGARAN KEUANGAN</h2>
            <p>Laporan Generated System E-Yayasan</p>
          </div>

          <div class="report-title">
            RINCIAN PENGAJUAN ${divName}<br/>
            PERIODE: ${titleTime}
          </div>

          <table>
            <thead>
                <tr>
                    <th style="width: 5%;">No</th>
                    <th style="width: 40%;">Uraian Kegiatan</th>
                    <th style="width: 30%;">Keterangan</th>
                    <th style="width: 25%;">Jumlah Pengajuan</th>
                </tr>
            </thead>
            <tbody>
                ${rowsHtml}
            </tbody>
            <tfoot>
                <tr style="background-color: #d1fae5; font-weight: bold;">
                    <td colspan="3" style="text-align: right; font-size: 12pt;">TOTAL ESTIMASI PENGAJUAN</td>
                    <td style="text-align: right; font-size: 12pt;">${formatCurrency(totalEstimate)}</td>
                </tr>
            </tfoot>
          </table>

          <div class="signatures">
            <div class="sig-block">
                <div>Diajukan Oleh,<br/>Bendahara / Pemohon</div>
                <div class="sig-line">( ..................................... )</div>
            </div>
             <div class="sig-block">
                <div>Mengetahui,<br/>Ketua Bidang</div>
                <div class="sig-line">( ..................................... )</div>
            </div>
            <div class="sig-block">
                <div>Disetujui Oleh,<br/>Ketua Yayasan</div>
                <div class="sig-line">( ..................................... )</div>
            </div>
          </div>
          <script>
            window.onload = function() { window.print(); }
          </script>
        </body>
      </html>
    `);
    printWindow.document.close();
  };

  return (
    <div className="space-y-6">
       <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
          <FileText className="text-primary-600 dark:text-primary-400" /> Pengajuan Keuangan
        </h2>
      </div>

      {/* --- FILTERS --- */}
      <div className="bg-white dark:bg-dark-card p-5 rounded-xl border border-gray-100 dark:border-dark-border shadow-sm">
         <div className="flex items-center gap-2 mb-4 text-gray-700 dark:text-gray-200 font-semibold border-b border-gray-100 dark:border-dark-border pb-2">
            <Filter size={18} /> Konfigurasi Laporan
         </div>
         <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <div>
               <label className="text-xs text-gray-500 dark:text-gray-400 mb-1 block">Organisasi</label>
               <div className="relative">
                 <Building2 size={16} className="absolute left-3 top-2.5 text-gray-400"/>
                 <select 
                    className="w-full pl-9 pr-3 py-2 bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg text-sm text-gray-700 dark:text-white focus:ring-2 focus:ring-primary-500 outline-none"
                    value={selectedOrg}
                    onChange={(e) => setSelectedOrg(e.target.value)}
                 >
                    <option value="">Semua Organisasi</option>
                    {organizations.map(o => <option key={o.id} value={o.id}>{o.name}</option>)}
                 </select>
               </div>
            </div>

            <div>
               <label className="text-xs text-gray-500 dark:text-gray-400 mb-1 block">Tahun Anggaran</label>
               <div className="relative">
                 <Calendar size={16} className="absolute left-3 top-2.5 text-gray-400"/>
                 <input 
                    type="number"
                    className="w-full pl-9 pr-3 py-2 bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg text-sm text-gray-700 dark:text-white focus:ring-2 focus:ring-primary-500 outline-none"
                    value={selectedYear}
                    onChange={(e) => setSelectedYear(Number(e.target.value))}
                 />
               </div>
            </div>

            <div>
               <label className="text-xs text-gray-500 dark:text-gray-400 mb-1 block">Bulan Pengajuan</label>
               <div className="relative">
                 <CalendarDays size={16} className="absolute left-3 top-2.5 text-gray-400"/>
                 <select 
                    className="w-full pl-9 pr-3 py-2 bg-gray-50 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg text-sm text-gray-700 dark:text-white focus:ring-2 focus:ring-primary-500 outline-none"
                    value={selectedMonth}
                    onChange={(e) => setSelectedMonth(e.target.value)}
                 >
                    <option value="">-- Laporan Satu Tahun --</option>
                    {allMonths.map(m => <option key={m} value={m}>{m}</option>)}
                 </select>
