import React, { useState, useRef, useEffect } from 'react';
import { supabase } from '../supabaseClient';
import { Event, EventAttendance, Member } from '../types';
import { 
  Plus, Edit, Trash2, CalendarDays, MapPin, 
  ClipboardCheck, CheckCircle2, XCircle, HelpCircle, 
  Clock, Search, ChevronLeft, Maximize2, Minimize2, PieChart
} from '../components/ui/Icons';
import { Modal } from '../components/Modal';
import { PieChart as RePieChart, Pie, Cell, ResponsiveContainer, Tooltip as ReTooltip, Legend } from 'recharts';

interface EventsProps {
  events: Event[];
  members: Member[];
  attendance: EventAttendance[];
  onRefresh: () => void;
}

export const Events: React.FC<EventsProps> = ({ events, members, attendance, onRefresh }) => {
  const [view, setView] = useState<'LIST' | 'ATTENDANCE'>('LIST');
  const [selectedEvent, setSelectedEvent] = useState<Event | null>(null);

  // Full Screen State
  const containerRef = useRef<HTMLDivElement>(null);
  const [isFullScreen, setIsFullScreen] = useState(false);

  // Modal & Form State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<Event | null>(null);
  const [name, setName] = useState('');
  const [date, setDate] = useState('');
  const [time, setTime] = useState('');
  const [location, setLocation] = useState('');
  const [description, setDescription] = useState('');
  const [status, setStatus] = useState<'Upcoming' | 'Completed' | 'Cancelled'>('Upcoming');
  const [loading, setLoading] = useState(false);

  // Attendance Filter State
  const [attendanceSearch, setAttendanceSearch] = useState('');

  // --- SYNC STATE ON DATA REFRESH ---
  // Ini penting: Ketika onRefresh dipanggil, props 'events' berubah. 
  // Kita harus update 'selectedEvent' agar UI tidak kembali ke menu utama atau menampilkan data usang.
  useEffect(() => {
    if (view === 'ATTENDANCE' && selectedEvent) {
      const updatedEvent = events.find(e => e.id === selectedEvent.id);
      if (updatedEvent) {
        setSelectedEvent(updatedEvent);
      }
    }
  }, [events]);

  // Handle Full Screen Changes
  useEffect(() => {
    const handleFsChange = () => {
      setIsFullScreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      containerRef.current?.requestFullscreen().catch(err => {
        alert(`Error attempting to enable full-screen mode: ${err.message} (${err.name})`);
      });
    } else {
      document.exitFullscreen();
    }
  };

  // --- CRUD HANDLERS ---
  const handleOpenModal = (event?: Event) => {
    if (event) {
      setEditingItem(event);
      setName(event.name);

      const dt = new Date(event.date);
      setDate(dt.toISOString().split('T')[0]);
      // Handle local time extraction properly
      const hours = dt.getHours().toString().padStart(2, '0');
      const minutes = dt.getMinutes().toString().padStart(2, '0');
      setTime(`${hours}:${minutes}`);

      setLocation(event.location || '');
      setDescription(event.description || '');
      setStatus(event.status);
    } else {
      setEditingItem(null);
      setName('');
      setDate(new Date().toISOString().split('T')[0]);
      setTime('09:00');
      setLocation('');
      setDescription('');
      setStatus('Upcoming');
    }
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    const fullDate = new Date(`${date}T${time}:00`);

    const payload = {
      name,
      date: fullDate.toISOString(),
      location,
      description,
      status
    };

    try {
      if (editingItem) {
        const { error } = await supabase.from('events').update(payload).eq('id', editingItem.id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from('events').insert([payload]);
        if (error) throw error;
      }
      onRefresh();
      setIsModalOpen(false);
    } catch (error: any) {
      alert('Error: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Apakah Anda yakin ingin menghapus acara ini? Data absensi terkait akan hilang.')) return;
    try {
      const { error } = await supabase.from('events').delete().eq('id', id);
      if (error) throw error;

      // Jika yang dihapus adalah event yang sedang dilihat, kembali ke list
      if (selectedEvent?.id === id) {
          setView('LIST');
          setSelectedEvent(null);
      }

      onRefresh();
    } catch (error: any) {
      alert('Error: ' + error.message);
    }
  };

  // --- ATTENDANCE HANDLERS ---
  const openAttendance = (event: Event) => {
    setSelectedEvent(event);
    setView('ATTENDANCE');
    setAttendanceSearch('');
  };

  const handleAttendanceChange = async (memberId: string, newStatus: 'Present' | 'Absent' | 'Excused') => {
    if (!selectedEvent) return;

    // Optimistic check to avoid heavy reload if not needed, but we rely on DB
    try {
       const { error } = await supabase
        .from('event_attendance')
        .upsert(
            { 
                event_id: selectedEvent.id, 
                member_id: memberId, 
                status: newStatus 
            }, 
            { onConflict: 'event_id, member_id' }
        );

       if (error) throw error;

       // Trigger refresh. Note: Because of our useEffect above, the view will stay 'ATTENDANCE'
       onRefresh(); 
    } catch (error: any) {
        alert('Gagal update absensi: ' + error.message);
    }
  };

  const getAttendanceStats = (eventId: string) => {
    const eventAtt = attendance.filter(a => a.event_id === eventId);
    const present = eventAtt.filter(a => a.status === 'Present').length;
    const excused = eventAtt.filter(a => a.status === 'Excused').length;
    const absent = eventAtt.filter(a => a.status === 'Absent').length;
    return { present, excused, absent, total: eventAtt.length };
  };

  const filteredMembers = members.filter(m => 
    m.full_name.toLowerCase().includes(attendanceSearch.toLowerCase())
  );

  // Sort events by date descending
  const sortedEvents = [...events].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  // Chart Data for Attendance
  const chartData = selectedEvent ? [
      { name: 'Hadir', value: getAttendanceStats(selectedEvent.id).present, color: '#22c55e' },
      { name: 'Izin', value: getAttendanceStats(selectedEvent.id).excused, color: '#eab308' },
      { name: 'Alpha', value: getAttendanceStats(selectedEvent.id).absent, color: '#ef4444' },
  ].filter(d => d.value > 0) : [];

  return (
    <div ref={containerRef} className={`transition-all duration-300 ${isFullScreen ? 'bg-gray-50 dark:bg-dark-bg p-8 overflow-y-auto h-screen w-screen' : ''}`}>

      {/* Header with Fullscreen Toggle */}
      <div className="flex justify-between items-center mb-6">
          <div className="flex items-center gap-4">
             {view === 'ATTENDANCE' && (
                 <button 
                    onClick={() => setView('LIST')}
                    className="p-2 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg text-gray-500 hover:text-primary-600 transition"
                >
                    <ChevronLeft size={24} />
                </button>
             )}
             <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
                <CalendarDays className="text-primary-600 dark:text-primary-400" /> 
                {view === 'ATTENDANCE' && selectedEvent ? `Absensi: ${selectedEvent.name}` : 'Agenda & Acara'}
            </h2>
          </div>

          <div className="flex gap-2">
             <button
                onClick={toggleFullScreen}
                className="bg-white dark:bg-gray-700 text-gray-600 dark:text-gray-200 hover:text-primary-600 border border-gray-200 dark:border-gray-600 px-3 py-2 rounded-lg flex items-center gap-2 transition"
                title={isFullScreen ? "Keluar Full Screen" : "Full Screen"}
             >
                {isFullScreen ? <Minimize2 size={18} /> : <Maximize2 size={18} />}
                <span className="hidden sm:inline">{isFullScreen ? 'Minimize' : 'Full Screen'}</span>
             </button>

             {view === 'LIST' && (
                <button
                    onClick={() => handleOpenModal()}
                    className="bg-primary-600 hover:bg-primary-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition"
                >
                    <Plus size={18} /> Buat Acara
                </button>
             )}
          </div>
      </div>

      {/* --- RENDER VIEW: LIST --- */}
      {view === 'LIST' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-in fade-in duration-300">
          {sortedEvents.map(item => {
            const stats = getAttendanceStats(item.id);
            const eventDate = new Date(item.date);

            return (
              <div key={item.id} className="bg-white dark:bg-dark-card rounded-xl shadow-sm border border-gray-100 dark:border-dark-border overflow-hidden hover:shadow-md transition flex flex-col">
                <div className={`h-2 w-full ${item.status === 'Upcoming' ? 'bg-blue-500' : item.status === 'Completed' ? 'bg-green-500' : 'bg-red-500'}`}></div>
                <div className="p-5 flex-1 flex flex-col">
                  <div className="flex justify-between items-start mb-2">
                    <span className={`px-2 py-1 rounded text-[10px] uppercase font-bold tracking-wide ${
                        item.status === 'Upcoming' ? 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300' :
                        item.status === 'Completed' ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-300' :
                        'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-300'
                    }`}>
                        {item.status}
                    </span>
                    <div className="flex gap-2">
                        <button onClick={() => handleOpenModal(item)} className="text-gray-400 hover:text-blue-600"><Edit size={16}/></button>
                        <button onClick={() => handleDelete(item.id)} className="text-gray-400 hover:text-red-600"><Trash2 size={16}/></button>
                    </div>
                  </div>

                  <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-1 line-clamp-1">{item.name}</h3>
                  <div className="text-sm text-gray-500 dark:text-gray-400 space-y-1 mb-4">
                     <div className="flex items-center gap-2">
                        <CalendarDays size={14} /> 
                        <span>{eventDate.toLocaleDateString('id-ID', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</span>
                     </div>
                     <div className="flex items-center gap-2">
                        <Clock size={14} /> 
                        <span>{eventDate.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' })} WIB</span>
                     </div>
                     {item.location && (
                        <div className="flex items-center gap-2">
                            <MapPin size={14} /> 
                            <span className="truncate">{item.location}</span>
                        </div>
                     )}
                  </div>

                  <div className="mt-auto pt-4 border-t border-gray-100 dark:border-gray-700">
                     <div className="flex justify-between text-xs text-gray-500 dark:text-gray-400 mb-2">
                        <span>Kehadiran:</span>
                        <span className="font-semibold text-gray-700 dark:text-gray-200">{stats.present} Hadir</span>
                     </div>
                     <button 
                        onClick={() => openAttendance(item)}
                        className="w-full py-2 bg-gray-50 hover:bg-gray-100 dark:bg-gray-800 dark:hover:bg-gray-700 text-gray-700 dark:text-gray-200 text-sm font-medium rounded-lg flex items-center justify-center gap-2 border border-gray-200 dark:border-gray-600 transition"
                     >
                        <ClipboardCheck size={16} /> Kelola Absensi
                     </button>
                  </div>
                </div>
              </div>
            );
          })}
          {events.length === 0 && (
             <div className="col-span-full text-center py-12 text-gray-500 dark:text-gray-400 bg-white dark:bg-dark-card rounded-xl border border-dashed border-gray-200 dark:border-dark-border">
                Belum ada acara yang dijadwalkan.
             </div>
          )}
        </div>
      )}

      {/* --- RENDER VIEW: ATTENDANCE --- */}
      {view === 'ATTENDANCE' && selectedEvent && (
        <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
            {/* Event Info & Stats Chart */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* Info Card */}
                <div className="lg:col-span-2 bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border">
                    <div className="flex flex-col sm:flex-row justify-between items-start mb-4">
                        <div>
                            <h3 className="text-xl font-bold text-gray-900 dark:text-white mb-2">{selectedEvent.name}</h3>
                            <div className="space-y-1 text-sm text-gray-500 dark:text-gray-400">
                                <p className="flex items-center gap-2"><CalendarDays size={14}/> {new Date(selectedEvent.date).toLocaleDateString('id-ID', {weekday: 'long', day:'numeric', month:'long', year:'numeric'})}</p>
                                <p className="flex items-center gap-2"><Clock size={14}/> {new Date(selectedEvent.date).toLocaleTimeString('id-ID', {hour:'2-digit', minute:'2-digit'})} WIB</p>
                                <p className="flex items-center gap-2"><MapPin size={14}/> {selectedEvent.location || 'Online / Tidak ada lokasi'}</p>
                            </div>
                        </div>
                        <span className={`mt-2 sm:mt-0 px-3 py-1 rounded-full text-xs font-bold uppercase ${
                            selectedEvent.status === 'Upcoming' ? 'bg-blue-100 text-blue-700' : 
                            selectedEvent.status === 'Completed' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'
                        }`}>
                            {selectedEvent.status}
                        </span>
                    </div>

                    {/* Numeric Stats */}
                    <div className="grid grid-cols-3 gap-4 mt-6">
                        <div className="p-3 bg-green-50 dark:bg-green-900/20 rounded-lg text-center border border-green-100 dark:border-green-800">
                            <div className="text-2xl font-bold text-green-600 dark:text-green-400">{getAttendanceStats(selectedEvent.id).present}</div>
                            <div className="text-xs font-medium text-green-800 dark:text-green-300 uppercase">Hadir</div>
                        </div>
                        <div className="p-3 bg-yellow-50 dark:bg-yellow-900/20 rounded-lg text-center border border-yellow-100 dark:border-yellow-800">
                             <div className="text-2xl font-bold text-yellow-600 dark:text-yellow-400">{getAttendanceStats(selectedEvent.id).excused}</div>
                            <div className="text-xs font-medium text-yellow-800 dark:text-yellow-300 uppercase">Izin / Sakit</div>
                        </div>
                        <div className="p-3 bg-red-50 dark:bg-red-900/20 rounded-lg text-center border border-red-100 dark:border-red-800">
                             <div className="text-2xl font-bold text-red-600 dark:text-red-400">{getAttendanceStats(selectedEvent.id).absent}</div>
                            <div className="text-xs font-medium text-red-800 dark:text-red-300 uppercase">Alpha</div>
                        </div>
                    </div>
                </div>

                {/* Chart Card */}
                <div className="bg-white dark:bg-dark-card p-4 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border flex flex-col justify-center items-center">
                    <h4 className="text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2 flex items-center gap-2"><PieChart size={16}/> Grafik Kehadiran</h4>
                    <div className="w-full h-48">
                        {chartData.length > 0 ? (
                            <ResponsiveContainer width="100%" height="100%">
                                <RePieChart>
                                    <Pie
                                        data={chartData}
                                        cx="50%"
                                        cy="50%"
                                        innerRadius={40}
                                        outerRadius={70}
                                        paddingAngle={5}
                                        dataKey="value"
                                    >
                                        {chartData.map((entry, index) => (
                                            <Cell key={`cell-${index}`} fill={entry.color} />
                                        ))}
                                    </Pie>
                                    <ReTooltip />
                                    <Legend iconSize={8} wrapperStyle={{ fontSize: '10px' }} />
                                </RePieChart>
                            </ResponsiveContainer>
                        ) : (
                             <div className="h-full flex items-center justify-center text-xs text-gray-400 italic">Belum ada data</div>
                        )}
                    </div>
                </div>
            </div>

            {/* Attendance Table */}
            <div className="bg-white dark:bg-dark-card rounded-xl shadow-sm border border-gray-100 dark:border-dark-border overflow-hidden">
                <div className="p-4 border-b border-gray-100 dark:border-dark-border flex items-center gap-2">
                    <div className="relative flex-1 max-w-md">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                        <input 
                            type="text" 
                            placeholder="Cari anggota..." 
                            value={attendanceSearch}
                            onChange={(e) => setAttendanceSearch(e.target.value)}
                            className="w-full pl-9 pr-4 py-2 text-sm border border-gray-200 dark:border-gray-700 rounded-lg bg-gray-50 dark:bg-gray-800 dark:text-white focus:outline-none focus:ring-2 focus:ring-primary-500"
                        />
                    </div>
                    <div className="text-xs text-gray-500 italic ml-auto hidden sm:block">
                        *Data disimpan otomatis saat tombol ditekan
                    </div>
                </div>

                <div className="overflow-x-auto">
                    <table className="w-full text-left">
                        <thead className="bg-gray-50 dark:bg-gray-800 text-gray-600 dark:text-gray-400 text-xs uppercase font-semibold">
                            <tr>
                                <th className="px-6 py-4">Nama Anggota</th>
                                <th className="px-6 py-4 text-center">Hadir</th>
                                <th className="px-6 py-4 text-center">Izin</th>
                                <th className="px-6 py-4 text-center">Alpha / Absen</th>
                                <th className="px-6 py-4 text-right">Status Saat Ini</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100 dark:divide-dark-border">
                            {filteredMembers.map(member => {
                                const record = attendance.find(a => a.event_id === selectedEvent.id && a.member_id === member.id);
                                const currentStatus = record?.status; // undefined means Belum Absen

                                return (
                                    <tr key={member.id} className="hover:bg-gray-50 dark:hover:bg-gray-800/50">
                                        <td className="px-6 py-4">
                                            <div className="font-medium text-gray-900 dark:text-white">{member.full_name}</div>
                                            <div className="text-xs text-gray-500 dark:text-gray-400">{member.divisions?.name || 'Tanpa Bidang'}</div>
                                        </td>
                                        <td className="px-6 py-4 text-center">
                                            <button 
                                                onClick={() => handleAttendanceChange(member.id, 'Present')}
                                                className={`p-2 rounded-full transition ${currentStatus === 'Present' ? 'bg-green-100 text-green-600 ring-2 ring-green-500 shadow-sm' : 'text-gray-300 hover:bg-green-50 hover:text-green-500'}`}
                                            >
                                                <CheckCircle2 size={24} />
                                            </button>
                                        </td>
                                        <td className="px-6 py-4 text-center">
                                            <button 
                                                onClick={() => handleAttendanceChange(member.id, 'Excused')}
                                                className={`p-2 rounded-full transition ${currentStatus === 'Excused' ? 'bg-yellow-100 text-yellow-600 ring-2 ring-yellow-500 shadow-sm' : 'text-gray-300 hover:bg-yellow-50 hover:text-yellow-500'}`}
                                            >
                                                <HelpCircle size={24} />
                                            </button>
                                        </td>
                                        <td className="px-6 py-4 text-center">
                                            <button 
                                                onClick={() => handleAttendanceChange(member.id, 'Absent')}
                                                className={`p-2 rounded-full transition ${currentStatus === 'Absent' ? 'bg-red-100 text-red-600 ring-2 ring-red-500 shadow-sm' : 'text-gray-300 hover:bg-red-50 hover:text-red-500'}`}
                                            >
                                                <XCircle size={24} />
                                            </button>
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            {currentStatus ? (
                                                <span className={`px-3 py-1 rounded-full text-xs font-bold ${
                                                    currentStatus === 'Present' ? 'bg-green-100 text-green-700' :
                                                    currentStatus === 'Excused' ? 'bg-yellow-100 text-yellow-700' :
                                                    'bg-red-100 text-red-700'
                                                }`}>
                                                    {currentStatus === 'Present' ? 'HADIR' : currentStatus === 'Excused' ? 'IZIN' : 'ALPHA'}
                                                </span>
                                            ) : (
                                                <span className="text-xs text-gray-400 italic">Belum Absen</span>
                                            )}
                                        </td>
                                    </tr>
                                )
                            })}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
      )}

      {/* Modal Form for Creating/Editing Events */}
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={editingItem ? 'Edit Acara' : 'Buat Acara Baru'}>
        <form onSubmit={handleSubmit} className="space-y-4">
            <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Nama Acara</label>
                <input type="text" required value={name} onChange={e => setName(e.target.value)} className="input-field mt-1 w-full p-2 border rounded dark:bg-gray-800 dark:text-white dark:border-gray-600" />
            </div>
            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Tanggal</label>
                    <input type="date" required value={date} onChange={e => setDate(e.target.value)} className="input-field mt-1 w-full p-2 border rounded dark:bg-gray-800 dark:text-white dark:border-gray-600" />
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Jam</label>
                    <input type="time" required value={time} onChange={e => setTime(e.target.value)} className="input-field mt-1 w-full p-2 border rounded dark:bg-gray-800 dark:text-white dark:border-gray-600" />
                </div>
            </div>
            <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Lokasi</label>
                <input type="text" value={location} onChange={e => setLocation(e.target.value)} className="input-field mt-1 w-full p-2 border rounded dark:bg-gray-800 dark:text-white dark:border-gray-600" />
            </div>
            <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Deskripsi</label>
                <textarea rows={3} value={description} onChange={e => setDescription(e.target.value)} className="input-field mt-1 w-full p-2 border rounded dark:bg-gray-800 dark:text-white dark:border-gray-600" />
            </div>
            <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Status</label>
                <select value={status} onChange={e => setStatus(e.target.value as any)} className="input-field mt-1 w-full p-2 border rounded dark:bg-gray-800 dark:text-white dark:border-gray-600">
                    <option value="Upcoming">Upcoming (Akan Datang)</option>
                    <option value="Completed">Completed (Selesai)</option>
                    <option value="Cancelled">Cancelled (Dibatalkan)</option>
                </select>
            </div>
            <div className="pt-4 flex justify-end gap-3">
                <button type="button" onClick={() => setIsModalOpen(false)} className="px-4 py-2 bg-gray-200 dark:bg-gray-700 rounded text-gray-800 dark:text-white">Batal</button>
                <button type="submit" disabled={loading} className="px-4 py-2 bg-primary-600 text-white rounded hover:bg-primary-700">{loading ? 'Simpan...' : 'Simpan'}</button>
            </div>
        </form>
      </Modal>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { supabase } from './supabaseClient';
import { ViewState, Member, Role, Division, Program, Organization, Event, EventAttendance } from './types';
import { Auth } from './components/Auth';
import { Dashboard } from './pages/Dashboard';
import { Members } from './pages/Members';
import { Divisions } from './pages/Divisions';
import { Organizations } from './pages/Organizations';
import { Programs } from './pages/Programs';
import { Events } from './pages/Events';
import { Finance } from './pages/Finance'; // Import Finance
import { Roles } from './pages/Roles';
import { Help } from './components/Help';
import { 
  LayoutDashboard, 
  Users, 
  Layers, 
  Briefcase, 
  LogOut, 
  Sun, 
  Moon, 
  Building2, 
  ShieldCheck,
  ChevronLeft,
  ChevronRight,
  CalendarDays,
  FileText,
  Maximize2,
  Minimize2
} from './components/ui/Icons';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [view, setView] = useState<ViewState>('DASHBOARD');
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  const [isFullScreen, setIsFullScreen] = useState(false);

  // Theme State
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('theme') as 'light' | 'dark' || 'light';
    }
    return 'light';
  });

  // Data State
  const [members, setMembers] = useState<Member[]>([]);
  const [roles, setRoles] = useState<Role[]>([]);
  const [divisions, setDivisions] = useState<Division[]>([]);
  const [organizations, setOrganizations] = useState<Organization[]>([]);
  const [programs, setPrograms] = useState<Program[]>([]);
  const [events, setEvents] = useState<Event[]>([]);
  const [attendance, setAttendance] = useState<EventAttendance[]>([]);

  const [loadingData, setLoadingData] = useState(false);
  const [dbError, setDbError] = useState(false);

  // Theme Effect
  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  // Full Screen Effect
  useEffect(() => {
    const handleFsChange = () => {
      setIsFullScreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch((err) => {
        console.error(`Error attempting to enable full-screen mode: ${err.message}`);
      });
    } else {
      document.exitFullscreen();
    }
  };

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
    });

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    return () => subscription.unsubscribe();
  }, []);

  const fetchData = async () => {
    if (!session) return;
    setLoadingData(true);
    setDbError(false);

    try {
      const [membersRes, rolesRes, divisionsRes, programsRes, orgsRes, eventsRes, attendRes] = await Promise.all([
        supabase.from('members').select('*, divisions(name), roles(name)'), // Join basic info
        supabase.from('roles').select('*'),
        supabase.from('divisions').select('*'),
        supabase.from('programs').select('*'),
        supabase.from('organizations').select('*'),
        supabase.from('events').select('*'),
        supabase.from('event_attendance').select('*')
      ]);

      if (membersRes.error || rolesRes.error || divisionsRes.error || programsRes.error || orgsRes.error) {
        throw new Error('Database Error');
      }

      setMembers(membersRes.data || []);
      setRoles(rolesRes.data || []);
      setDivisions(divisionsRes.data || []);
      setPrograms(programsRes.data || []);
      setOrganizations(orgsRes.data || []);
      setEvents(eventsRes.data || []);
      setAttendance(attendRes.data || []);

    } catch (error) {
      console.error('Error fetching data:', error);
      // Suppress error if tables don't exist yet (for new events feature)
      // setDbError(true); 
    } finally {
      setLoadingData(false);
    }
  };

  useEffect(() => {
    if (session) {
      fetchData();
    }
  }, [session]);

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  if (!session) {
    return <Auth onLogin={() => {}} />;
  }

  const NavItem = ({ id, label, icon: Icon }: { id: ViewState; label: string; icon: any }) => (
    <button
      onClick={() => setView(id)}
      title={isSidebarCollapsed ? label : ''}
      className={`w-full flex items-center ${isSidebarCollapsed ? 'justify-center px-2' : 'space-x-3 px-4'} py-3 rounded-lg transition text-sm font-medium ${
        view === id 
          ? 'bg-primary-50 dark:bg-primary-900/30 text-primary-700 dark:text-primary-400' 
          : 'text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 hover:text-gray-900 dark:hover:text-gray-200'
      }`}
    >
      <Icon size={20} className="shrink-0" />
      {!isSidebarCollapsed && <span>{label}</span>}
    </button>
  );

  return (
    <div className="flex min-h-screen bg-gray-50 dark:bg-dark-bg transition-colors duration-200">
      {/* Sidebar (Desktop) */}
      <aside 
        className={`${isSidebarCollapsed ? 'w-20' : 'w-64'} bg-white dark:bg-dark-card border-r border-gray-200 dark:border-dark-border fixed inset-y-0 left-0 z-20 hidden md:flex flex-col transition-all duration-300 ease-in-out`}
      >
        <div className={`p-6 border-b border-gray-100 dark:border-dark-border flex items-center ${isSidebarCollapsed ? 'justify-center' : 'justify-between'}`}>
          {!isSidebarCollapsed && (
            <div className="flex items-center space-x-2 text-primary-600 dark:text-primary-400 animate-in fade-in duration-300">
              <div className="bg-primary-600 dark:bg-primary-500 p-1.5 rounded-lg text-white">
                <Layers size={20} />
              </div>
              <span className="text-xl font-bold tracking-tight text-gray-900 dark:text-white">E-Yayasan</span>
            </div>
          )}
          {isSidebarCollapsed && (
             <div className="bg-primary-600 dark:bg-primary-500 p-1.5 rounded-lg text-white">
                <Layers size={20} />
             </div>
          )}
        </div>

        {/* Toggle Button */}
        <button 
            onClick={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
            className="absolute -right-3 top-20 bg-white dark:bg-gray-700 border border-gray-200 dark:border-gray-600 rounded-full p-1 shadow-sm hover:bg-gray-50 dark:hover:bg-gray-600 text-gray-500 dark:text-gray-300"
        >
            {isSidebarCollapsed ? <ChevronRight size={14} /> : <ChevronLeft size={14} />}
        </button>

        <nav className="flex-1 p-3 space-y-2 overflow-y-auto overflow-x-hidden mt-4">
          {!isSidebarCollapsed && (
            <div className="text-xs font-semibold text-gray-400 dark:text-gray-500 uppercase tracking-wider mb-2 px-4 transition-opacity duration-300">
              Menu Utama
            </div>
          )}
          <NavItem id="DASHBOARD" label="Dashboard" icon={LayoutDashboard} />
          <NavItem id="EVENTS" label="Acara & Absensi" icon={CalendarDays} />
          <NavItem id="FINANCE" label="Pengajuan Keuangan" icon={FileText} />
          <NavItem id="ORGANIZATIONS" label="Organisasi" icon={Building2} />
          <NavItem id="MEMBERS" label="Anggota" icon={Users} />
          <NavItem id="ROLES" label="Role / Peran" icon={ShieldCheck} />
          <NavItem id="DIVISIONS" label="Bidang" icon={Layers} />
          <NavItem id="PROGRAMS" label="Program Kerja" icon={Briefcase} />
        </nav>

        <div className="p-4 border-t border-gray-100 dark:border-dark-border space-y-2">
          <button
            onClick={toggleFullScreen}
            title={isSidebarCollapsed ? (isFullScreen ? 'Keluar Full Screen' : 'Full Screen') : ''}
            className={`w-full flex items-center ${isSidebarCollapsed ? 'justify-center px-2' : 'space-x-3 px-4'} py-2 text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded-lg transition text-sm font-medium`}
          >
            {isFullScreen ? <Minimize2 size={20} /> : <Maximize2 size={20} />}
            {!isSidebarCollapsed && <span>{isFullScreen ? 'Exit Full Screen' : 'Full Screen'}</span>}
          </button>

          <button
            onClick={toggleTheme}
            title={isSidebarCollapsed ? (theme === 'light' ? 'Mode Gelap' : 'Mode Terang') : ''}
            className={`w-full flex items-center ${isSidebarCollapsed ? 'justify-center px-2' : 'space-x-3 px-4'} py-2 text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded-lg transition text-sm font-medium`}
          >
            {theme === 'light' ? <Moon size={20} /> : <Sun size={20} />}
            {!isSidebarCollapsed && <span>{theme === 'light' ? 'Mode Gelap' : 'Mode Terang'}</span>}
          </button>

          <button
            onClick={handleLogout}
            title={isSidebarCollapsed ? 'Keluar' : ''}
            className={`w-full flex items-center ${isSidebarCollapsed ? 'justify-center px-2' : 'space-x-3 px-4'} py-2 text-gray-600 dark:text-gray-400 hover:text-red-600 dark:hover:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition text-sm font-medium`}
          >
            <LogOut size={20} />
            {!isSidebarCollapsed && <span>Keluar</span>}
          </button>
        </div>
      </aside>

      {/* Mobile Header (Visible only on small screens) */}
      <div className="md:hidden fixed top-0 w-full bg-white dark:bg-dark-card border-b border-gray-200 dark:border-dark-border z-20 px-4 py-3 flex justify-between items-center transition-colors duration-200">
        <span className="font-bold text-gray-900 dark:text-white">E-Yayasan</span>
        <div className="flex gap-2">
           <button onClick={toggleFullScreen} className="text-gray-500 dark:text-gray-400">
             {isFullScreen ? <Minimize2 size={20} /> : <Maximize2 size={20} />}
           </button>
           <button onClick={toggleTheme} className="text-gray-500 dark:text-gray-400">
             {theme === 'light' ? <Moon size={20} /> : <Sun size={20} />}
           </button>
           <button onClick={handleLogout} className="text-gray-500 dark:text-gray-400">
            <LogOut size={20} />
          </button>
        </div>
      </div>

      {/* Main Content */}
      <main className={`flex-1 ${isSidebarCollapsed ? 'md:ml-20' : 'md:ml-64'} p-4 md:p-8 mt-12 md:mt-0 overflow-y-auto transition-all duration-300 ease-in-out`}>
        {dbError && (
           <div className="mb-6 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 text-red-700 dark:text-red-400 px-4 py-3 rounded-lg">
             <p className="font-bold">Koneksi Database Gagal</p>
             <p className="text-sm">Gagal mengambil data dari Supabase. Pastikan tabel telah dibuat.</p>
             <Help />
           </div>
        )}

        {!dbError && loadingData ? (
          <div className="flex items-center justify-center h-64 text-gray-400">
            Memuat data...
          </div>
        ) : (
          <div className="max-w-7xl mx-auto animate-in fade-in duration-300">
            {view === 'DASHBOARD' && (
              <Dashboard 
                members={members} 
                programs={programs} 
                divisions={divisions} 
                events={events}
                attendance={attendance}
                isDarkMode={theme === 'dark'} 
              />
            )}
            {view === 'EVENTS' && (
              <Events 
                events={events}
                members={members}
                attendance={attendance}
                onRefresh={fetchData}
              />
            )}
            {view === 'FINANCE' && (
              <Finance 
                programs={programs}
                divisions={divisions}
                organizations={organizations}
              />
            )}
            {view === 'ORGANIZATIONS' && (
              <Organizations 
                data={organizations} 
                onRefresh={fetchData} 
              />
            )}
            {view === 'MEMBERS' && (
              <Members 
                data={members} 
                roles={roles} 
                divisions={divisions} 
                organizations={organizations}
                onRefresh={fetchData} 
                currentUserEmail={session?.user?.email}
              />
            )}
            {view === 'ROLES' && (
              <Roles 
                data={roles} 
                onRefresh={fetchData} 
              />
            )}
            {view === 'DIVISIONS' && (
              <Divisions 
                data={divisions} 
                onRefresh={fetchData} 
              />
            )}
            {view === 'PROGRAMS' && (
              <Programs 
                data={programs} 
                divisions={divisions} 
                organizations={organizations}
                members={members}
                onRefresh={fetchData} 
              />
            )}
          </div>
        )}
      </main>

      {/* Mobile Bottom Nav */}
      <div className="md:hidden fixed bottom-0 w-full bg-white dark:bg-dark-card border-t border-gray-200 dark:border-dark-border z-20 flex justify-around p-2 transition-colors duration-200 overflow-x-auto">
        <button onClick={() => setView('DASHBOARD')} className={`p-2 rounded ${view === 'DASHBOARD' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><LayoutDashboard size={20}/></button>
        <button onClick={() => setView('EVENTS')} className={`p-2 rounded ${view === 'EVENTS' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><CalendarDays size={20}/></button>
        <button onClick={() => setView('FINANCE')} className={`p-2 rounded ${view === 'FINANCE' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><FileText size={20}/></button>
        <button onClick={() => setView('PROGRAMS')} className={`p-2 rounded ${view === 'PROGRAMS' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><Briefcase size={20}/></button>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { supabase } from '../supabaseClient';
import { Program, Division, Organization, Member } from '../types';
import { 
  Plus, Edit, Trash2, Calendar, Briefcase, Wallet, Filter, AlertTriangle, 
  X, Layers, CheckSquare, Square, Building2, ChevronRight, Table, 
  FileSpreadsheet, Maximize2, Minimize2 
} from '../components/ui/Icons';
import { Modal } from '../components/Modal';

interface ProgramsProps {
  data: Program[];
  divisions: Division[];
  organizations: Organization[];
  members: Member[]; // Added members prop to list personnel
  onRefresh: () => void;
}

type ViewMode = 'table' | 'sheet';

export const Programs: React.FC<ProgramsProps> = ({ data, divisions, organizations, members, onRefresh }) => {
  const [viewMode, setViewMode] = useState<ViewMode>('table');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<Program | null>(null);

  // Full Screen State
  const containerRef = useRef<HTMLDivElement>(null);
  const [isFullScreen, setIsFullScreen] = useState(false);

  // Description View Modal
  const [descModal, setDescModal] = useState<{isOpen: boolean, text: string, title: string}>({ isOpen: false, text: '', title: '' });

  // Filter State
  const [filterDivisionId, setFilterDivisionId] = useState('');
  const [filterOrgId, setFilterOrgId] = useState('');
  const [filterYear, setFilterYear] = useState<number | ''>('');
  const [filterMonths, setFilterMonths] = useState<string[]>([]); // Multi select

  // Delete Confirmation State
  const [deleteConfirm, setDeleteConfirm] = useState<{isOpen: boolean, id: string | null}>({ isOpen: false, id: null });

  // Form State
  const [name, setName] = useState('');
  const [description, setDescription] = useState(''); // New State
  const [costPerMonth, setCostPerMonth] = useState<number>(0);
  const [selectedMonths, setSelectedMonths] = useState<string[]>([]);
  const [divisionId, setDivisionId] = useState('');
  const [organizationId, setOrganizationId] = useState('');
  const [year, setYear] = useState<number>(new Date().getFullYear());
  const [status, setStatus] = useState<'Planned' | 'In Progress' | 'Completed'>('Planned');
  const [loading, setLoading] = useState(false);

  const allMonths = [
    'Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni', 
    'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'
  ];

  // Handle Full Screen Changes
  useEffect(() => {
    const handleFsChange = () => {
      setIsFullScreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      containerRef.current?.requestFullscreen().catch(err => {
        alert(`Error attempting to enable full-screen mode: ${err.message}`);
      });
    } else {
      document.exitFullscreen();
    }
  };

  // Get unique years for filter
  const availableYears = useMemo(() => {
    const years = new Set(data.map(p => p.year || 2024));
    return Array.from(years).sort((a: number, b: number) => b - a);
  }, [data]);

  // Helper: Parse Month
  const parseMonths = (monthStr: string): string[] => {
    try {
      const parsed = JSON.parse(monthStr);
      return Array.isArray(parsed) ? parsed : [monthStr];
    } catch (e) {
      return monthStr ? [monthStr] : [];
    }
  };

  // --- FILTERING & STATISTICS LOGIC ---

  const filteredData = useMemo(() => {
    let result = data.filter(item => {
      const itemMonths = parseMonths(item.month);

      const matchDivision = filterDivisionId ? item.division_id === filterDivisionId : true;
      const matchOrg = filterOrgId ? item.organization_id === filterOrgId : true;
      const matchYear = filterYear ? (item.year || 2024) === Number(filterYear) : true;

      // Filter Month logic
      const matchMonth = filterMonths.length > 0 
        ? itemMonths.some(m => filterMonths.includes(m))
        : true;

      return matchDivision && matchOrg && matchYear && matchMonth;
    });

    // Sort result by Division Name, then by Program Name for Sheet View consistency
    result.sort((a, b) => {
        const divA = divisions.find(d => d.id === a.division_id)?.name || '';
        const divB = divisions.find(d => d.id === b.division_id)?.name || '';
        if (divA < divB) return -1;
        if (divA > divB) return 1;
        return a.name.localeCompare(b.name);
    });

    return result;
  }, [data, filterDivisionId, filterOrgId, filterYear, filterMonths, divisions]);

  const stats = useMemo(() => {
    const totalCost = filteredData.reduce((acc, curr) => acc + curr.cost, 0);
    const totalPrograms = filteredData.length;
    const uniqueDivisionIds = new Set(filteredData.map(p => p.division_id));
    const divisionNames = Array.from(uniqueDivisionIds)
      .map(id => divisions.find(d => d.id === id)?.name)
      .filter(Boolean)
      .join(', ');

    return { totalCost, totalPrograms, divisionNames };
  }, [filteredData, divisions]);

  // --- HANDLERS ---

  const handleOpen = (program?: Program) => {
    if (program) {
      setEditingItem(program);
      setName(program.name);
      setDescription(program.description || '');

      const months = parseMonths(program.month);
      setSelectedMonths(months);

      const count = months.length || 1;
      setCostPerMonth(program.cost / count);

      setDivisionId(program.division_id);
      setOrganizationId(program.organization_id || '');
      setYear(program.year || new Date().getFullYear());
      setStatus(program.status);
    } else {
      setEditingItem(null);
      setName('');
      setDescription('');
      setCostPerMonth(0);
      setSelectedMonths([allMonths[new Date().getMonth()]]);
      setDivisionId(divisions[0]?.id || '');
      setOrganizationId(organizations[0]?.id || '');
      setYear(new Date().getFullYear());
      setStatus('Planned');
    }
    setIsModalOpen(true);
  };

  const toggleMonthSelection = (month: string, isFilter: boolean = false) => {
    const setState = isFilter ? setFilterMonths : setSelectedMonths;
    const currentState = isFilter ? filterMonths : selectedMonths;

    if (currentState.includes(month)) {
        setState(currentState.filter(m => m !== month));
    } else {
        const newSelection = [...currentState, month];
        // Sort chronologically
        setState(newSelection.sort((a, b) => allMonths.indexOf(a) - allMonths.indexOf(b)));
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    if (selectedMonths.length === 0) {
      alert("Pilih setidaknya satu bulan.");
      setLoading(false);
      return;
    }

    const totalCost = costPerMonth * selectedMonths.length;
    const monthString = JSON.stringify(selectedMonths);

    const payload = {
      name,
      description,
      cost: totalCost,
      month: monthString,
      division_id: divisionId,
      organization_id: organizationId || null,
      year: year,
      status
    };

    try {
      if (editingItem) {
        const { error } = await supabase.from('programs').update(payload).eq('id', editingItem.id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from('programs').insert([payload]);
        if (error) throw error;
      }
      onRefresh();
      setIsModalOpen(false);
    } catch (error: any) {
      alert('Error: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const confirmDelete = (id: string) => {
    setDeleteConfirm({ isOpen: true, id });
  };

  const executeDelete = async () => {
    if (!deleteConfirm.id) return;
    try {
      const { error } = await supabase.from('programs').delete().eq('id', deleteConfirm.id);
      if (error) throw error;
      onRefresh();
      setDeleteConfirm({ isOpen: false, id: null });
    } catch (error: any) {
      alert('Error: ' + error.message);
    }
  };

  const formatCurrency = (val: number) => new Intl.NumberFormat('id-ID', { style: 'currency', currency: 'IDR', maximumFractionDigits: 0 }).format(val);

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'Completed': return 'bg-green-100 dark:bg-green-900/40 text-green-800 dark:text-green-300';
      case 'In Progress': return 'bg-blue-100 dark:bg-blue-900/40 text-blue-800 dark:text-blue-300';
      default: return 'bg-gray-100 dark:bg-gray-700 text-gray-800 dark:text-gray-300';
    }
  };

  const resetFilters = () => {
    setFilterDivisionId('');
    setFilterOrgId('');
    setFilterYear('');
    setFilterMonths([]);
  };

  // --- SHEET VIEW RENDER ---
  const renderSheetView = () => {
    // Group Data by Division
    const groupedData = new Map<string, Program[]>();
    filteredData.forEach(item => {
        const existing = groupedData.get(item.division_id) || [];
        existing.push(item);
        groupedData.set(item.division_id, existing);
    });

    return (
        <div className="bg-white dark:bg-dark-card rounded-xl shadow-sm border border-gray-100 dark:border-dark-border overflow-hidden flex-1 flex flex-col">
            <div className="overflow-auto flex-1">
                <table className="w-full text-left border-collapse border border-gray-300 dark:border-gray-700 min-w-[1200px]">
                    <thead className="bg-emerald-600 text-white text-xs uppercase font-bold text-center sticky top-0 z-10">
                        <tr>
                            <th className="border border-emerald-700 px-2 py-3 w-10 bg-emerald-600">No</th>
                            <th className="border border-emerald-700 px-2 py-3 w-32 bg-emerald-600">Bidang</th>
                            <th className="border border-emerald-700 px-2 py-3 w-40 bg-emerald-600">Personil</th>
                            <th className="border border-emerald-700 px-2 py-3 w-10 bg-emerald-600">No</th>
                            <th className="border border-emerald-700 px-2 py-3 min-w-[200px] bg-emerald-600">Kegiatan</th>
                            <th className="border border-emerald-700 px-2 py-3 min-w-[150px] bg-emerald-600">Keterangan</th>
                            <th className="border border-emerald-700 px-2 py-3 w-28 bg-emerald-600">Biaya</th>
                            {/* Months 1-12 */}
                            {Array.from({length: 12}, (_, i) => i + 1).map(m => (
                                <th key={m} className="border border-emerald-700 px-1 py-3 w-8 bg-emerald-600">{m}</th>
                            ))}
                            <th className="border border-emerald-700 px-2 py-3 w-16 bg-emerald-600">Jml</th>
                            <th className="border border-emerald-700 px-2 py-3 w-32 bg-emerald-600">Total Biaya</th>
                            <th className="border border-emerald-700 px-2 py-3 w-20 bg-emerald-600">Aksi</th>
                        </tr>
                    </thead>
                    <tbody className="text-xs text-gray-800 dark:text-gray-200">
                        {Array.from(groupedData.entries()).map(([divId, groupItems], groupIndex) => {
                             const divName = divisions.find(d => d.id === divId)?.name || 'Unknown';
                             // Get Members for this division
                             const divMembers = members
                                .filter(m => m.division_id === divId)
                                .map(m => m.full_name)
                                .join(', ');

                             return groupItems.map((item, index) => {
                                 const itemMonths = parseMonths(item.month);
                                 const count = itemMonths.length;
                                 const unitCost = count > 0 ? item.cost / count : 0;
                                 const isFirst = index === 0;

                                 return (
                                     <tr key={item.id} className="hover:bg-gray-50 dark:hover:bg-gray-800">
                                         {/* Group Columns (Rowspan) */}
                                         {isFirst && (
                                             <>
                                                 <td rowSpan={groupItems.length} className="border border-gray-300 dark:border-gray-700 px-2 py-2 text-center align-top font-bold bg-gray-50 dark:bg-gray-800">
                                                     {groupIndex + 1}
                                                 </td>
                                                 <td rowSpan={groupItems.length} className="border border-gray-300 dark:border-gray-700 px-2 py-2 align-top font-bold bg-gray-50 dark:bg-gray-800 rotate-180 [writing-mode:vertical-rl] text-center uppercase tracking-widest h-full min-h-[100px]">
                                                     {divName}
                                                 </td>
                                                 <td rowSpan={groupItems.length} className="border border-gray-300 dark:border-gray-700 px-2 py-2 align-top bg-gray-50 dark:bg-gray-800">
                                                     {divMembers || '-'}
                                                 </td>
                                             </>
                                         )}

                                         {/* Program Columns */}
                                         <td className="border border-gray-300 dark:border-gray-700 px-2 py-2 text-center">{index + 1}</td>
                                         <td className="border border-gray-300 dark:border-gray-700 px-2 py-2 font-medium">{item.name}</td>
                                         <td className="border border-gray-300 dark:border-gray-700 px-2 py-2">{item.description}</td>
                                         <td className="border border-gray-300 dark:border-gray-700 px-2 py-2 text-right whitespace-nowrap">
                                            {new Intl.NumberFormat('id-ID').format(unitCost)}
                                         </td>

                                         {/* Months Matrix */}
                                         {allMonths.map(m => (
                                             <td key={m} className="border border-gray-300 dark:border-gray-700 px-1 py-1 text-center bg-gray-50/50 dark:bg-gray-900/30">
                                                 {itemMonths.includes(m) ? 'X' : ''}
                                             </td>
                                         ))}

                                         <td className="border border-gray-300 dark:border-gray-700 px-2 py-2 text-center font-bold">{count}</td>
                                         <td className="border border-gray-300 dark:border-gray-700 px-2 py-2 text-right font-bold whitespace-nowrap">
                                            {new Intl.NumberFormat('id-ID').format(item.cost)}
                                         </td>
                                         <td className="border border-gray-300 dark:border-gray-700 px-1 py-2 text-center">
                                            <div className="flex justify-center gap-1">
                                                <button onClick={() => handleOpen(item)} title="Edit"><Edit size={14} className="text-blue-500" /></button>
                                                <button onClick={() => confirmDelete(item.id)} title="Hapus"><Trash2 size={14} className="text-red-500" /></button>
                                            </div>
                                         </td>
                                     </tr>
                                 );
                             });
                        })}
                        {filteredData.length === 0 && (
                            <tr>
                                <td colSpan={19} className="p-8 text-center text-gray-500 dark:text-gray-400 border border-gray-300 dark:border-gray-700">
                                    Tidak ada data untuk ditampilkan.
                                </td>
                            </tr>
                        )}
                        {/* Grand Total Row */}
                         {filteredData.length > 0 && (
                            <tr className="bg-emerald-50 dark:bg-emerald-900/20 font-bold sticky bottom-0 z-10">
                                <td colSpan={17} className="border border-gray-300 dark:border-gray-700 px-4 py-3 text-right text-emerald-800 dark:text-emerald-300 uppercase bg-emerald-50 dark:bg-emerald-900/20">
                                    Total Anggaran
                                </td>
                                <td colSpan={2} className="border border-gray-300 dark:border-gray-700 px-4 py-3 text-right text-emerald-800 dark:text-emerald-300 text-sm bg-emerald-50 dark:bg-emerald-900/20">
                                    {formatCurrency(filteredData.reduce((sum, item) => sum + item.cost, 0))}
                                </td>
                            </tr>
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    );
  }

  // --- STANDARD TABLE VIEW RENDER ---
  const renderTableView = () => (
    <div className="bg-white dark:bg-dark-card rounded-xl shadow-sm border border-gray-100 dark:border-dark-border overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-gray-50 dark:bg-gray-800 text-gray-600 dark:text-gray-400 text-xs uppercase font-semibold">
              <tr>
                <th className="px-6 py-4 w-1/5">Nama Program</th>
                <th className="px-6 py-4 w-1/5">Deskripsi</th>
                <th className="px-6 py-4">Organisasi</th>
                <th className="px-6 py-4">Jadwal & Tahun</th>
                <th className="px-6 py-4">Biaya</th>
                <th className="px-6 py-4">Bidang</th>
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4 text-right">Aksi</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-dark-border">
              {filteredData.map((item) => {
                const months = parseMonths(item.month);
                const monthsCount = months.length;
                const unitCost = item.cost / (monthsCount || 1);

                return (
                <tr key={item.id} className="hover:bg-gray-50 dark:hover:bg-gray-800/50 transition">
                  <td className="px-6 py-4 align-top">
                    <div className="font-bold text-gray-900 dark:text-white text-sm">{item.name}</div>
                  </td>
                  <td className="px-6 py-4 align-top">
                     {item.description ? (
                        <div 
                          className="text-xs text-gray-600 dark:text-gray-300 cursor-pointer hover:text-blue-600 dark:hover:text-blue-400 flex items-start gap-1 group"
                          onClick={() => setDescModal({isOpen: true, text: item.description || '', title: item.name})}
                        >
                            <span className="line-clamp-2">{item.description}</span>
                            <ChevronRight size={14} className="opacity-0 group-hover:opacity-100 transition-opacity shrink-0" />
                        </div>
                     ) : (
                        <span className="text-xs text-gray-400 italic"> - </span>
                     )}
                  </td>
                  <td className="px-6 py-4 align-top">
                    <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-indigo-50 text-indigo-800 dark:bg-indigo-900/30 dark:text-indigo-300">
                        {organizations.find(o => o.id === item.organization_id)?.name || 'N/A'}
                    </span>
                  </td>
                  <td className="px-6 py-4 align-top text-sm text-gray-600 dark:text-gray-300 min-w-[140px]">
                    <div className="font-semibold mb-1 text-gray-900 dark:text-white">{item.year || 2024}</div>
                    <div className="flex flex-wrap gap-1">
                      {months.map(m => (
                        <span key={m} className={`px-1.5 py-0.5 rounded text-[10px] ${
                          filterMonths.includes(m)
                            ? 'bg-primary-100 text-primary-700 dark:bg-primary-900/50 dark:text-primary-300 font-bold ring-1 ring-primary-200' 
                            : 'bg-gray-100 dark:bg-gray-700'
                        }`}>
                          {m.substring(0, 3)}
                        </span>
                      ))}
                    </div>
                  </td>
                  <td className="px-6 py-4 align-top text-sm">
                    <div className="font-bold text-gray-800 dark:text-white">{formatCurrency(item.cost)}</div>
                    <div className="text-[10px] text-gray-500 dark:text-gray-400 mt-0.5">
                      {formatCurrency(unitCost)} / bln
                    </div>
                  </td>
                  <td className="px-6 py-4 align-top text-sm text-gray-600 dark:text-gray-400">
                    {divisions.find(d => d.id === item.division_id)?.name || '-'}
                  </td>
                  <td className="px-6 py-4 align-top">
                    <span className={`px-2 py-1 rounded-full text-[10px] font-semibold uppercase tracking-wide ${getStatusColor(item.status)}`}>
                      {item.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 align-top text-right">
                    <div className="flex justify-end gap-2">
                      <button onClick={() => handleOpen(item)} className="text-gray-400 hover:text-blue-600 dark:hover:text-blue-400">
                        <Edit size={18} />
                      </button>
                      <button onClick={() => confirmDelete(item.id)} className="text-gray-400 hover:text-red-600 dark:hover:text-red-400">
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </td>
                </tr>
              )})}
              {filteredData.length === 0 && (
                <tr>
                  <td colSpan={8} className="px-6 py-12 text-center text-gray-500 dark:text-gray-400">
                    <div className="flex flex-col items-center justify-center">
                      <Briefcase size={40} className="text-gray-300 dark:text-gray-600 mb-2" />
                      <p>Tidak ada program yang ditemukan.</p>
                      {(filterDivisionId || filterOrgId || filterYear || filterMonths.length > 0) && <p className="text-xs mt-1">Coba reset filter anda.</p>}
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
  );

  return (
    <div ref={containerRef} className={`transition-all duration-300 space-y-6 ${isFullScreen ? 'bg-gray-50 dark:bg-dark-bg p-8 overflow-y-auto h-screen w-screen fixed inset-0 z-50' : ''}`}>
      <div className="flex flex-col xl:flex-row justify-between items-start xl:items-center gap-4">
        <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
          <Briefcase className="text-primary-600 dark:text-primary-400" /> Program Kerja
        </h2>
        <div className="flex flex-col sm:flex-row gap-2 w-full xl:w-auto">
            {/* View Toggles */}
            <div className="flex bg-gray-100 dark:bg-gray-800 p-1 rounded-lg self-start">
                <button 
                    onClick={() => setViewMode('table')}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-sm font-medium transition ${
                        viewMode === 'table' 
                        ? 'bg-white dark:bg-gray-700 text-gray-900 dark:text-white shadow-sm' 
                        : 'text-gray-500 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-200'
                    }`}
                >
                    <Table size={16} /> Table
                </button>
                <button 
                    onClick={() => setViewMode('sheet')}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-sm font-medium transition ${
                        viewMode === 'sheet' 
                        ? 'bg-white dark:bg-gray-700 text-gray-900 dark:text-white shadow-sm' 
                        : 'text-gray-500 dark:text-gray-400 hover:text-gray-900 dark:hover:text-gray-200'
                    }`}
                >
                    <FileSpreadsheet size={16} /> Sheet
                </button>
            </div>

             <button
                onClick={toggleFullScreen}
                className="bg-white dark:bg-gray-700 text-gray-600 dark:text-gray-200 hover:text-primary-600 border border-gray-200 dark:border-gray-600 px-3 py-2 rounded-lg flex items-center justify-center gap-2 transition"
                title={isFullScreen ? "Keluar Full Screen" : "Focus Mode"}
             >
                {isFullScreen ? <Minimize2 size={18} /> : <Maximize2 size={18} />}
                <span className="hidden sm:inline">{isFullScreen ? 'Minimize' : 'Focus Mode'}</span>
             </button>

            <button
            onClick={() => handleOpen()}
            className="bg-primary-600 hover:bg-primary-700 text-white px-4 py-2 rounded-lg flex items-center justify-center gap-2 transition shadow-sm"
            >
            <Plus size={18} /> Tambah Program
            </button>
        </div>
      </div>

      {/* --- STATS SUMMARY & FILTERS --- */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* Left: Summary Cards */}
        <div className="lg:col-span-2 grid grid-cols-1 md:grid-cols-2 gap-4">
          <div className="bg-gradient-to-br from-blue-500 to-blue-600 dark:from-blue-600 dark:to-blue-800 p-5 rounded-xl text-white shadow-md">
            <div className="flex justify-between items-start">
               <div>
                  <p className="text-blue-100 text-sm font-medium mb-1">Total Anggaran (Tersaring)</p>
                  <h3 className="text-3xl font-bold">{formatCurrency(stats.totalCost)}</h3>
               </div>
               <div className="p-2 bg-white/20 rounded-lg">
                 <Wallet size={24} className="text-white" />
               </div>
            </div>
            <p className="text-sm text-blue-100 mt-4 flex items-center gap-1">
              <Layers size={14} /> 
