import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, AreaChart, Area } from 'recharts';
import { Wallet, Users, Layers, Briefcase, CalendarDays, ClipboardCheck, Clock } from '../components/ui/Icons';
import { Member, Program, Division, Event, EventAttendance } from '../types';

interface DashboardProps {
  members: Member[];
  programs: Program[];
  divisions: Division[];
  events: Event[];
  attendance: EventAttendance[];
  isDarkMode: boolean;
}

// Helper to parse months
const parseMonths = (monthStr: string): string[] => {
    try {
      const parsed = JSON.parse(monthStr);
      return Array.isArray(parsed) ? parsed : [monthStr];
    } catch (e) {
      return monthStr ? [monthStr] : [];
    }
  };

export const Dashboard: React.FC<DashboardProps> = ({ members, programs, divisions, events, attendance, isDarkMode }) => {

  // Statistics
  const totalCost = useMemo(() => programs.reduce((acc, curr) => acc + curr.cost, 0), [programs]);
  const activePrograms = programs.filter(p => p.status === 'In Progress').length;
  const upcomingEvents = events.filter(e => e.status === 'Upcoming').length;

  // Current Month Programs
  const currentMonthPrograms = useMemo(() => {
    const allMonths = [
        'Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni', 
        'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'
      ];
    const currentMonthIndex = new Date().getMonth();
    const currentMonthName = allMonths[currentMonthIndex];

    return programs.filter(p => {
        const months = parseMonths(p.month);
        return months.includes(currentMonthName);
    });
  }, [programs]);

  // Chart Data: Cost per Division
  const costPerDivision = useMemo(() => {
    const data: Record<string, number> = {};
    programs.forEach(p => {
      const divName = divisions.find(d => d.id === p.division_id)?.name || 'Unknown';
      data[divName] = (data[divName] || 0) + p.cost;
    });
    return Object.entries(data).map(([name, value]) => ({ name, value }));
  }, [programs, divisions]);

  // Chart Data: Programs per Status
  const statusData = useMemo(() => {
    const counts: Record<string, number> = { Planned: 0, 'In Progress': 0, Completed: 0 };
    programs.forEach(p => {
      if (counts[p.status] !== undefined) counts[p.status]++;
    });
    return Object.entries(counts).map(([name, value]) => ({ name, value }));
  }, [programs]);

  // Chart Data: Attendance Rate (Last 5 Completed Events)
  const attendanceTrend = useMemo(() => {
      // 1. Get completed events sorted by date
      const completedEvents = events
        .filter(e => e.status === 'Completed')
        .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
        .slice(-5); // Take last 5

      // 2. Calculate percentage per event
      return completedEvents.map(event => {
          const records = attendance.filter(a => a.event_id === event.id);
          const presentCount = records.filter(a => a.status === 'Present').length;
          // Assume total members is consistent, or use attendance count if larger (should handle active members ideally)
          const totalMembers = members.length || 1; 
          const percentage = Math.round((presentCount / totalMembers) * 100);

          return {
              name: event.name.length > 15 ? event.name.substring(0, 15) + '...' : event.name,
              fullDate: new Date(event.date).toLocaleDateString(),
              percentage: percentage,
              present: presentCount
          }
      });
  }, [events, attendance, members]);

  // List: Upcoming 3 Events
  const upcomingList = useMemo(() => {
      return events
        .filter(e => e.status === 'Upcoming')
        .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
        .slice(0, 3);
  }, [events]);


  const COLORS = ['#94a3b8', '#3b82f6', '#10b981'];

  const formatCurrency = (value: number) => 
    new Intl.NumberFormat('id-ID', { style: 'currency', currency: 'IDR', maximumFractionDigits: 0 }).format(value);

  const tooltipStyle = isDarkMode ? {
    backgroundColor: '#1e293b',
    borderColor: '#334155',
    color: '#f1f5f9'
  } : undefined;

  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold text-gray-800 dark:text-white">Dashboard Overview</h2>

      {/* Stat Cards Row 1: General */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border flex items-center space-x-4">
          <div className="p-3 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-lg">
            <Users size={24} />
          </div>
          <div>
            <p className="text-sm text-gray-500 dark:text-gray-400">Total Anggota</p>
            <p className="text-2xl font-bold text-gray-900 dark:text-white">{members.length}</p>
          </div>
        </div>

        <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border flex items-center space-x-4">
          <div className="p-3 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 rounded-lg">
            <CalendarDays size={24} />
          </div>
          <div>
            <p className="text-sm text-gray-500 dark:text-gray-400">Acara Mendatang</p>
            <p className="text-2xl font-bold text-gray-900 dark:text-white">{upcomingEvents}</p>
          </div>
        </div>

        <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border flex items-center space-x-4">
          <div className="p-3 bg-green-50 dark:bg-green-900/30 text-green-600 dark:text-green-400 rounded-lg">
            <Briefcase size={24} />
          </div>
          <div>
            <p className="text-sm text-gray-500 dark:text-gray-400">Program Aktif</p>
            <p className="text-2xl font-bold text-gray-900 dark:text-white">{activePrograms}</p>
          </div>
        </div>

        <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border flex items-center space-x-4">
          <div className="p-3 bg-amber-50 dark:bg-amber-900/30 text-amber-600 dark:text-amber-400 rounded-lg">
            <Wallet size={24} />
          </div>
          <div>
            <p className="text-sm text-gray-500 dark:text-gray-400">Total Anggaran</p>
            <p className="text-lg font-bold text-gray-900 dark:text-white truncate">{formatCurrency(totalCost)}</p>
          </div>
        </div>
      </div>

      {/* Program Bulan Ini Section */}
      <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border">
          <h3 className="text-lg font-semibold text-gray-800 dark:text-white mb-4 flex items-center gap-2">
             <Briefcase size={20} className="text-primary-500" /> Program Kerja Bulan Ini ({new Date().toLocaleDateString('id-ID', { month: 'long' })})
          </h3>
          <div className="overflow-x-auto">
             <table className="w-full text-left text-sm">
                <thead className="bg-gray-50 dark:bg-gray-800 text-gray-600 dark:text-gray-400 font-semibold">
                    <tr>
                        <th className="px-4 py-2 rounded-l-lg">Program</th>
                        <th className="px-4 py-2">Bidang</th>
                        <th className="px-4 py-2">Status</th>
                        <th className="px-4 py-2 rounded-r-lg text-right">Biaya</th>
                    </tr>
                </thead>
                <tbody className="divide-y divide-gray-100 dark:divide-dark-border">
                    {currentMonthPrograms.map(p => (
                        <tr key={p.id} className="hover:bg-gray-50 dark:hover:bg-gray-800/50">
                            <td className="px-4 py-2 font-medium text-gray-800 dark:text-white">{p.name}</td>
                            <td className="px-4 py-2 text-gray-600 dark:text-gray-400">{divisions.find(d => d.id === p.division_id)?.name || '-'}</td>
                            <td className="px-4 py-2">
                                <span className={`px-2 py-0.5 rounded text-xs ${
                                    p.status === 'Completed' ? 'bg-green-100 text-green-700' :
                                    p.status === 'In Progress' ? 'bg-blue-100 text-blue-700' : 'bg-gray-100 text-gray-700'
                                }`}>
                                    {p.status}
                                </span>
                            </td>
                            <td className="px-4 py-2 text-right font-medium text-gray-700 dark:text-gray-300">{formatCurrency(p.cost)}</td>
                        </tr>
                    ))}
                    {currentMonthPrograms.length === 0 && (
                        <tr>
                            <td colSpan={4} className="px-4 py-6 text-center text-gray-500 dark:text-gray-400 italic">
                                Tidak ada program yang dijadwalkan bulan ini.
                            </td>
                        </tr>
                    )}
                </tbody>
             </table>
          </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Main Chart: Cost */}
          <div className="lg:col-span-2 bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border">
            <h3 className="text-lg font-semibold text-gray-800 dark:text-white mb-4">Alokasi Anggaran per Bidang</h3>
            <div className="h-72">
                <ResponsiveContainer width="100%" height="100%">
                <BarChart data={costPerDivision}>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? '#334155' : '#e5e7eb'} />
                    <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 12, fill: isDarkMode ? '#94a3b8' : '#666'}} />
                    <YAxis axisLine={false} tickLine={false} tickFormatter={(val) => `Rp${val/1000}k`} tick={{fontSize: 12, fill: isDarkMode ? '#94a3b8' : '#666'}} />
                    <Tooltip 
                    formatter={(value: number) => formatCurrency(value)} 
                    contentStyle={tooltipStyle}
                    />
                    <Bar dataKey="value" fill="#3b82f6" radius={[4, 4, 0, 0]} />
                </BarChart>
                </ResponsiveContainer>
            </div>
         </div>

         {/* Side: Upcoming Events List */}
         <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border flex flex-col">
            <h3 className="text-lg font-semibold text-gray-800 dark:text-white mb-4 flex items-center gap-2">
                <CalendarDays size={20} className="text-indigo-500" /> Agenda Terdekat
            </h3>
            <div className="flex-1 space-y-4">
                {upcomingList.map(event => (
                    <div key={event.id} className="p-4 rounded-lg bg-gray-50 dark:bg-gray-800/50 border border-gray-100 dark:border-gray-700 flex flex-col gap-1">
                        <div className="flex justify-between items-start">
                             <span className="font-semibold text-gray-800 dark:text-white line-clamp-1">{event.name}</span>
                        </div>
                        <div className="text-xs text-gray-500 dark:text-gray-400 flex items-center gap-2">
                             <Clock size={12} />
                             {new Date(event.date).toLocaleDateString('id-ID', { day: 'numeric', month: 'short', year: 'numeric', hour: '2-digit', minute: '2-digit'})}
                        </div>
                        <div className="mt-2 text-xs font-medium text-blue-600 dark:text-blue-400 bg-blue-50 dark:bg-blue-900/20 py-1 px-2 rounded w-fit">
                            {event.status}
                        </div>
                    </div>
                ))}
                {upcomingList.length === 0 && (
                    <div className="h-full flex flex-col items-center justify-center text-gray-400 text-sm">
                        <p>Tidak ada agenda mendatang.</p>
                    </div>
                )}
            </div>
         </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Attendance Trend Area Chart */}
        <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border">
             <h3 className="text-lg font-semibold text-gray-800 dark:text-white mb-4 flex items-center gap-2">
                <ClipboardCheck size={20} className="text-green-500" /> Tren Kehadiran (5 Acara Terakhir)
            </h3>
            <div className="h-64">
                {attendanceTrend.length > 0 ? (
                    <ResponsiveContainer width="100%" height="100%">
                        <AreaChart data={attendanceTrend}>
                        <defs>
                            <linearGradient id="colorPv" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#10b981" stopOpacity={0.8}/>
                            <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                            </linearGradient>
                        </defs>
                        <XAxis dataKey="name" tick={{fontSize: 10}} interval={0} />
                        <YAxis unit="%" />
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke={isDarkMode ? '#334155' : '#e5e7eb'}/>
                        <Tooltip contentStyle={tooltipStyle} formatter={(val: number) => `${val}% Hadir`} labelFormatter={(label, payload) => payload[0]?.payload.fullDate} />
                        <Area type="monotone" dataKey="percentage" stroke="#10b981" fillOpacity={1} fill="url(#colorPv)" />
                        </AreaChart>
                    </ResponsiveContainer>
                ) : (
                    <div className="h-full flex items-center justify-center text-gray-400 text-sm">
                        Belum ada data acara yang selesai.
                    </div>
                )}
            </div>
        </div>

        {/* Status Pie Chart */}
        <div className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border">
          <h3 className="text-lg font-semibold text-gray-800 dark:text-white mb-4">Status Program Kerja</h3>
          <div className="flex items-center">
            <div className="h-64 w-2/3">
                <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                    <Pie
                    data={statusData}
                    cx="50%"
                    cy="50%"
                    innerRadius={60}
                    outerRadius={80}
                    paddingAngle={5}
                    dataKey="value"
                    >
                    {statusData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                    </Pie>
                    <Tooltip contentStyle={tooltipStyle} />
                </PieChart>
                </ResponsiveContainer>
            </div>
            <div className="w-1/3 flex flex-col gap-3">
                 {statusData.map((entry, index) => (
                    <div key={entry.name}>
                        <div className="flex items-center text-xs text-gray-500 mb-1">
                            <span className="w-2 h-2 rounded-full mr-2" style={{ backgroundColor: COLORS[index] }}></span>
                            {entry.name}
                        </div>
                        <div className="text-xl font-bold text-gray-800 dark:text-white">{entry.value}</div>
                    </div>
                ))}
            </div>
          </div>
        </div>

      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { supabase } from '../supabaseClient';
import { Event, EventAttendance, Member } from '../types';
import { 
  Plus, Edit, Trash2, CalendarDays, MapPin, 
  ClipboardCheck, CheckCircle2, XCircle, HelpCircle, 
  Clock, Search, ChevronLeft, Maximize2, Minimize2, PieChart, Users, AlertTriangle
} from '../components/ui/Icons';
import { Modal } from '../components/Modal';
import { PieChart as RePieChart, Pie, Cell, ResponsiveContainer, Tooltip as ReTooltip, Legend } from 'recharts';

interface EventsProps {
  events: Event[];
  members: Member[];
  attendance: EventAttendance[];
  onRefresh: () => void;
}

export const Events: React.FC<EventsProps> = ({ events, members, attendance, onRefresh }) => {
  const [view, setView] = useState<'LIST' | 'ATTENDANCE'>('LIST');
  const [selectedEvent, setSelectedEvent] = useState<Event | null>(null);

  // Full Screen State
  const containerRef = useRef<HTMLDivElement>(null);
  const [isFullScreen, setIsFullScreen] = useState(false);

  // Modal & Form State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<Event | null>(null);
  const [name, setName] = useState('');
  const [date, setDate] = useState('');
  const [time, setTime] = useState('');
  const [location, setLocation] = useState('');
  const [description, setDescription] = useState('');
  const [status, setStatus] = useState<'Upcoming' | 'Completed' | 'Cancelled'>('Upcoming');

  // Participant Selection State
  const [inviteType, setInviteType] = useState<'ALL' | 'SELECT'>('ALL');
  const [selectedInvitees, setSelectedInvitees] = useState<string[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Delete Confirm State
  const [deleteConfirm, setDeleteConfirm] = useState<{isOpen: boolean, id: string | null}>({ isOpen: false, id: null });

  // Attendance Filter State
  const [attendanceSearch, setAttendanceSearch] = useState('');

  // --- SYNC STATE ON DATA REFRESH ---
  useEffect(() => {
    if (view === 'ATTENDANCE' && selectedEvent) {
      const updatedEvent = events.find(e => e.id === selectedEvent.id);
      if (updatedEvent) {
        setSelectedEvent(updatedEvent);
      }
    }
  }, [events]);

  // Handle Full Screen Changes
  useEffect(() => {
    const handleFsChange = () => {
      setIsFullScreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      containerRef.current?.requestFullscreen().catch(err => {
        alert(`Error attempting to enable full-screen mode: ${err.message} (${err.name})`);
      });
    } else {
      document.exitFullscreen();
    }
  };

  // --- CRUD HANDLERS ---
  const handleOpenModal = (event?: Event) => {
    if (event) {
      setEditingItem(event);
      setName(event.name);

      const dt = new Date(event.date);
      setDate(dt.toISOString().split('T')[0]);
      // Handle local time extraction properly
      const hours = dt.getHours().toString().padStart(2, '0');
      const minutes = dt.getMinutes().toString().padStart(2, '0');
      setTime(`${hours}:${minutes}`);

      setLocation(event.location || '');
      setDescription(event.description || '');
      setStatus(event.status);
      setInviteType('ALL'); // Default for editing, logic handled differently if needed
      setSelectedInvitees([]);
    } else {
      setEditingItem(null);
      setName('');
      setDate(new Date().toISOString().split('T')[0]);
      setTime('09:00');
      setLocation('');
      setDescription('');
      setStatus('Upcoming');
      setInviteType('ALL');
      setSelectedInvitees([]);
    }
    setIsModalOpen(true);
  };

  const toggleInvitee = (id: string) => {
    setSelectedInvitees(prev => 
      prev.includes(id) ? prev.filter(mid => mid !== id) : [...prev, id]
    );
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    const fullDate = new Date(`${date}T${time}:00`);

    const payload = {
      name,
      date: fullDate.toISOString(),
      location,
      description,
      status
    };

    try {
      let eventId = editingItem?.id;

      if (editingItem) {
        const { error } = await supabase.from('events').update(payload).eq('id', editingItem.id);
        if (error) throw error;
      } else {
        const { data: newEvent, error } = await supabase.from('events').insert([payload]).select().single();
        if (error) throw error;
        eventId = newEvent.id;

        // --- Handle Initial Attendance Logic ---
        if (eventId) {
            let membersToAdd: string[] = [];
            if (inviteType === 'ALL') {
                membersToAdd = members.map(m => m.id);
            } else {
                membersToAdd = selectedInvitees;
            }

            if (membersToAdd.length > 0) {
                const attendancePayload = membersToAdd.map(mid => ({
                    event_id: eventId,
                    member_id: mid,
                    status: 'Absent' // Default status: Belum Hadir / Alpha until changed
                }));

                // Batch Insert
                const { error: attError } = await supabase.from('event_attendance').insert(attendancePayload);
                if (attError) console.error("Error creating initial attendance:", attError);
            }
        }
      }
      onRefresh();
      setIsModalOpen(false);
    } catch (error: any) {
      alert('Error: ' + error.message);
    } finally {
      setIsSubmitting(false);
    }
  };

  const confirmDelete = (id: string) => {
      setDeleteConfirm({ isOpen: true, id });
  }

  const handleDelete = async () => {
    if (!deleteConfirm.id) return;
    try {
      const { error } = await supabase.from('events').delete().eq('id', deleteConfirm.id);
      if (error) throw error;

      // Jika yang dihapus adalah event yang sedang dilihat, kembali ke list
      if (selectedEvent?.id === deleteConfirm.id) {
          setView('LIST');
          setSelectedEvent(null);
      }

      onRefresh();
      setDeleteConfirm({ isOpen: false, id: null });
    } catch (error: any) {
      alert('Error: ' + error.message);
    }
  };

  // --- ATTENDANCE HANDLERS ---
  const openAttendance = (event: Event) => {
    setSelectedEvent(event);
    setView('ATTENDANCE');
    setAttendanceSearch('');
  };

  const handleAttendanceChange = async (memberId: string, newStatus: 'Present' | 'Absent' | 'Excused') => {
    if (!selectedEvent) return;

    // Optimistic check to avoid heavy reload if not needed, but we rely on DB
    try {
       const { error } = await supabase
        .from('event_attendance')
        .upsert(
            { 
                event_id: selectedEvent.id, 
                member_id: memberId, 
                status: newStatus 
            }, 
            { onConflict: 'event_id, member_id' }
        );

       if (error) throw error;
       onRefresh(); 
    } catch (error: any) {
        alert('Gagal update absensi: ' + error.message);
    }
  };

  const getAttendanceStats = (eventId: string) => {
    const eventAtt = attendance.filter(a => a.event_id === eventId);
    const present = eventAtt.filter(a => a.status === 'Present').length;
    const excused = eventAtt.filter(a => a.status === 'Excused').length;
    const absent = eventAtt.filter(a => a.status === 'Absent').length;
    return { present, excused, absent, total: eventAtt.length };
  };

  const filteredMembers = members.filter(m => 
    m.full_name.toLowerCase().includes(attendanceSearch.toLowerCase())
  );

  // Sort events by date descending
  const sortedEvents = [...events].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  // Chart Data for Attendance
  const chartData = selectedEvent ? [
      { name: 'Hadir', value: getAttendanceStats(selectedEvent.id).present, color: '#22c55e' },
      { name: 'Izin', value: getAttendanceStats(selectedEvent.id).excused, color: '#eab308' },
      { name: 'Alpha', value: getAttendanceStats(selectedEvent.id).absent, color: '#ef4444' },
  ].filter(d => d.value > 0) : [];

  return (
    <div ref={containerRef} className={`transition-all duration-300 ${isFullScreen ? 'bg-gray-50 dark:bg-dark-bg p-8 overflow-y-auto h-screen w-screen' : ''}`}>

      {/* Header with Fullscreen Toggle */}
      <div className="flex justify-between items-center mb-6">
          <div className="flex items-center gap-4">
             {view === 'ATTENDANCE' && (
                 <button 
                    onClick={() => setView('LIST')}
                    className="p-2 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg text-gray-500 hover:text-primary-600 transition"
                >
                    <ChevronLeft size={24} />
                </button>
             )}
             <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
                <CalendarDays className="text-primary-600 dark:text-primary-400" /> 
                {view === 'ATTENDANCE' && selectedEvent ? `Absensi: ${selectedEvent.name}` : 'Agenda & Acara'}
            </h2>
          </div>

          <div className="flex gap-2">
             <button
                onClick={toggleFullScreen}
                className="bg-white dark:bg-gray-700 text-gray-600 dark:text-gray-200 hover:text-primary-600 border border-gray-200 dark:border-gray-600 px-3 py-2 rounded-lg flex items-center gap-2 transition"
                title={isFullScreen ? "Keluar Full Screen" : "Full Screen"}
             >
                {isFullScreen ? <Minimize2 size={18} /> : <Maximize2 size={18} />}
                <span className="hidden sm:inline">{isFullScreen ? 'Minimize' : 'Full Screen'}</span>
             </button>

             {view === 'LIST' && (
                <button
                    onClick={() => handleOpenModal()}
                    className="bg-primary-600 hover:bg-primary-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition"
                >
                    <Plus size={18} /> Buat Acara
                </button>
             )}
          </div>
      </div>

      {/* --- RENDER VIEW: LIST --- */}
      {view === 'LIST' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-in fade-in duration-300">
          {sortedEvents.map(item => {
            const stats = getAttendanceStats(item.id);
            const eventDate = new Date(item.date);

            return (
              <div key={item.id} className="bg-white dark:bg-dark-card rounded-xl shadow-sm border border-gray-100 dark:border-dark-border overflow-hidden hover:shadow-md transition flex flex-col">
                <div className={`h-2 w-full ${item.status === 'Upcoming' ? 'bg-blue-500' : item.status === 'Completed' ? 'bg-green-500' : 'bg-red-500'}`}></div>
                <div className="p-5 flex-1 flex flex-col">
                  <div className="flex justify-between items-start mb-2">
                    <span className={`px-2 py-1 rounded text-[10px] uppercase font-bold tracking-wide ${
                        item.status === 'Upcoming' ? 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300' :
                        item.status === 'Completed' ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-300' :
                        'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-300'
                    }`}>
                        {item.status}
                    </span>
                    <div className="flex gap-2">
                        <button onClick={() => handleOpenModal(item)} className="text-gray-400 hover:text-blue-600"><Edit size={16}/></button>
                        <button onClick={() => confirmDelete(item.id)} className="text-gray-400 hover:text-red-600"><Trash2 size={16}/></button>
                    </div>
                  </div>

                  <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-1 line-clamp-1">{item.name}</h3>
                  <div className="text-sm text-gray-500 dark:text-gray-400 space-y-1 mb-4">
                     <div className="flex items-center gap-2">
                        <CalendarDays size={14} /> 
                        <span>{eventDate.toLocaleDateString('id-ID', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</span>
                     </div>
                     <div className="flex items-center gap-2">
                        <Clock size={14} /> 
                        <span>{eventDate.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' })} WIB</span>
                     </div>
                     {item.location && (
                        <div className="flex items-center gap-2">
                            <MapPin size={14} /> 
                            <span className="truncate">{item.location}</span>
                        </div>
                     )}
                  </div>

                  <div className="mt-auto pt-4 border-t border-gray-100 dark:border-gray-700">
                     <div className="flex justify-between text-xs text-gray-500 dark:text-gray-400 mb-2">
                        <span>Kehadiran:</span>
                        <span className="font-semibold text-gray-700 dark:text-gray-200">{stats.present} Hadir</span>
                     </div>
                     <button 
                        onClick={() => openAttendance(item)}
                        className="w-full py-2 bg-gray-50 hover:bg-gray-100 dark:bg-gray-800 dark:hover:bg-gray-700 text-gray-700 dark:text-gray-200 text-sm font-medium rounded-lg flex items-center justify-center gap-2 border border-gray-200 dark:border-gray-600 transition"
                     >
                        <ClipboardCheck size={16} /> Kelola Absensi
                     </button>
                  </div>
                </div>
              </div>
            );
          })}
          {events.length === 0 && (
             <div className="col-span-full text-center py-12 text-gray-500 dark:text-gray-400 bg-white dark:bg-dark-card rounded-xl border border-dashed border-gray-200 dark:border-dark-border">
                Belum ada acara yang dijadwalkan.
             </div>
          )}
        </div>
      )}

      {/* --- RENDER VIEW: ATTENDANCE --- */}
      {view === 'ATTENDANCE' && selectedEvent && (
        <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
            {/* Event Info & Stats Chart */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* Info Card */}
                <div className="lg:col-span-2 bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border">
                    <div className="flex flex-col sm:flex-row justify-between items-start mb-4">
                        <div>
                            <h3 className="text-xl font-bold text-gray-900 dark:text-white mb-2">{selectedEvent.name}</h3>
                            <div className="space-y-1 text-sm text-gray-500 dark:text-gray-400">
                                <p className="flex items-center gap-2"><CalendarDays size={14}/> {new Date(selectedEvent.date).toLocaleDateString('id-ID', {weekday: 'long', day:'numeric', month:'long', year:'numeric'})}</p>
                                <p className="flex items-center gap-2"><Clock size={14}/> {new Date(selectedEvent.date).toLocaleTimeString('id-ID', {hour:'2-digit', minute:'2-digit'})} WIB</p>
                                <p className="flex items-center gap-2"><MapPin size={14}/> {selectedEvent.location || 'Online / Tidak ada lokasi'}</p>
                            </div>
                        </div>
                        <span className={`mt-2 sm:mt-0 px-3 py-1 rounded-full text-xs font-bold uppercase ${
                            selectedEvent.status === 'Upcoming' ? 'bg-blue-100 text-blue-700' : 
                            selectedEvent.status === 'Completed' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'
                        }`}>
                            {selectedEvent.status}
                        </span>
                    </div>

                    {/* Numeric Stats */}
                    <div className="grid grid-cols-3 gap-4 mt-6">
                        <div className="p-3 bg-green-50 dark:bg-green-900/20 rounded-lg text-center border border-green-100 dark:border-green-800">
                            <div className="text-2xl font-bold text-green-600 dark:text-green-400">{getAttendanceStats(selectedEvent.id).present}</div>
                            <div className="text-xs font-medium text-green-800 dark:text-green-300 uppercase">Hadir</div>
                        </div>
                        <div className="p-3 bg-yellow-50 dark:bg-yellow-900/20 rounded-lg text-center border border-yellow-100 dark:border-yellow-800">
                             <div className="text-2xl font-bold text-yellow-600 dark:text-yellow-400">{getAttendanceStats(selectedEvent.id).excused}</div>
                            <div className="text-xs font-medium text-yellow-800 dark:text-yellow-300 uppercase">Izin / Sakit</div>
                        </div>
                        <div className="p-3 bg-red-50 dark:bg-red-900/20 rounded-lg text-center border border-red-100 dark:border-red-800">
                             <div className="text-2xl font-bold text-red-600 dark:text-red-400">{getAttendanceStats(selectedEvent.id).absent}</div>
                            <div className="text-xs font-medium text-red-800 dark:text-red-300 uppercase">Alpha</div>
                        </div>
                    </div>
                </div>

                {/* Chart Card */}
                <div className="bg-white dark:bg-dark-card p-4 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border flex flex-col justify-center items-center">
                    <h4 className="text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2 flex items-center gap-2"><PieChart size={16}/> Grafik Kehadiran</h4>
                    <div className="w-full h-48">
                        {chartData.length > 0 ? (
                            <ResponsiveContainer width="100%" height="100%">
                                <RePieChart>
                                    <Pie
                                        data={chartData}
                                        cx="50%"
                                        cy="50%"
                                        innerRadius={40}
                                        outerRadius={70}
                                        paddingAngle={5}
                                        dataKey="value"
                                    >
                                        {chartData.map((entry, index) => (
                                            <Cell key={`cell-${index}`} fill={entry.color} />
                                        ))}
                                    </Pie>
                                    <ReTooltip />
                                    <Legend iconSize={8} wrapperStyle={{ fontSize: '10px' }} />
                                </RePieChart>
                            </ResponsiveContainer>
                        ) : (
                             <div className="h-full flex items-center justify-center text-xs text-gray-400 italic">Belum ada data</div>
                        )}
                    </div>
                </div>
            </div>

            {/* Attendance Table */}
            <div className="bg-white dark:bg-dark-card rounded-xl shadow-sm border border-gray-100 dark:border-dark-border overflow-hidden">
                <div className="p-4 border-b border-gray-100 dark:border-dark-border flex items-center gap-2">
                    <div className="relative flex-1 max-w-md">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                        <input 
                            type="text" 
                            placeholder="Cari anggota..." 
                            value={attendanceSearch}
                            onChange={(e) => setAttendanceSearch(e.target.value)}
                            className="w-full pl-9 pr-4 py-2 text-sm border border-gray-200 dark:border-gray-700 rounded-lg bg-gray-50 dark:bg-gray-800 dark:text-white focus:outline-none focus:ring-2 focus:ring-primary-500"
                        />
                    </div>
                    <div className="text-xs text-gray-500 italic ml-auto hidden sm:block">
                        *Data disimpan otomatis saat tombol ditekan
                    </div>
                </div>

                <div className="overflow-x-auto">
                    <table className="w-full text-left">
                        <thead className="bg-gray-50 dark:bg-gray-800 text-gray-600 dark:text-gray-400 text-xs uppercase font-semibold">
                            <tr>
                                <th className="px-6 py-4">Nama Anggota</th>
                                <th className="px-6 py-4 text-center">Hadir</th>
                                <th className="px-6 py-4 text-center">Izin</th>
                                <th className="px-6 py-4 text-center">Alpha / Absen</th>
                                <th className="px-6 py-4 text-right">Status Saat Ini</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100 dark:divide-dark-border">
                            {filteredMembers.map(member => {
                                const record = attendance.find(a => a.event_id === selectedEvent.id && a.member_id === member.id);
                                const currentStatus = record?.status; // undefined means Belum Absen

                                return (
                                    <tr key={member.id} className="hover:bg-gray-50 dark:hover:bg-gray-800/50">
                                        <td className="px-6 py-4">
                                            <div className="font-medium text-gray-900 dark:text-white">{member.full_name}</div>
                                            <div className="text-xs text-gray-500 dark:text-gray-400">{member.divisions?.name || 'Tanpa Bidang'}</div>
                                        </td>
                                        <td className="px-6 py-4 text-center">
                                            <button 
                                                onClick={() => handleAttendanceChange(member.id, 'Present')}
                                                className={`p-2 rounded-full transition ${currentStatus === 'Present' ? 'bg-green-100 text-green-600 ring-2 ring-green-500 shadow-sm' : 'text-gray-300 hover:bg-green-50 hover:text-green-500'}`}
                                            >
                                                <CheckCircle2 size={24} />
                                            </button>
                                        </td>
                                        <td className="px-6 py-4 text-center">
                                            <button 
                                                onClick={() => handleAttendanceChange(member.id, 'Excused')}
                                                className={`p-2 rounded-full transition ${currentStatus === 'Excused' ? 'bg-yellow-100 text-yellow-600 ring-2 ring-yellow-500 shadow-sm' : 'text-gray-300 hover:bg-yellow-50 hover:text-yellow-500'}`}
                                            >
                                                <HelpCircle size={24} />
                                            </button>
                                        </td>
                                        <td className="px-6 py-4 text-center">
                                            <button 
                                                onClick={() => handleAttendanceChange(member.id, 'Absent')}
                                                className={`p-2 rounded-full transition ${currentStatus === 'Absent' ? 'bg-red-100 text-red-600 ring-2 ring-red-500 shadow-sm' : 'text-gray-300 hover:bg-red-50 hover:text-red-500'}`}
                                            >
                                                <XCircle size={24} />
                                            </button>
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            {currentStatus ? (
                                                <span className={`px-3 py-1 rounded-full text-xs font-bold ${
                                                    currentStatus === 'Present' ? 'bg-green-100 text-green-700' :
                                                    currentStatus === 'Excused' ? 'bg-yellow-100 text-yellow-700' :
                                                    'bg-red-100 text-red-700'
                                                }`}>
                                                    {currentStatus === 'Present' ? 'HADIR' : currentStatus === 'Excused' ? 'IZIN' : 'ALPHA'}
                                                </span>
                                            ) : (
                                                <span className="text-xs text-gray-400 italic">Belum Absen</span>
                                            )}
                                        </td>
                                    </tr>
                                )
                            })}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
      )}

      {/* Modal Form for Creating/Editing Events */}
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={editingItem ? 'Edit Acara' : 'Buat Acara Baru'}>
        <form onSubmit={handleSubmit} className="space-y-4">
            <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Nama Acara</label>
                <input 
                    type="text" 
                    required 
                    value={name} 
                    onChange={e => setName(e.target.value)} 
                    className="mt-1 block w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 dark:text-white px-3 py-2 focus:border-primary-500 focus:ring-primary-500 outline-none" 
                />
            </div>
            <div className="grid grid-cols-2 gap-4">
                <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Tanggal</label>
                    <input 
                        type="date" 
                        required 
                        value={date} 
                        onChange={e => setDate(e.target.value)} 
                        className="mt-1 block w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 dark:text-white px-3 py-2 focus:border-primary-500 focus:ring-primary-500 outline-none" 
                    />
                </div>
                <div>
                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Jam</label>
                    <input 
                        type="time" 
                        required 
                        value={time} 
                        onChange={e => setTime(e.target.value)} 
                        className="mt-1 block w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 dark:text-white px-3 py-2 focus:border-primary-500 focus:ring-primary-500 outline-none" 
                    />
                </div>
            </div>
            <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Lokasi</label>
                <input 
                    type="text" 
                    value={location} 
                    onChange={e => setLocation(e.target.value)} 
                    className="mt-1 block w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 dark:text-white px-3 py-2 focus:border-primary-500 focus:ring-primary-500 outline-none" 
                />
            </div>
            <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Deskripsi</label>
                <textarea 
                    rows={3} 
                    value={description} 
                    onChange={e => setDescription(e.target.value)} 
                    className="mt-1 block w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 dark:text-white px-3 py-2 focus:border-primary-500 focus:ring-primary-500 outline-none" 
                />
            </div>

            {/* Participant Selection */}
            {!editingItem && (
               <div className="bg-gray-50 dark:bg-gray-900/50 p-4 rounded-lg border border-gray-200 dark:border-gray-700">
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Undang Peserta (Otomatis)</label>
                  <div className="flex gap-4 mb-3">
                      <label className="flex items-center gap-2 text-sm text-gray-700 dark:text-gray-300 cursor-pointer">
                          <input 
                            type="radio" 
                            checked={inviteType === 'ALL'} 
                            onChange={() => setInviteType('ALL')}
                            className="text-primary-600 focus:ring-primary-500" 
                          />
                          Semua Anggota
                      </label>
                      <label className="flex items-center gap-2 text-sm text-gray-700 dark:text-gray-300 cursor-pointer">
                          <input 
                            type="radio" 
                            checked={inviteType === 'SELECT'} 
                            onChange={() => setInviteType('SELECT')}
                            className="text-primary-600 focus:ring-primary-500" 
                          />
                          Pilih Anggota
                      </label>
                  </div>

                  {inviteType === 'SELECT' && (
                      <div className="max-h-40 overflow-y-auto border border-gray-200 dark:border-gray-700 rounded-md bg-white dark:bg-gray-800 p-2 space-y-1">
                          {members.map(m => (
                              <label key={m.id} className="flex items-center gap-2 p-1 hover:bg-gray-100 dark:hover:bg-gray-700 rounded cursor-pointer">
                                  <input 
                                    type="checkbox"
                                    checked={selectedInvitees.includes(m.id)}
                                    onChange={() => toggleInvitee(m.id)}
                                    className="rounded border-gray-300 text-primary-600 focus:ring-primary-500"
                                  />
                                  <span className="text-sm text-gray-700 dark:text-gray-300">{m.full_name}</span>
                              </label>
                          ))}
                      </div>
                  )}
                  <p className="text-xs text-gray-500 dark:text-gray-400 mt-2">
                     *Peserta yang dipilih akan otomatis masuk daftar absensi dengan status awal "Alpha/Belum Hadir".
                  </p>
               </div>
            )}

            <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Status</label>
                <select 
                    value={status} 
                    onChange={e => setStatus(e.target.value as any)} 
                    className="mt-1 block w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 dark:text-white px-3 py-2 focus:border-primary-500 focus:ring-primary-500 outline-none"
                >
                    <option value="Upcoming">Upcoming (Akan Datang)</option>
                    <option value="Completed">Completed (Selesai)</option>
                    <option value="Cancelled">Cancelled (Dibatalkan)</option>
                </select>
            </div>
            <div className="pt-4 flex justify-end gap-3">
                <button 
                    type="button" 
                    onClick={() => setIsModalOpen(false)} 
                    className="px-4 py-2 text-sm font-medium text-gray-700 dark:text-gray-300 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-md hover:bg-gray-50 dark:hover:bg-gray-600"
                >
                    Batal
                </button>
                <button 
                    type="submit" 
                    disabled={isSubmitting} 
                    className="px-4 py-2 text-sm font-medium text-white bg-primary-600 rounded-md hover:bg-primary-700 disabled:opacity-50"
                >
                    {isSubmitting ? 'Menyimpan...' : 'Simpan'}
                </button>
            </div>
        </form>
      </Modal>

      {/* --- DELETE CONFIRMATION MODAL --- */}
      <Modal 
        isOpen={deleteConfirm.isOpen} 
        onClose={() => setDeleteConfirm({isOpen: false, id: null})} 
        title="Konfirmasi Hapus"
      >
        <div className="text-center sm:text-left">
          <div className="flex flex-col items-center gap-4 mb-4">
             <div className="p-3 bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400 rounded-full">
               <AlertTriangle size={32} />
             </div>
             <div>
                <p className="text-gray-700 dark:text-gray-300">
                  Apakah Anda yakin ingin menghapus acara ini?
                </p>
                <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">
                  Semua data absensi terkait acara ini akan ikut terhapus permanen.
                </p>
             </div>
          </div>
          <div className="flex justify-center sm:justify-end gap-3 mt-6">
            <button
              onClick={() => setDeleteConfirm({isOpen: false, id: null})}
              className="px-4 py-2 text-sm font-medium text-gray-700 dark:text-gray-300 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-md hover:bg-gray-50 dark:hover:bg-gray-600"
            >
              Batal
            </button>
            <button
              onClick={handleDelete}
              className="px-4 py-2 text-sm font-medium text-white bg-red-600 rounded-md hover:bg-red-700"
            >
              Ya, Hapus
            </button>
          </div>
        </div>
      </Modal>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { supabase } from '../supabaseClient';
import { Division, Member, Program } from '../types';
import { Plus, Edit, Trash2, Layers, AlertTriangle, Users, Briefcase, X } from '../components/ui/Icons';
import { Modal } from '../components/Modal';

interface DivisionsProps {
  data: Division[];
  members: Member[];   // Receive members
  programs: Program[]; // Receive programs
  onRefresh: () => void;
}

export const Divisions: React.FC<DivisionsProps> = ({ data, members, programs, onRefresh }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<Division | null>(null);

  // Detail View State
  const [detailModalOpen, setDetailModalOpen] = useState(false);
  const [selectedDivision, setSelectedDivision] = useState<Division | null>(null);

  // Delete Confirmation State
  const [deleteConfirm, setDeleteConfirm] = useState<{isOpen: boolean, id: string | null}>({ isOpen: false, id: null });

  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [loading, setLoading] = useState(false);

  const handleOpen = (division?: Division) => {
    if (division) {
      setEditingItem(division);
      setName(division.name);
      setDescription(division.description || '');
    } else {
      setEditingItem(null);
      setName('');
      setDescription('');
    }
    setIsModalOpen(true);
  };

  const openDetail = (division: Division) => {
      setSelectedDivision(division);
      setDetailModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    const payload = { name, description };

    try {
      if (editingItem) {
        const { error } = await supabase.from('divisions').update(payload).eq('id', editingItem.id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from('divisions').insert([payload]);
        if (error) throw error;
      }
      onRefresh();
      setIsModalOpen(false);
    } catch (error: any) {
      alert('Error: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const confirmDelete = (id: string, e: React.MouseEvent) => {
    e.stopPropagation(); // Prevent card click
    setDeleteConfirm({ isOpen: true, id });
  };

  const executeDelete = async () => {
    if (!deleteConfirm.id) return;
    try {
      const { error } = await supabase.from('divisions').delete().eq('id', deleteConfirm.id);
      if (error) throw error;
      onRefresh();
      setDeleteConfirm({ isOpen: false, id: null });
    } catch (error: any) {
      alert('Error: ' + error.message);
    }
  };

  // Filtered Lists for Detail View
  const detailMembers = useMemo(() => {
      return selectedDivision ? members.filter(m => m.division_id === selectedDivision.id) : [];
  }, [selectedDivision, members]);

  const detailPrograms = useMemo(() => {
      return selectedDivision ? programs.filter(p => p.division_id === selectedDivision.id) : [];
  }, [selectedDivision, programs]);


  return (
    <div>
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
          <Layers className="text-primary-600 dark:text-primary-400" /> Manajemen Bidang
        </h2>
        <button
          onClick={() => handleOpen()}
          className="bg-primary-600 hover:bg-primary-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition"
        >
          <Plus size={18} /> Tambah Bidang
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {data.map((item) => (
          <div 
            key={item.id} 
            onClick={() => openDetail(item)}
            className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border hover:shadow-md transition cursor-pointer group relative"
          >
            <div className="flex justify-between items-start mb-4">
              <div className="p-2 bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-400 rounded-lg group-hover:scale-110 transition-transform">
                <Layers size={20} />
              </div>
              <div className="flex gap-2">
                <button 
                    onClick={(e) => { e.stopPropagation(); handleOpen(item); }} 
                    className="text-gray-400 hover:text-blue-600 dark:hover:text-blue-400 z-10"
                >
                  <Edit size={18} />
                </button>
                <button 
                    onClick={(e) => confirmDelete(item.id, e)} 
                    className="text-gray-400 hover:text-red-600 dark:hover:text-red-400 z-10"
                >
                  <Trash2 size={18} />
                </button>
              </div>
            </div>
            <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-2">{item.name}</h3>
            <p className="text-sm text-gray-500 dark:text-gray-400 line-clamp-3">
              {item.description || 'Tidak ada deskripsi.'}
            </p>
            <div className="mt-4 pt-4 border-t border-gray-100 dark:border-dark-border flex gap-4 text-xs text-gray-500 dark:text-gray-400">
                <span className="flex items-center gap-1"><Users size={12}/> {members.filter(m => m.division_id === item.id).length} Anggota</span>
                <span className="flex items-center gap-1"><Briefcase size={12}/> {programs.filter(p => p.division_id === item.id).length} Program</span>
            </div>
          </div>
        ))}
        {data.length === 0 && (
          <div className="col-span-full text-center py-10 text-gray-500 dark:text-gray-400 bg-white dark:bg-dark-card rounded-xl border border-dashed border-gray-200 dark:border-dark-border">
            Belum ada bidang yang dibuat.
          </div>
        )}
      </div>

      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={editingItem ? 'Edit Bidang' : 'Tambah Bidang'}>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Nama Bidang</label>
            <input
              type="text"
              required
              value={name}
              onChange={e => setName(e.target.value)}
              className="mt-1 block w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 dark:text-white px-3 py-2 focus:border-primary-500 focus:ring-primary-500 outline-none"
              placeholder="Contoh: Humas"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Deskripsi</label>
            <textarea
              rows={3}
              value={description}
              onChange={e => setDescription(e.target.value)}
              className="mt-1 block w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 dark:text-white px-3 py-2 focus:border-primary-500 focus:ring-primary-500 outline-none"
            />
          </div>
          <div className="pt-4 flex justify-end gap-3">
            <button
              type="button"
              onClick={() => setIsModalOpen(false)}
              className="px-4 py-2 text-sm font-medium text-gray-700 dark:text-gray-300 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-md hover:bg-gray-50 dark:hover:bg-gray-600"
            >
              Batal
            </button>
            <button
              type="submit"
              disabled={loading}
              className="px-4 py-2 text-sm font-medium text-white bg-primary-600 rounded-md hover:bg-primary-700 disabled:opacity-50"
            >
              {loading ? 'Menyimpan...' : 'Simpan'}
            </button>
          </div>
        </form>
      </Modal>

      {/* --- DETAIL MODAL --- */}
      {selectedDivision && (
          <Modal 
            isOpen={detailModalOpen} 
            onClose={() => setDetailModalOpen(false)} 
            title={`Detail Bidang: ${selectedDivision.name}`}
          >
              <div className="max-h-[60vh] overflow-y-auto pr-1">
                  <div className="mb-6">
                      <h4 className="text-sm font-bold text-gray-800 dark:text-white mb-2 flex items-center gap-2 border-b border-gray-200 dark:border-gray-700 pb-1">
                          <Users size={16} /> Anggota Bidang
                      </h4>
                      {detailMembers.length > 0 ? (
                          <ul className="space-y-2">
                              {detailMembers.map(m => (
                                  <li key={m.id} className="flex justify-between items-center text-sm bg-gray-50 dark:bg-gray-800/50 p-2 rounded">
                                      <span className="font-medium text-gray-700 dark:text-gray-300">{m.full_name}</span>
                                      <span className="text-xs text-gray-500 dark:text-gray-400">{m.roles?.name || '-'}</span>
                                  </li>
                              ))}
                          </ul>
                      ) : (
                          <p className="text-sm text-gray-400 italic">Belum ada anggota di bidang ini.</p>
                      )}
                  </div>

                  <div>
                      <h4 className="text-sm font-bold text-gray-800 dark:text-white mb-2 flex items-center gap-2 border-b border-gray-200 dark:border-gray-700 pb-1">
                          <Briefcase size={16} /> Program Kerja
                      </h4>
                      {detailPrograms.length > 0 ? (
                          <div className="space-y-3">
                              {detailPrograms.map(p => (
                                  <div key={p.id} className="bg-gray-50 dark:bg-gray-800/50 p-3 rounded text-sm border-l-2 border-primary-500">
                                      <div className="flex justify-between items-start">
                                          <span className="font-bold text-gray-800 dark:text-white">{p.name}</span>
                                          <span className={`text-[10px] px-2 py-0.5 rounded-full ${
                                              p.status === 'Completed' ? 'bg-green-100 text-green-700' :
                                              p.status === 'In Progress' ? 'bg-blue-100 text-blue-700' : 'bg-gray-200 text-gray-600'
                                          }`}>{p.status}</span>
                                      </div>
                                      <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">{p.description || 'Tidak ada deskripsi'}</p>
                                  </div>
                              ))}
                          </div>
                      ) : (
                          <p className="text-sm text-gray-400 italic">Belum ada program kerja.</p>
                      )}
                  </div>
              </div>
              <div className="mt-6 flex justify-end">
                <button
                    onClick={() => setDetailModalOpen(false)}
                    className="px-4 py-2 text-sm font-medium text-gray-700 dark:text-gray-300 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-md hover:bg-gray-50 dark:hover:bg-gray-600"
                >
                    Tutup
                </button>
              </div>
          </Modal>
      )}

      {/* --- DELETE CONFIRMATION MODAL --- */}
      <Modal 
        isOpen={deleteConfirm.isOpen} 
        onClose={() => setDeleteConfirm({isOpen: false, id: null})} 
        title="Konfirmasi Hapus"
      >
        <div className="text-center sm:text-left">
          <div className="flex flex-col items-center gap-4 mb-4">
             <div className="p-3 bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400 rounded-full">
               <AlertTriangle size={32} />
             </div>
             <div>
                <p className="text-gray-700 dark:text-gray-300">
                  Apakah Anda yakin ingin menghapus bidang ini?
                </p>
                <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">
                  Semua anggota dan program terkait mungkin akan terpengaruh.
                </p>
             </div>
          </div>
          <div className="flex justify-center sm:justify-end gap-3 mt-6">
            <button
              onClick={() => setDeleteConfirm({isOpen: false, id: null})}
              className="px-4 py-2 text-sm font-medium text-gray-700 dark:text-gray-300 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-md hover:bg-gray-50 dark:hover:bg-gray-600"
            >
              Batal
            </button>
            <button
              onClick={executeDelete}
              className="px-4 py-2 text-sm font-medium text-white bg-red-600 rounded-md hover:bg-red-700"
            >
              Ya, Hapus
            </button>
          </div>
        </div>
      </Modal>
    </div>
  );
};

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { supabase } from '../supabaseClient';
import { Program, Division, Organization, Member } from '../types';
import { 
  Plus, Edit, Trash2, Calendar, Briefcase, Wallet, Filter, AlertTriangle, 
  X, Layers, CheckSquare, Square, Building2, ChevronRight, Table, 
  FileSpreadsheet, Maximize2, Minimize2, Search, ZoomIn, ZoomOut
} from '../components/ui/Icons';
import { Modal } from '../components/Modal';

interface ProgramsProps {
  data: Program[];
  divisions: Division[];
  organizations: Organization[];
  members: Member[]; // Added members prop to list personnel
  onRefresh: () => void;
}

type ViewMode = 'table' | 'sheet';

// Helper: Parse Month (Moved outside component for stability)
const parseMonths = (monthStr: string): string[] => {
  try {
    const parsed = JSON.parse(monthStr);
    return Array.isArray(parsed) ? parsed : [monthStr];
  } catch (e) {
    return monthStr ? [monthStr] : [];
  }
};

export const Programs: React.FC<ProgramsProps> = ({ data, divisions, organizations, members, onRefresh }) => {
  const [viewMode, setViewMode] = useState<ViewMode>('table');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<Program | null>(null);

  // Full Screen State
  const containerRef = useRef<HTMLDivElement>(null);
  const [isFullScreen, setIsFullScreen] = useState(false);

  // Sheet Zoom State
  const [zoomLevel, setZoomLevel] = useState(1);

  // Description View Modal
  const [descModal, setDescModal] = useState<{isOpen: boolean, text: string, title: string}>({ isOpen: false, text: '', title: '' });

  // Filter State
  const [filterDivisionId, setFilterDivisionId] = useState('');
  const [filterOrgId, setFilterOrgId] = useState('');
  const [filterYear, setFilterYear] = useState<number | ''>('');
  const [filterMonths, setFilterMonths] = useState<string[]>([]); // Multi select

  // Delete Confirmation State
  const [deleteConfirm, setDeleteConfirm] = useState<{isOpen: boolean, id: string | null}>({ isOpen: false, id: null });

  // Form State
  const [name, setName] = useState('');
  const [description, setDescription] = useState(''); // New State
  const [costPerMonth, setCostPerMonth] = useState<number>(0);
  const [selectedMonths, setSelectedMonths] = useState<string[]>([]);
  const [divisionId, setDivisionId] = useState('');
  const [organizationId, setOrganizationId] = useState('');
  const [year, setYear] = useState<number>(new Date().getFullYear());
  const [status, setStatus] = useState<'Planned' | 'In Progress' | 'Completed'>('Planned');
  const [loading, setLoading] = useState(false);

  const allMonths = [
    'Januari', 'Februari', 'Maret', 'April', 'Mei', 'Juni', 
    'Juli', 'Agustus', 'September', 'Oktober', 'November', 'Desember'
  ];

  // Handle Full Screen Changes
  useEffect(() => {
    const handleFsChange = () => {
      setIsFullScreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      containerRef.current?.requestFullscreen().catch(err => {
        alert(`Error attempting to enable full-screen mode: ${err.message}`);
      });
    } else {
      document.exitFullscreen();
    }
  };

  const adjustZoom = (delta: number) => {
      setZoomLevel(prev => {
          const newZoom = prev + delta;
          return Math.min(Math.max(newZoom, 0.5), 1.5); // Limit between 0.5 and 1.5
      });
  };

  // Get unique years for filter
  const availableYears = useMemo(() => {
    const years = new Set(data.map(p => p.year || 2024));
    return Array.from(years).sort((a: number, b: number) => b - a);
  }, [data]);

  // --- FILTERING & STATISTICS LOGIC ---

  const filteredData = useMemo(() => {
    let result = data.filter(item => {
      const itemMonths = parseMonths(item.month);

      const matchDivision = filterDivisionId ? item.division_id === filterDivisionId : true;
      const matchOrg = filterOrgId ? item.organization_id === filterOrgId : true;
      const matchYear = filterYear ? (item.year || 2024) === Number(filterYear) : true;

      // Filter Month logic
      const matchMonth = filterMonths.length > 0 
        ? itemMonths.some(m => filterMonths.includes(m))
        : true;

      return matchDivision && matchOrg && matchYear && matchMonth;
    });

    // Sort result by Division Name, then by Program Name for Sheet View consistency
    result.sort((a, b) => {
        const divA = divisions.find(d => d.id === a.division_id)?.name || '';
        const divB = divisions.find(d => d.id === b.division_id)?.name || '';
        if (divA < divB) return -1;
        if (divA > divB) return 1;
        return a.name.localeCompare(b.name);
    });

    return result;
  }, [data, filterDivisionId, filterOrgId, filterYear, filterMonths, divisions]);

  const stats = useMemo(() => {
    const isMonthlyFilter = filterMonths.length > 0;

    const calculatedCost = filteredData.reduce((acc, curr) => {
        if (!isMonthlyFilter) {
            // Jika tidak ada filter bulan, gunakan Total Biaya (Anggaran Tahunan/Keseluruhan)
            return acc + curr.cost;
        } else {
            // Jika ada filter bulan, hitung estimasi biaya HANYA untuk bulan yang dipilih
            const m = parseMonths(curr.month);
            const duration = m.length > 0 ? m.length : 1;
            const monthlyEstimate = curr.cost / duration;

            // Hitung berapa bulan yang beririsan dengan filter
            const matchCount = m.filter(month => filterMonths.includes(month)).length;

            return acc + (monthlyEstimate * matchCount);
        }
    }, 0);

    const totalPrograms = filteredData.length;
    const uniqueDivisionIds = new Set(filteredData.map(p => p.division_id));
    const divisionNames = Array.from(uniqueDivisionIds)
      .map(id => divisions.find(d => d.id === id)?.name)
      .filter(Boolean)
      .join(', ');

    return { totalCost: calculatedCost, totalPrograms, divisionNames, isMonthlyFilter };
  }, [filteredData, divisions, filterMonths]);

  // --- HANDLERS ---

  const handleOpen = (program?: Program) => {
    if (program) {
      setEditingItem(program);
      setName(program.name);
      setDescription(program.description || '');

      const months = parseMonths(program.month);
      setSelectedMonths(months);

      const count = months.length || 1;
      setCostPerMonth(program.cost / count);

      setDivisionId(program.division_id);
      setOrganizationId(program.organization_id || '');
      setYear(program.year || new Date().getFullYear());
      setStatus(program.status);
    } else {
      setEditingItem(null);
      setName('');
      setDescription('');
      setCostPerMonth(0);
      setSelectedMonths([allMonths[new Date().getMonth()]]);
      setDivisionId(divisions[0]?.id || '');
      setOrganizationId(organizations[0]?.id || '');
      setYear(new Date().getFullYear());
      setStatus('Planned');
    }
    setIsModalOpen(true);
  };

  const toggleMonthSelection = (month: string, isFilter: boolean = false) => {
    const setState = isFilter ? setFilterMonths : setSelectedMonths;
    const currentState = isFilter ? filterMonths : selectedMonths;

    if (currentState.includes(month)) {
        setState(currentState.filter(m => m !== month));
    } else {
        const newSelection = [...currentState, month];
        // Sort chronologically
        setState(newSelection.sort((a, b) => allMonths.indexOf(a) - allMonths.indexOf(b)));
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    if (selectedMonths.length === 0) {
      alert("Pilih setidaknya satu bulan.");
      setLoading(false);
      return;
    }

    const totalCost = costPerMonth * selectedMonths.length;
    const monthString = JSON.stringify(selectedMonths);

    const payload = {
      name,
      description,
      cost: totalCost,
      month: monthString,
      division_id: divisionId,
      organization_id: organizationId || null,
      year: year,
      status
    };

    try {
      if (editingItem) {
        const { error } = await supabase.from('programs').update(payload).eq('id', editingItem.id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from('programs').insert([payload]);
        if (error) throw error;
      }
      onRefresh();
      setIsModalOpen(false);
    } catch (error: any) {
      alert('Error: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const confirmDelete = (id: string) => {
    setDeleteConfirm({ isOpen: true, id });
  };

  const executeDelete = async () => {
    if (!deleteConfirm.id) return;
    try {
      const { error } = await supabase.from('programs').delete().eq('id', deleteConfirm.id);
      if (error) throw error;
      onRefresh();
      setDeleteConfirm({ isOpen: false, id: null });
    } catch (error: any) {
      alert('Error: ' + error.message);
    }
  };

  const formatCurrency = (val: number) => new Intl.NumberFormat('id-ID', { style: 'currency', currency: 'IDR', maximumFractionDigits: 0 }).format(val);

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'Completed': return 'bg-green-100 dark:bg-green-900/40 text-green-800 dark:text-green-300';
      case 'In Progress': return 'bg-blue-100 dark:bg-blue-900/40 text-blue-800 dark:text-blue-300';
      default: return 'bg-gray-100 dark:bg-gray-700 text-gray-800 dark:text-gray-300';
    }
  };

  const resetFilters = () => {
    setFilterDivisionId('');
    setFilterOrgId('');
    setFilterYear('');
    setFilterMonths([]);
  };

  // --- SHEET VIEW RENDER ---
  const renderSheetView = () => {
    // Group Data by Division
    const groupedData = new Map<string, Program[]>();
    filteredData.forEach(item => {
        const existing = groupedData.get(item.division_id) || [];
        existing.push(item);
        groupedData.set(item.division_id, existing);
    });

    return (
        <div className="bg-white dark:bg-dark-card rounded-xl shadow-sm border border-gray-100 dark:border-dark-border overflow-hidden flex-1 flex flex-col relative">
            {/* Zoom Controls Overlay */}
            <div className="absolute top-2 right-2 z-20 flex bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-600 rounded-lg shadow-sm">
                <button onClick={() => adjustZoom(-0.1)} className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 text-gray-600 dark:text-gray-300 rounded-l-lg" title="Zoom Out">
                    <ZoomOut size={16} />
                </button>
                <div className="px-2 py-2 text-xs font-mono border-x border-gray-200 dark:border-gray-600 text-gray-600 dark:text-gray-300 min-w-[50px] text-center">
                    {Math.round(zoomLevel * 100)}%
                </div>
                <button onClick={() => adjustZoom(0.1)} className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 text-gray-600 dark:text-gray-300 rounded-r-lg" title="Zoom In">
                    <ZoomIn size={16} />
                </button>
            </div>

            <div className="overflow-auto flex-1 p-2">
                <div style={{ 
                    transform: `scale(${zoomLevel})`, 
                    transformOrigin: 'top left',
                    width: `${zoomLevel < 1 ? 100 / zoomLevel : 100}%` 
                }}>
                    <table className="w-full text-left border-collapse border border-gray-300 dark:border-gray-700 min-w-[1200px]">
                        <thead className="bg-emerald-600 text-white text-xs uppercase font-bold text-center sticky top-0 z-10">
                            <tr>
                                <th className="border border-emerald-700 px-2 py-3 w-10 bg-emerald-600">No</th>
                                <th className="border border-emerald-700 px-2 py-3 w-32 bg-emerald-600">Bidang</th>
                                <th className="border border-emerald-700 px-2 py-3 w-40 bg-emerald-600">Personil</th>
                                <th className="border border-emerald-700 px-2 py-3 w-10 bg-emerald-600">No</th>
                                <th className="border border-emerald-700 px-2 py-3 min-w-[200px] bg-emerald-600">Kegiatan</th>
                                <th className="border border-emerald-700 px-2 py-3 min-w-[150px] bg-emerald-600">Keterangan</th>
                                <th className="border border-emerald-700 px-2 py-3 w-28 bg-emerald-600">Biaya</th>
                                {/* Months 1-12 */}
                                {Array.from({length: 12}, (_, i) => i + 1).map(m => (
                                    <th key={m} className="border border-emerald-700 px-1 py-3 w-8 bg-emerald-600">{m}</th>
                                ))}
                                <th className="border border-emerald-700 px-2 py-3 w-16 bg-emerald-600">Jml</th>
                                <th className="border border-emerald-700 px-2 py-3 w-32 bg-emerald-600">Total Biaya</th>
                                <th className="border border-emerald-700 px-2 py-3 w-20 bg-emerald-600">Aksi</th>
                            </tr>
                        </thead>
                        <tbody className="text-xs text-gray-800 dark:text-gray-200">
                            {Array.from(groupedData.entries()).map(([divId, groupItems], groupIndex) => {
                                const divName = divisions.find(d => d.id === divId)?.name || 'Unknown';
                                // Get Members for this division
                                const divMembers = members
                                    .filter(m => m.division_id === divId)
                                    .map(m => m.full_name)
                                    .join(', ');

                                return groupItems.map((item, index) => {
                                    const itemMonths = parseMonths(item.month);
                                    const count = itemMonths.length;
                                    const unitCost = count > 0 ? item.cost / count : 0;
                                    const isFirst = index === 0;

                                    return (
                                        <tr key={item.id} className="hover:bg-gray-50 dark:hover:bg-gray-800">
                                            {/* Group Columns (Rowspan) */}
                                            {isFirst && (
                                                <>
                                                    <td rowSpan={groupItems.length} className="border border-gray-300 dark:border-gray-700 px-2 py-2 text-center align-top font-bold bg-gray-50 dark:bg-gray-800">
                                                        {groupIndex + 1}
                                                    </td>
                                                    <td rowSpan={groupItems.length} className="border border-gray-300 dark:border-gray-700 px-2 py-2 align-top font-bold bg-gray-50 dark:bg-gray-800 rotate-180 [writing-mode:vertical-rl] text-center uppercase tracking-widest h-full min-h-[100px]">
                                                        {divName}
                                                    </td>
                                                    <td rowSpan={groupItems.length} className="border border-gray-300 dark:border-gray-700 px-2 py-2 align-top bg-gray-50 dark:bg-gray-800 whitespace-normal break-words">
                                                        {divMembers || '-'}
                                                    </td>
                                                </>
                                            )}

                                            {/* Program Columns */}
                                            <td className="border border-gray-300 dark:border-gray-700 px-2 py-2 text-center">{index + 1}</td>
                                            <td className="border border-gray-300 dark:border-gray-700 px-2 py-2 font-medium whitespace-normal break-words min-w-[200px]">{item.name}</td>
                                            <td className="border border-gray-300 dark:border-gray-700 px-2 py-2 whitespace-normal break-words min-w-[150px]">{item.description}</td>
                                            <td className="border border-gray-300 dark:border-gray-700 px-2 py-2 text-right whitespace-nowrap">
                                                {new Intl.NumberFormat('id-ID').format(unitCost)}
                                            </td>

                                            {/* Months Matrix */}
                                            {allMonths.map(m => (
                                                <td key={m} className="border border-gray-300 dark:border-gray-700 px-1 py-1 text-center bg-gray-50/50 dark:bg-gray-900/30">
                                                    {itemMonths.includes(m) ? 'X' : ''}
                                                </td>
                                            ))}

                                            <td className="border border-gray-300 dark:border-gray-700 px-2 py-2 text-center font-bold">{count}</td>
                                            <td className="border border-gray-300 dark:border-gray-700 px-2 py-2 text-right font-bold whitespace-nowrap">
                                                {new Intl.NumberFormat('id-ID').format(item.cost)}
                                            </td>
                                            <td className="border border-gray-300 dark:border-gray-700 px-1 py-2 text-center">
                                                <div className="flex justify-center gap-1">
                                                    <button onClick={() => handleOpen(item)} title="Edit"><Edit size={14} className="text-blue-500" /></button>
                                                    <button onClick={() => confirmDelete(item.id)} title="Hapus"><Trash2 size={14} className="text-red-500" /></button>
                                                </div>
                                            </td>
                                        </tr>
                                    );
                                });
                            })}
                            {filteredData.length === 0 && (
                                <tr>
                                    <td colSpan={19} className="p-8 text-center text-gray-500 dark:text-gray-400 border border-gray-300 dark:border-gray-700">
                                        Tidak ada data untuk ditampilkan.
                                    </td>
                                </tr>
                            )}
                            {/* Grand Total Row */}
                            {filteredData.length > 0 && (
                                <tr className="bg-emerald-50 dark:bg-emerald-900/20 font-bold sticky bottom-0 z-10">
                                    <td colSpan={17} className="border border-gray-300 dark:border-gray-700 px-4 py-3 text-right text-emerald-800 dark:text-emerald-300 uppercase bg-emerald-50 dark:bg-emerald-900/20">
                                        Total Anggaran
                                    </td>
                                    <td colSpan={2} className="border border-gray-300 dark:border-gray-700 px-4 py-3 text-right text-emerald-800 dark:text-emerald-300 text-sm bg-emerald-50 dark:bg-emerald-900/20">
                                        {formatCurrency(filteredData.reduce((sum, item) => sum + item.cost, 0))}
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
  }

  // --- STANDARD TABLE VIEW RENDER ---
  const renderTableView = () => (
    <div className="bg-white dark:bg-dark-card rounded-xl shadow-sm border border-gray-100 dark:border-dark-border overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-gray-50 dark:bg-gray-800 text-gray-600 dark:text-gray-400 text-xs uppercase font-semibold">
              <tr>
                <th className="px-6 py-4 w-1/5">Nama Program</th>
                <th className="px-6 py-4 w-1/5">Deskripsi</th>
                <th className="px-6 py-4">Organisasi</th>
                <th className="px-6 py-4">Jadwal & Tahun</th>
                <th className="px-6 py-4">Biaya</th>
                <th className="px-6 py-4">Bidang</th>
                <th className="px-6 py-4">Status</th>
