import React, { useState } from 'react';
import { supabase } from '../supabaseClient';
import { Role, ViewState } from '../types';
import { Plus, Edit, Trash2, ShieldCheck, AlertTriangle, CheckSquare, Square, Lock, Unlock } from '../components/ui/Icons';
import { Modal } from '../components/Modal';

interface RolesProps {
  data: Role[];
  onRefresh: () => void;
}

const ALL_PERMISSIONS: {id: ViewState, label: string}[] = [
    { id: 'DASHBOARD', label: 'Dashboard' },
    { id: 'EVENTS', label: 'Acara & Absensi' },
    { id: 'FINANCE', label: 'Keuangan' },
    { id: 'EDUCATORS', label: 'Tenaga Pendidik' },
    { id: 'ORGANIZATIONS', label: 'Organisasi' },
    { id: 'MEMBERS', label: 'Anggota' },
    { id: 'ROLES', label: 'Role & Akses' },
    { id: 'DIVISIONS', label: 'Bidang / Divisi' },
    { id: 'PROGRAMS', label: 'Program Kerja' },
];

export const Roles: React.FC<RolesProps> = ({ data, onRefresh }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<Role | null>(null);

  // Delete Confirmation State
  const [deleteConfirm, setDeleteConfirm] = useState<{isOpen: boolean, id: string | null}>({ isOpen: false, id: null });

  const [name, setName] = useState('');
  const [selectedPermissions, setSelectedPermissions] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);

  const handleOpen = (role?: Role) => {
    if (role) {
      setEditingItem(role);
      setName(role.name);

      // LOGIC: Jika Super Admin, otomatis pilih SEMUA permission untuk memastikan akses penuh
      if (role.name === 'Super Administration' || role.name === 'Super Admin') {
         setSelectedPermissions(ALL_PERMISSIONS.map(p => p.id));
      } else {
         setSelectedPermissions(role.permissions || []); 
      }
    } else {
      setEditingItem(null);
      setName('');
      setSelectedPermissions([]);
    }
    setIsModalOpen(true);
  };

  const togglePermission = (permId: string) => {
      // Prevent unchecking permissions for Super Admin
      if (editingItem?.name === 'Super Administration' || editingItem?.name === 'Super Admin') {
          return; 
      }

      setSelectedPermissions(prev => 
        prev.includes(permId) 
            ? prev.filter(p => p !== permId) 
            : [...prev, permId]
      );
  };

  const toggleAllPermissions = () => {
      // Prevent modifying Super Admin
      if (editingItem?.name === 'Super Administration' || editingItem?.name === 'Super Admin') return;

      if (selectedPermissions.length === ALL_PERMISSIONS.length) {
          setSelectedPermissions([]);
      } else {
          setSelectedPermissions(ALL_PERMISSIONS.map(p => p.id));
      }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    const payload = { 
        name,
        permissions: selectedPermissions 
    };

    try {
      if (editingItem) {
        const { error } = await supabase.from('roles').update(payload).eq('id', editingItem.id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from('roles').insert([payload]);
        if (error) throw error;
      }
      onRefresh();
      setIsModalOpen(false);
    } catch (error: any) {
      alert('Error: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const confirmDelete = (id: string) => {
    setDeleteConfirm({ isOpen: true, id });
  };

  const executeDelete = async () => {
    if (!deleteConfirm.id) return;
    try {
      const { error } = await supabase.from('roles').delete().eq('id', deleteConfirm.id);
      if (error) throw error;
      onRefresh();
      setDeleteConfirm({ isOpen: false, id: null });
    } catch (error: any) {
      alert('Error: ' + error.message);
    }
  };

  return (
    <div>
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
          <ShieldCheck className="text-primary-600 dark:text-primary-400" /> Manajemen Role & Hak Akses
        </h2>
        <button
          onClick={() => handleOpen()}
          className="bg-primary-600 hover:bg-primary-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition"
        >
          <Plus size={18} /> Tambah Role
        </button>
      </div>

      <div className="bg-white dark:bg-dark-card rounded-xl shadow-sm border border-gray-100 dark:border-dark-border overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-gray-50 dark:bg-gray-800 text-gray-600 dark:text-gray-400 text-xs uppercase font-semibold">
            <tr>
              <th className="px-6 py-4">Nama Role</th>
              <th className="px-6 py-4">Hak Akses Menu</th>
              <th className="px-6 py-4 text-right">Aksi</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100 dark:divide-dark-border">
            {data.map((item) => (
              <tr key={item.id} className="hover:bg-gray-50 dark:hover:bg-gray-800/50 transition">
                <td className="px-6 py-4 font-medium text-gray-900 dark:text-white align-top">
                    {item.name}
                    {item.name === 'Super Administration' && <span className="ml-2 text-xs bg-red-100 text-red-600 px-1.5 py-0.5 rounded">System</span>}
                </td>
                <td className="px-6 py-4 align-top">
                    <div className="flex flex-wrap gap-1">
                        {item.permissions && item.permissions.length > 0 ? (
                            item.permissions.map(p => {
                                const label = ALL_PERMISSIONS.find(ap => ap.id === p)?.label || p;
                                return (
                                    <span key={p} className="text-[10px] bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-300 px-2 py-1 rounded-full border border-gray-200 dark:border-gray-600">
                                        {label}
                                    </span>
                                )
                            })
                        ) : (
                            <span className="text-xs text-gray-400 italic">Tidak ada akses</span>
                        )}
                    </div>
                </td>
                <td className="px-6 py-4 text-right align-top">
                  <div className="flex justify-end gap-2">
                    <button onClick={() => handleOpen(item)} className="text-gray-400 hover:text-blue-600 dark:hover:text-blue-400">
                      <Edit size={18} />
                    </button>
                    {/* Protect Super Admin role */}
                    {item.name !== 'Super Administration' && (
                        <button onClick={() => confirmDelete(item.id)} className="text-gray-400 hover:text-red-600 dark:hover:text-red-400">
                        <Trash2 size={18} />
                        </button>
                    )}
                  </div>
                </td>
              </tr>
            ))}
            {data.length === 0 && (
              <tr>
                <td colSpan={3} className="px-6 py-8 text-center text-gray-500 dark:text-gray-400">
                  Belum ada data role.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={editingItem ? 'Edit Role & Akses' : 'Tambah Role Baru'}>
        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Nama Role</label>
            <input
              type="text"
              required
              readOnly={editingItem?.name === 'Super Administration'}
              value={name}
              onChange={e => setName(e.target.value)}
              className={`mt-1 block w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 dark:text-white px-3 py-2 focus:border-primary-500 focus:ring-primary-500 outline-none ${editingItem?.name === 'Super Administration' ? 'opacity-70 cursor-not-allowed' : ''}`}
              placeholder="Contoh: Guru, Kepala Sekolah"
            />
          </div>

          <div className="bg-gray-50 dark:bg-gray-900/50 p-4 rounded-lg border border-gray-200 dark:border-gray-700">
              <div className="flex justify-between items-center mb-3">
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 flex items-center gap-2">
                      <Lock size={16} className="text-primary-500" /> Hak Akses Menu
                  </label>
                  {(editingItem?.name !== 'Super Administration' && editingItem?.name !== 'Super Admin') && (
                    <button 
                        type="button"
                        onClick={toggleAllPermissions}
                        className="text-xs text-primary-600 hover:text-primary-700 dark:text-primary-400 font-medium"
                    >
                        {selectedPermissions.length === ALL_PERMISSIONS.length ? 'Hapus Semua' : 'Pilih Semua'}
                    </button>
                  )}
              </div>

              <div className="grid grid-cols-2 gap-2">
                  {ALL_PERMISSIONS.map((perm) => {
                      const isChecked = selectedPermissions.includes(perm.id);
                      const isLocked = editingItem?.name === 'Super Administration' || editingItem?.name === 'Super Admin';
                      return (
                          <div 
                            key={perm.id}
                            onClick={() => togglePermission(perm.id)}
                            className={`flex items-center gap-2 p-2 rounded transition border ${
                                isChecked 
                                ? 'bg-primary-50 border-primary-200 dark:bg-primary-900/30 dark:border-primary-800' 
                                : 'bg-white border-gray-200 dark:bg-gray-800 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700'
                            } ${isLocked ? 'cursor-default opacity-80' : 'cursor-pointer'}`}
                          >
                              <div className={`text-primary-600 dark:text-primary-400`}>
                                  {isChecked ? <CheckSquare size={18} /> : <Square size={18} className="text-gray-400" />}
                              </div>
                              <span className={`text-sm ${isChecked ? 'text-primary-700 dark:text-primary-300 font-medium' : 'text-gray-600 dark:text-gray-400'}`}>
                                  {perm.label}
                              </span>
                          </div>
                      )
                  })}
              </div>
              {(editingItem?.name === 'Super Administration' || editingItem?.name === 'Super Admin') && (
                  <p className="text-[10px] text-gray-500 mt-2 italic">* Akses Super Admin dikunci pada "Semua Akses".</p>
              )}
          </div>

          <div className="pt-2 flex justify-end gap-3">
            <button
              type="button"
              onClick={() => setIsModalOpen(false)}
              className="px-4 py-2 text-sm font-medium text-gray-700 dark:text-gray-300 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-md hover:bg-gray-50 dark:hover:bg-gray-600"
            >
              Batal
            </button>
            <button
              type="submit"
              disabled={loading}
              className="px-4 py-2 text-sm font-medium text-white bg-primary-600 rounded-md hover:bg-primary-700 disabled:opacity-50"
            >
              {loading ? 'Menyimpan...' : 'Simpan'}
            </button>
          </div>
        </form>
      </Modal>

      {/* --- DELETE CONFIRMATION MODAL --- */}
      <Modal 
        isOpen={deleteConfirm.isOpen} 
        onClose={() => setDeleteConfirm({isOpen: false, id: null})} 
        title="Konfirmasi Hapus"
      >
        <div className="text-center sm:text-left">
          <div className="flex flex-col items-center gap-4 mb-4">
             <div className="p-3 bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400 rounded-full">
               <AlertTriangle size={32} />
             </div>
             <div>
                <p className="text-gray-700 dark:text-gray-300">
                  Apakah Anda yakin ingin menghapus role ini?
                </p>
                <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">
                  Anggota yang memiliki role ini akan kehilangan role mereka di sistem.
                </p>
             </div>
          </div>
          <div className="flex justify-center sm:justify-end gap-3 mt-6">
            <button
              onClick={() => setDeleteConfirm({isOpen: false, id: null})}
              className="px-4 py-2 text-sm font-medium text-gray-700 dark:text-gray-300 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-md hover:bg-gray-50 dark:hover:bg-gray-600"
            >
              Batal
            </button>
            <button
              onClick={executeDelete}
              className="px-4 py-2 text-sm font-medium text-white bg-red-600 rounded-md hover:bg-red-700"
            >
              Ya, Hapus
            </button>
          </div>
        </div>
      </Modal>
    </div>
  );
};

-- JALANKAN SCRIPT INI DI SQL EDITOR SUPABASE UNTUK UPDATE DATABASE

-- 1. Buat Tabel Organizations (Organisasi Naungan)
create table if not exists public.organizations (
  id uuid default gen_random_uuid() primary key,
  name text not null,
  description text
);

-- 2. Aktifkan RLS untuk Organizations
alter table public.organizations enable row level security;
drop policy if exists "Enable all access for organizations" on public.organizations;
create policy "Enable all access for organizations" on public.organizations for all using (true) with check (true);

-- 3. Update Tabel Members (Tambah kolom organization_id)
do $$
begin
  if not exists (select 1 from information_schema.columns where table_name = 'members' and column_name = 'organization_id') then
    alter table public.members add column organization_id uuid references public.organizations(id) on delete set null;
  end if;
end $$;

-- 4. Update Tabel Programs (Tambah kolom year, organization_id, dan description)
do $$
begin
  if not exists (select 1 from information_schema.columns where table_name = 'programs' and column_name = 'year') then
    alter table public.programs add column year integer default 2024;
  end if;

  if not exists (select 1 from information_schema.columns where table_name = 'programs' and column_name = 'organization_id') then
    alter table public.programs add column organization_id uuid references public.organizations(id) on delete set null;
  end if;

  if not exists (select 1 from information_schema.columns where table_name = 'programs' and column_name = 'description') then
    alter table public.programs add column description text;
  end if;
end $$;

-- ==========================================
-- 5. TABEL ACARA (EVENTS)
-- ==========================================
create table if not exists public.events (
  id uuid default gen_random_uuid() primary key,
  name text not null,
  date timestamp with time zone not null,
  location text,
  description text,
  status text check (status in ('Upcoming', 'Completed', 'Cancelled')) default 'Upcoming'
);

alter table public.events enable row level security;
drop policy if exists "Enable all access for events" on public.events;
create policy "Enable all access for events" on public.events for all using (true) with check (true);

-- ==========================================
-- 6. TABEL ABSENSI (EVENT ATTENDANCE)
-- ==========================================
create table if not exists public.event_attendance (
  id uuid default gen_random_uuid() primary key,
  event_id uuid references public.events(id) on delete cascade,
  member_id uuid references public.members(id) on delete cascade,
  status text check (status in ('Present', 'Excused', 'Absent')),
  notes text,
  unique(event_id, member_id) -- Mencegah duplikasi absen per user per event
);

alter table public.event_attendance enable row level security;
drop policy if exists "Enable all access for event_attendance" on public.event_attendance;
create policy "Enable all access for event_attendance" on public.event_attendance for all using (true) with check (true);

-- ==========================================
-- 7. UPDATE ROLES & PERMISSIONS
-- ==========================================
-- Tambah kolom permissions di tabel roles (jika belum ada)
do $$
begin
    if not exists (select 1 from information_schema.columns where table_name = 'roles' and column_name = 'permissions') then
        alter table public.roles add column permissions text[]; 
    end if;
end $$;

-- Pastikan Role Super Administration ada dan punya full akses
INSERT INTO roles (name, permissions)
SELECT 'Super Administration', ARRAY['DASHBOARD', 'MEMBERS', 'DIVISIONS', 'ORGANIZATIONS', 'PROGRAMS', 'ROLES', 'EVENTS', 'FINANCE', 'EDUCATORS']
WHERE NOT EXISTS (SELECT 1 FROM roles WHERE name = 'Super Administration');

-- Force Update Permission Super Admin (jika sudah ada sebelumnya tapi belum lengkap)
UPDATE roles 
SET permissions = ARRAY['DASHBOARD', 'MEMBERS', 'DIVISIONS', 'ORGANIZATIONS', 'PROGRAMS', 'ROLES', 'EVENTS', 'FINANCE', 'EDUCATORS']
WHERE name = 'Super Administration' OR name = 'Super Admin';

-- Tambah Role Guru (Optional)
INSERT INTO roles (name, permissions)
SELECT 'Guru', ARRAY['DASHBOARD', 'EVENTS', 'EDUCATORS']
WHERE NOT EXISTS (SELECT 1 FROM roles WHERE name = 'Guru');

import React, { useEffect, useState, useMemo } from 'react';
import { supabase } from './supabaseClient';
import { ViewState, Member, Role, Division, Program, Organization, Event, EventAttendance } from './types';
import { Auth } from './components/Auth';
import { Dashboard } from './pages/Dashboard';
import { Members } from './pages/Members';
import { Divisions } from './pages/Divisions';
import { Organizations } from './pages/Organizations';
import { Programs } from './pages/Programs';
import { Events } from './pages/Events';
import { Finance } from './pages/Finance'; 
import { Educators } from './pages/Educators'; // Import Educators
import { Roles } from './pages/Roles';
import { Help } from './components/Help';
import { 
  LayoutDashboard, 
  Users, 
  Layers, 
  Briefcase, 
  LogOut, 
  Sun, 
  Moon, 
  Building2, 
  ShieldCheck,
  ChevronLeft,
  ChevronRight,
  CalendarDays,
  FileText,
  Maximize2,
  Minimize2,
  GraduationCap,
  Lock
} from './components/ui/Icons';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [view, setView] = useState<ViewState>('DASHBOARD');
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  const [isFullScreen, setIsFullScreen] = useState(false);

  // Theme State
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('theme') as 'light' | 'dark' || 'light';
    }
    return 'light';
  });

  // Data State
  const [members, setMembers] = useState<Member[]>([]);
  const [roles, setRoles] = useState<Role[]>([]);
  const [divisions, setDivisions] = useState<Division[]>([]);
  const [organizations, setOrganizations] = useState<Organization[]>([]);
  const [programs, setPrograms] = useState<Program[]>([]);
  const [events, setEvents] = useState<Event[]>([]);
  const [attendance, setAttendance] = useState<EventAttendance[]>([]);

  // Permission State
  const [userPermissions, setUserPermissions] = useState<string[]>([]);

  const [loadingData, setLoadingData] = useState(false);
  const [dbError, setDbError] = useState(false);

  // Theme Effect
  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  // Full Screen Effect
  useEffect(() => {
    const handleFsChange = () => {
      setIsFullScreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch((err) => {
        console.error(`Error attempting to enable full-screen mode: ${err.message}`);
      });
    } else {
      document.exitFullscreen();
    }
  };

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
    });

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    return () => subscription.unsubscribe();
  }, []);

  // --- FETCH DATA & DETERMINE PERMISSIONS ---
  const fetchData = async () => {
    if (!session) return;
    setDbError(false);

    try {
      const [membersRes, rolesRes, divisionsRes, programsRes, orgsRes, eventsRes, attendRes] = await Promise.all([
        supabase.from('members').select('*, divisions(name), roles(name, permissions)'), 
        supabase.from('roles').select('*'),
        supabase.from('divisions').select('*'),
        supabase.from('programs').select('*'),
        supabase.from('organizations').select('*'),
        supabase.from('events').select('*'),
        supabase.from('event_attendance').select('*')
      ]);

      if (membersRes.error || rolesRes.error || divisionsRes.error || programsRes.error || orgsRes.error) {
        throw new Error('Database Error');
      }

      setMembers(membersRes.data || []);
      setRoles(rolesRes.data || []);
      setDivisions(divisionsRes.data || []);
      setPrograms(programsRes.data || []);
      setOrganizations(orgsRes.data || []);
      setEvents(eventsRes.data || []);
      setAttendance(attendRes.data || []);

      // --- DETERMINE PERMISSIONS ---
      // Find the current logged-in user in the members list
      const currentUserEmail = session.user.email;
      const currentUser = membersRes.data?.find((m: any) => m.email === currentUserEmail);

      if (currentUser && currentUser.roles && currentUser.roles.permissions) {
          setUserPermissions(currentUser.roles.permissions);
      } else if (currentUserEmail === 'super@yayasan.org') {
          // Fallback for hardcoded super admin
          setUserPermissions(['DASHBOARD', 'MEMBERS', 'DIVISIONS', 'ORGANIZATIONS', 'PROGRAMS', 'ROLES', 'EVENTS', 'FINANCE', 'EDUCATORS']);
      } else {
          // Default: No permissions or maybe just Dashboard
          setUserPermissions(['DASHBOARD']); 
      }

    } catch (error) {
      console.error('Error fetching data:', error);
      setDbError(true); 
    } finally {
      setLoadingData(false);
    }
  };

  useEffect(() => {
    if (session) {
      setLoadingData(true); 
      fetchData();
    }
  }, [session]);

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  if (!session) {
    return <Auth onLogin={() => {}} />;
  }

  // Permission Checker
  const canAccess = (viewId: ViewState) => {
      if (userPermissions.length === 0) return false;
      return userPermissions.includes(viewId);
  }

  const NavItem = ({ id, label, icon: Icon }: { id: ViewState; label: string; icon: any }) => {
    if (!canAccess(id)) return null;

    return (
        <button
        onClick={() => setView(id)}
        title={isSidebarCollapsed ? label : ''}
        className={`w-full flex items-center ${isSidebarCollapsed ? 'justify-center px-2' : 'space-x-3 px-4'} py-3 rounded-lg transition text-sm font-medium ${
            view === id 
            ? 'bg-primary-50 dark:bg-primary-900/30 text-primary-700 dark:text-primary-400' 
            : 'text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 hover:text-gray-900 dark:hover:text-gray-200'
        }`}
        >
        <Icon size={20} className="shrink-0" />
        {!isSidebarCollapsed && <span>{label}</span>}
        </button>
    );
  };

  return (
    <div className="flex min-h-screen bg-gray-50 dark:bg-dark-bg transition-colors duration-200">
      {/* Sidebar (Desktop) */}
      <aside 
        className={`${isSidebarCollapsed ? 'w-20' : 'w-64'} bg-white dark:bg-dark-card border-r border-gray-200 dark:border-dark-border fixed inset-y-0 left-0 z-20 hidden md:flex flex-col transition-all duration-300 ease-in-out`}
      >
        <div className={`p-6 border-b border-gray-100 dark:border-dark-border flex items-center ${isSidebarCollapsed ? 'justify-center' : 'justify-between'}`}>
          {!isSidebarCollapsed && (
            <div className="flex items-center space-x-2 text-primary-600 dark:text-primary-400 animate-in fade-in duration-300">
              <div className="bg-primary-600 dark:bg-primary-500 p-1.5 rounded-lg text-white">
                <Layers size={20} />
              </div>
              <span className="text-xl font-bold tracking-tight text-gray-900 dark:text-white">E-Yayasan</span>
            </div>
          )}
          {isSidebarCollapsed && (
             <div className="bg-primary-600 dark:bg-primary-500 p-1.5 rounded-lg text-white">
                <Layers size={20} />
             </div>
          )}
        </div>

        {/* Toggle Button */}
        <button 
            onClick={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
            className="absolute -right-3 top-20 bg-white dark:bg-gray-700 border border-gray-200 dark:border-gray-600 rounded-full p-1 shadow-sm hover:bg-gray-50 dark:hover:bg-gray-600 text-gray-500 dark:text-gray-300"
        >
            {isSidebarCollapsed ? <ChevronRight size={14} /> : <ChevronLeft size={14} />}
        </button>

        <nav className="flex-1 p-3 space-y-2 overflow-y-auto overflow-x-hidden mt-4">
          {!isSidebarCollapsed && (
            <div className="text-xs font-semibold text-gray-400 dark:text-gray-500 uppercase tracking-wider mb-2 px-4 transition-opacity duration-300">
              Menu Utama
            </div>
          )}
          <NavItem id="DASHBOARD" label="Dashboard" icon={LayoutDashboard} />
          <NavItem id="EVENTS" label="Acara & Absensi" icon={CalendarDays} />
          <NavItem id="EDUCATORS" label="Tenaga Pendidik" icon={GraduationCap} />
          <NavItem id="FINANCE" label="Pengajuan Keuangan" icon={FileText} />
          <NavItem id="ORGANIZATIONS" label="Organisasi" icon={Building2} />
          <NavItem id="MEMBERS" label="Anggota" icon={Users} />
          <NavItem id="ROLES" label="Role & Akses" icon={ShieldCheck} />
          <NavItem id="DIVISIONS" label="Bidang" icon={Layers} />
          <NavItem id="PROGRAMS" label="Program Kerja" icon={Briefcase} />
        </nav>

        <div className="p-4 border-t border-gray-100 dark:border-dark-border space-y-2">
          <button
            onClick={toggleFullScreen}
            title={isSidebarCollapsed ? (isFullScreen ? 'Keluar Full Screen' : 'Full Screen') : ''}
            className={`w-full flex items-center ${isSidebarCollapsed ? 'justify-center px-2' : 'space-x-3 px-4'} py-2 text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded-lg transition text-sm font-medium`}
          >
            {isFullScreen ? <Minimize2 size={20} /> : <Maximize2 size={20} />}
            {!isSidebarCollapsed && <span>{isFullScreen ? 'Exit Full Screen' : 'Full Screen'}</span>}
          </button>

          <button
            onClick={toggleTheme}
            title={isSidebarCollapsed ? (theme === 'light' ? 'Mode Gelap' : 'Mode Terang') : ''}
            className={`w-full flex items-center ${isSidebarCollapsed ? 'justify-center px-2' : 'space-x-3 px-4'} py-2 text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded-lg transition text-sm font-medium`}
          >
            {theme === 'light' ? <Moon size={20} /> : <Sun size={20} />}
            {!isSidebarCollapsed && <span>{theme === 'light' ? 'Mode Gelap' : 'Mode Terang'}</span>}
          </button>

          <button
            onClick={handleLogout}
            title={isSidebarCollapsed ? 'Keluar' : ''}
            className={`w-full flex items-center ${isSidebarCollapsed ? 'justify-center px-2' : 'space-x-3 px-4'} py-2 text-gray-600 dark:text-gray-400 hover:text-red-600 dark:hover:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition text-sm font-medium`}
          >
            <LogOut size={20} />
            {!isSidebarCollapsed && <span>Keluar</span>}
          </button>
        </div>
      </aside>

      {/* Mobile Header (Visible only on small screens) */}
      <div className="md:hidden fixed top-0 w-full bg-white dark:bg-dark-card border-b border-gray-200 dark:border-dark-border z-20 px-4 py-3 flex justify-between items-center transition-colors duration-200">
        <span className="font-bold text-gray-900 dark:text-white">E-Yayasan</span>
        <div className="flex gap-2">
           <button onClick={toggleFullScreen} className="text-gray-500 dark:text-gray-400">
             {isFullScreen ? <Minimize2 size={20} /> : <Maximize2 size={20} />}
           </button>
           <button onClick={toggleTheme} className="text-gray-500 dark:text-gray-400">
             {theme === 'light' ? <Moon size={20} /> : <Sun size={20} />}
           </button>
           <button onClick={handleLogout} className="text-gray-500 dark:text-gray-400">
            <LogOut size={20} />
          </button>
        </div>
      </div>

      {/* Main Content */}
      <main className={`flex-1 ${isSidebarCollapsed ? 'md:ml-20' : 'md:ml-64'} p-4 md:p-8 mt-12 md:mt-0 overflow-y-auto transition-all duration-300 ease-in-out`}>
        {dbError && (
           <div className="mb-6 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 text-red-700 dark:text-red-400 px-4 py-3 rounded-lg">
             <div className="flex justify-between items-start">
                <div>
                    <p className="font-bold">Koneksi Database Gagal</p>
                    <p className="text-sm">Gagal mengambil data dari Supabase. Pastikan tabel telah dibuat.</p>
                </div>
                <button 
                    onClick={handleLogout}
                    className="bg-red-600 text-white px-3 py-1.5 rounded text-xs hover:bg-red-700 transition flex items-center gap-1"
                >
                    <LogOut size={12} /> Force Logout
                </button>
             </div>
             <Help />
           </div>
        )}

        {!dbError && loadingData ? (
          <div className="flex items-center justify-center h-64 text-gray-400">
            Memuat data...
          </div>
        ) : (
          <div className="max-w-7xl mx-auto animate-in fade-in duration-300 relative">

            {/* View Rendering with Permission Checks */}

            {view === 'DASHBOARD' && canAccess('DASHBOARD') && (
              <Dashboard 
                members={members} 
                programs={programs} 
                divisions={divisions} 
                events={events}
                attendance={attendance}
                isDarkMode={theme === 'dark'} 
              />
            )}
            {view === 'EVENTS' && canAccess('EVENTS') && (
              <Events 
                events={events}
                members={members}
                attendance={attendance}
                onRefresh={fetchData}
              />
            )}
            {view === 'EDUCATORS' && canAccess('EDUCATORS') && (
              <Educators 
                members={members}
                organizations={organizations}
                roles={roles}
              />
            )}
            {view === 'FINANCE' && canAccess('FINANCE') && (
              <Finance 
                programs={programs}
                divisions={divisions}
                organizations={organizations}
              />
            )}
            {view === 'ORGANIZATIONS' && canAccess('ORGANIZATIONS') && (
              <Organizations 
                data={organizations} 
                onRefresh={fetchData} 
              />
            )}
            {view === 'MEMBERS' && canAccess('MEMBERS') && (
              <Members 
                data={members} 
                roles={roles} 
                divisions={divisions} 
                organizations={organizations}
                onRefresh={fetchData} 
                currentUserEmail={session?.user?.email}
              />
            )}
            {view === 'ROLES' && canAccess('ROLES') && (
              <Roles 
                data={roles} 
                onRefresh={fetchData} 
              />
            )}
            {view === 'DIVISIONS' && canAccess('DIVISIONS') && (
              <Divisions 
                data={divisions} 
                members={members}
                programs={programs}
                onRefresh={fetchData} 
              />
            )}
            {view === 'PROGRAMS' && canAccess('PROGRAMS') && (
              <Programs 
                data={programs} 
                divisions={divisions} 
                organizations={organizations}
                members={members}
                onRefresh={fetchData} 
              />
            )}

            {/* Access Denied / Fallback */}
            {!canAccess(view) && (
                <div className="flex flex-col items-center justify-center h-64 text-gray-400">
                    <Lock size={48} className="mb-4 text-gray-300 dark:text-gray-600" />
                    <h2 className="text-lg font-bold text-gray-600 dark:text-gray-300">Akses Ditolak</h2>
                    <p>Anda tidak memiliki izin untuk melihat halaman ini.</p>
                </div>
            )}
          </div>
        )}
      </main>

      {/* Mobile Bottom Nav */}
      <div className="md:hidden fixed bottom-0 w-full bg-white dark:bg-dark-card border-t border-gray-200 dark:border-dark-border z-20 flex justify-around p-2 transition-colors duration-200 overflow-x-auto">
        {canAccess('DASHBOARD') && <button onClick={() => setView('DASHBOARD')} className={`p-2 rounded ${view === 'DASHBOARD' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><LayoutDashboard size={20}/></button>}
        {canAccess('EVENTS') && <button onClick={() => setView('EVENTS')} className={`p-2 rounded ${view === 'EVENTS' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><CalendarDays size={20}/></button>}
        {canAccess('EDUCATORS') && <button onClick={() => setView('EDUCATORS')} className={`p-2 rounded ${view === 'EDUCATORS' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><GraduationCap size={20}/></button>}
        {canAccess('FINANCE') && <button onClick={() => setView('FINANCE')} className={`p-2 rounded ${view === 'FINANCE' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><FileText size={20}/></button>}
      </div>
    </div>
  );
};

export default App;

