        >
        <Icon size={20} className="shrink-0" />
        {!isSidebarCollapsed && <span>{label}</span>}
        </button>
    );
  };

  return (
    <div className="flex min-h-screen bg-gray-50 dark:bg-dark-bg transition-colors duration-200">
      {/* Sidebar (Desktop) */}
      <aside 
        className={`${isSidebarCollapsed ? 'w-20' : 'w-64'} bg-white dark:bg-dark-card border-r border-gray-200 dark:border-dark-border fixed inset-y-0 left-0 z-20 hidden md:flex flex-col transition-all duration-300 ease-in-out`}
      >
        <div className={`p-6 border-b border-gray-100 dark:border-dark-border flex items-center ${isSidebarCollapsed ? 'justify-center' : 'justify-between'}`}>
          {!isSidebarCollapsed && (
            <div className="flex items-center space-x-2 text-primary-600 dark:text-primary-400 animate-in fade-in duration-300">
              <div className="bg-primary-600 dark:bg-primary-500 p-1.5 rounded-lg text-white">
                <Layers size={20} />
              </div>
              <span className="text-xl font-bold tracking-tight text-gray-900 dark:text-white">E-Yayasan</span>
            </div>
          )}
          {isSidebarCollapsed && (
             <div className="bg-primary-600 dark:bg-primary-500 p-1.5 rounded-lg text-white">
                <Layers size={20} />
             </div>
          )}
        </div>

        {/* Toggle Button */}
        <button 
            onClick={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
            className="absolute -right-3 top-20 bg-white dark:bg-gray-700 border border-gray-200 dark:border-gray-600 rounded-full p-1 shadow-sm hover:bg-gray-50 dark:hover:bg-gray-600 text-gray-500 dark:text-gray-300"
        >
            {isSidebarCollapsed ? <ChevronRight size={14} /> : <ChevronLeft size={14} />}
        </button>

        <nav className="flex-1 p-3 space-y-2 overflow-y-auto overflow-x-hidden mt-4">
          {!isSidebarCollapsed && (
            <div className="text-xs font-semibold text-gray-400 dark:text-gray-500 uppercase tracking-wider mb-2 px-4 transition-opacity duration-300">
              Menu Utama
            </div>
          )}
          <NavItem id="DASHBOARD" label="Dashboard" icon={LayoutDashboard} />
          <NavItem id="EVENTS" label="Acara & Absensi" icon={CalendarDays} />
          <NavItem id="EDUCATORS" label="Tenaga Pendidik" icon={GraduationCap} />
          <NavItem id="FINANCE" label="Pengajuan Keuangan" icon={FileText} />
          <NavItem id="ORGANIZATIONS" label="Organisasi" icon={Building2} />
          <NavItem id="MEMBERS" label="Anggota" icon={Users} />
          <NavItem id="ROLES" label="Role & Akses" icon={ShieldCheck} />
          <NavItem id="DIVISIONS" label="Bidang" icon={Layers} />
          <NavItem id="PROGRAMS" label="Program Kerja" icon={Briefcase} />
        </nav>

        <div className="p-4 border-t border-gray-100 dark:border-dark-border space-y-2">
          <button
            onClick={toggleFullScreen}
            title={isSidebarCollapsed ? (isFullScreen ? 'Keluar Full Screen' : 'Full Screen') : ''}
            className={`w-full flex items-center ${isSidebarCollapsed ? 'justify-center px-2' : 'space-x-3 px-4'} py-2 text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded-lg transition text-sm font-medium`}
          >
            {isFullScreen ? <Minimize2 size={20} /> : <Maximize2 size={20} />}
            {!isSidebarCollapsed && <span>{isFullScreen ? 'Exit Full Screen' : 'Full Screen'}</span>}
          </button>

          <button
            onClick={toggleTheme}
            title={isSidebarCollapsed ? (theme === 'light' ? 'Mode Gelap' : 'Mode Terang') : ''}
            className={`w-full flex items-center ${isSidebarCollapsed ? 'justify-center px-2' : 'space-x-3 px-4'} py-2 text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded-lg transition text-sm font-medium`}
          >
            {theme === 'light' ? <Moon size={20} /> : <Sun size={20} />}
            {!isSidebarCollapsed && <span>{theme === 'light' ? 'Mode Gelap' : 'Mode Terang'}</span>}
          </button>

          <button
            onClick={handleLogout}
            title={isSidebarCollapsed ? 'Keluar' : ''}
            className={`w-full flex items-center ${isSidebarCollapsed ? 'justify-center px-2' : 'space-x-3 px-4'} py-2 text-gray-600 dark:text-gray-400 hover:text-red-600 dark:hover:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition text-sm font-medium`}
          >
            <LogOut size={20} />
            {!isSidebarCollapsed && <span>Keluar</span>}
          </button>
        </div>
      </aside>

      {/* Mobile Header (Visible only on small screens) */}
      <div className="md:hidden fixed top-0 w-full bg-white dark:bg-dark-card border-b border-gray-200 dark:border-dark-border z-20 px-4 py-3 flex justify-between items-center transition-colors duration-200">
        <span className="font-bold text-gray-900 dark:text-white">E-Yayasan</span>
        <div className="flex gap-2">
           <button onClick={toggleFullScreen} className="text-gray-500 dark:text-gray-400">
             {isFullScreen ? <Minimize2 size={20} /> : <Maximize2 size={20} />}
           </button>
           <button onClick={toggleTheme} className="text-gray-500 dark:text-gray-400">
             {theme === 'light' ? <Moon size={20} /> : <Sun size={20} />}
           </button>
           <button onClick={handleLogout} className="text-gray-500 dark:text-gray-400">
            <LogOut size={20} />
          </button>
        </div>
      </div>

      {/* Main Content */}
      <main className={`flex-1 ${isSidebarCollapsed ? 'md:ml-20' : 'md:ml-64'} p-4 md:p-8 mt-12 md:mt-0 overflow-y-auto transition-all duration-300 ease-in-out`}>
        {dbError && (
           <div className="mb-6 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 text-red-700 dark:text-red-400 px-4 py-3 rounded-lg">
             <div className="flex justify-between items-start">
                <div>
                    <p className="font-bold">Koneksi Database Gagal</p>
                    <p className="text-sm">Gagal mengambil data dari Supabase. Pastikan tabel telah dibuat.</p>
                </div>
                <button 
                    onClick={handleLogout}
                    className="bg-red-600 text-white px-3 py-1.5 rounded text-xs hover:bg-red-700 transition flex items-center gap-1"
                >
                    <LogOut size={12} /> Force Logout
                </button>
             </div>
             <Help />
           </div>
        )}

        {!dbError && loadingData ? (
          <div className="flex items-center justify-center h-64 text-gray-400">
            Memuat data...
          </div>
        ) : (
          <div className="max-w-7xl mx-auto animate-in fade-in duration-300 relative">

            {/* View Rendering with Permission Checks */}

            {view === 'DASHBOARD' && canAccess('DASHBOARD') && (
              <Dashboard 
                members={members} 
                programs={programs} 
                divisions={divisions} 
                events={events}
                attendance={attendance}
                isDarkMode={theme === 'dark'} 
              />
            )}
            {view === 'EVENTS' && canAccess('EVENTS') && (
              <Events 
                events={events}
                members={members}
                attendance={attendance}
                onRefresh={fetchData}
              />
            )}
            {view === 'EDUCATORS' && canAccess('EDUCATORS') && (
              <Educators 
                members={members}
                organizations={organizations}
                roles={roles}
              />
            )}
            {view === 'FINANCE' && canAccess('FINANCE') && (
              <Finance 
                programs={programs}
                divisions={divisions}
                organizations={organizations}
              />
            )}
            {view === 'ORGANIZATIONS' && canAccess('ORGANIZATIONS') && (
              <Organizations 
                data={organizations} 
                members={members}
                roles={roles}
                onRefresh={fetchData} 
              />
            )}
            {view === 'MEMBERS' && canAccess('MEMBERS') && (
              <Members 
                data={members} 
                roles={roles} 
                divisions={divisions} 
                organizations={organizations}
                onRefresh={fetchData} 
                currentUserEmail={session?.user?.email}
              />
            )}
            {view === 'ROLES' && canAccess('ROLES') && (
              <Roles 
                data={roles} 
                onRefresh={fetchData} 
              />
            )}
            {view === 'DIVISIONS' && canAccess('DIVISIONS') && (
              <Divisions 
                data={divisions} 
                members={members}
                programs={programs}
                onRefresh={fetchData} 
              />
            )}
            {view === 'PROGRAMS' && canAccess('PROGRAMS') && (
              <Programs 
                data={programs} 
                divisions={divisions} 
                organizations={organizations}
                members={members}
                onRefresh={fetchData} 
              />
            )}

            {/* Access Denied / Fallback */}
            {!canAccess(view) && (
                <div className="flex flex-col items-center justify-center h-64 text-gray-400">
                    <Lock size={48} className="mb-4 text-gray-300 dark:text-gray-600" />
                    <h2 className="text-lg font-bold text-gray-600 dark:text-gray-300">Akses Ditolak</h2>
                    <p>Anda tidak memiliki izin untuk melihat halaman ini.</p>
                </div>
            )}
          </div>
        )}
      </main>

      {/* Mobile Bottom Nav */}
      <div className="md:hidden fixed bottom-0 w-full bg-white dark:bg-dark-card border-t border-gray-200 dark:border-dark-border z-20 flex justify-around p-2 transition-colors duration-200 overflow-x-auto">
        {canAccess('DASHBOARD') && <button onClick={() => setView('DASHBOARD')} className={`p-2 rounded ${view === 'DASHBOARD' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><LayoutDashboard size={20}/></button>}
        {canAccess('EVENTS') && <button onClick={() => setView('EVENTS')} className={`p-2 rounded ${view === 'EVENTS' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><CalendarDays size={20}/></button>}
        {canAccess('EDUCATORS') && <button onClick={() => setView('EDUCATORS')} className={`p-2 rounded ${view === 'EDUCATORS' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><GraduationCap size={20}/></button>}
        {canAccess('FINANCE') && <button onClick={() => setView('FINANCE')} className={`p-2 rounded ${view === 'FINANCE' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><FileText size={20}/></button>}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { supabase } from '../supabaseClient';
import { Organization, Member, Role } from '../types';
import { Plus, Edit, Trash2, Building2, AlertTriangle, GraduationCap, Users, UserPlus, X, Save } from '../components/ui/Icons';
import { Modal } from '../components/Modal';

interface OrganizationsProps {
  data: Organization[];
  members: Member[];
  roles: Role[];
  onRefresh: () => void;
}

export const Organizations: React.FC<OrganizationsProps> = ({ data, members, roles, onRefresh }) => {
  // Org CRUD State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<Organization | null>(null);
  const [deleteConfirm, setDeleteConfirm] = useState<{isOpen: boolean, id: string | null}>({ isOpen: false, id: null });
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [loading, setLoading] = useState(false);

  // Educator Management State
  const [educatorModal, setEducatorModal] = useState<{isOpen: boolean, org: Organization | null}>({ isOpen: false, org: null });
  const [educatorView, setEducatorView] = useState<'LIST' | 'FORM'>('LIST');
  const [editingEducator, setEditingEducator] = useState<Member | null>(null);

  // Educator Form State
  const [eduName, setEduName] = useState('');
  const [eduEmail, setEduEmail] = useState('');
  const [eduPhone, setEduPhone] = useState('');
  const [eduRoleId, setEduRoleId] = useState('');
  const [eduLoading, setEduLoading] = useState(false);

  // --- ORG CRUD HANDLERS ---
  const handleOpen = (org?: Organization) => {
    if (org) {
      setEditingItem(org);
      setName(org.name);
      setDescription(org.description || '');
    } else {
      setEditingItem(null);
      setName('');
      setDescription('');
    }
    setIsModalOpen(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    const payload = { name, description };
    try {
      if (editingItem) {
        const { error } = await supabase.from('organizations').update(payload).eq('id', editingItem.id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from('organizations').insert([payload]);
        if (error) throw error;
      }
      onRefresh();
      setIsModalOpen(false);
    } catch (error: any) {
      alert('Error: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const confirmDelete = (id: string) => {
    setDeleteConfirm({ isOpen: true, id });
  };

  const executeDelete = async () => {
    if (!deleteConfirm.id) return;
    try {
      const { error } = await supabase.from('organizations').delete().eq('id', deleteConfirm.id);
      if (error) throw error;
      onRefresh();
      setDeleteConfirm({ isOpen: false, id: null });
    } catch (error: any) {
      alert('Error: ' + error.message);
    }
  };

  // --- EDUCATOR CRUD HANDLERS ---

  // Filter members belonging to the currently selected organization
  const currentOrgEducators = useMemo(() => {
      if (!educatorModal.org) return [];
      return members.filter(m => m.organization_id === educatorModal.org!.id);
  }, [members, educatorModal.org]);

  const openEducatorManager = (org: Organization) => {
      setEducatorModal({ isOpen: true, org });
      setEducatorView('LIST');
  };

  const openEducatorForm = (member?: Member) => {
      if (member) {
          setEditingEducator(member);
          setEduName(member.full_name);
          setEduEmail(member.email);
          setEduPhone(member.phone || '');
          setEduRoleId(member.role_id || '');
      } else {
          setEditingEducator(null);
          setEduName('');
          setEduEmail('');
          setEduPhone('');
          setEduRoleId('');
      }
      setEducatorView('FORM');
  };

  const handleEducatorSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!educatorModal.org) return;
      setEduLoading(true);

      const payload = {
          full_name: eduName,
          email: eduEmail,
          phone: eduPhone,
          role_id: eduRoleId || null,
          organization_id: educatorModal.org.id, // Enforce current org
          division_id: null // Educators usually don't need division here, or add field if needed
      };

      try {
          if (editingEducator) {
              const { error } = await supabase.from('members').update(payload).eq('id', editingEducator.id);
              if (error) throw error;
          } else {
              const { error } = await supabase.from('members').insert([payload]);
              if (error) throw error;
          }
          onRefresh(); // Refresh app data
          setEducatorView('LIST');
      } catch (error: any) {
          alert("Gagal menyimpan data pendidik: " + error.message);
      } finally {
          setEduLoading(false);
      }
  };

  const deleteEducator = async (id: string) => {
      if (!confirm("Yakin ingin menghapus data pendidik ini? Data akan hilang permanen.")) return;
      try {
          const { error } = await supabase.from('members').delete().eq('id', id);
          if (error) throw error;
          onRefresh();
      } catch (error: any) {
          alert("Gagal menghapus: " + error.message);
      }
  }


  return (
    <div>
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
          <Building2 className="text-primary-600 dark:text-primary-400" /> Manajemen Organisasi
        </h2>
        <button
          onClick={() => handleOpen()}
          className="bg-primary-600 hover:bg-primary-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition"
        >
          <Plus size={18} /> Tambah Organisasi
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {data.map((item) => {
           // Count educators for this org
           const educatorCount = members.filter(m => m.organization_id === item.id).length;

           return (
            <div key={item.id} className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border hover:shadow-md transition flex flex-col">
                <div className="flex justify-between items-start mb-4">
                <div className="p-2 bg-orange-50 dark:bg-orange-900/30 text-orange-600 dark:text-orange-400 rounded-lg">
                    <Building2 size={20} />
                </div>
                <div className="flex gap-2">
                    <button onClick={() => handleOpen(item)} className="text-gray-400 hover:text-blue-600 dark:hover:text-blue-400">
                    <Edit size={18} />
                    </button>
                    <button onClick={() => confirmDelete(item.id)} className="text-gray-400 hover:text-red-600 dark:hover:text-red-400">
                    <Trash2 size={18} />
                    </button>
                </div>
                </div>
                <h3 className="text-lg font-bold text-gray-900 dark:text-white mb-2">{item.name}</h3>
                <p className="text-sm text-gray-500 dark:text-gray-400 line-clamp-3 mb-4 flex-1">
                {item.description || 'Tidak ada deskripsi.'}
                </p>

                <div className="mt-4 pt-4 border-t border-gray-100 dark:border-dark-border flex justify-between items-center">
                    <div className="text-xs text-gray-500 dark:text-gray-400 flex items-center gap-1">
                        <Users size={14} /> {educatorCount} Pendidik
                    </div>
                    <button 
                        onClick={() => openEducatorManager(item)}
                        className="text-xs font-medium text-primary-600 hover:text-primary-700 dark:text-primary-400 bg-primary-50 dark:bg-primary-900/20 px-3 py-1.5 rounded-full flex items-center gap-1 hover:bg-primary-100 transition"
                    >
                        <GraduationCap size={14} /> Kelola Pendidik
                    </button>
                </div>
            </div>
        )})}
        {data.length === 0 && (
          <div className="col-span-full text-center py-10 text-gray-500 dark:text-gray-400 bg-white dark:bg-dark-card rounded-xl border border-dashed border-gray-200 dark:border-dark-border">
            Belum ada organisasi yang dibuat.
          </div>
        )}
      </div>

      {/* --- MODAL EDIT ORGANISASI --- */}
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={editingItem ? 'Edit Organisasi' : 'Tambah Organisasi'}>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Nama Organisasi</label>
            <input
              type="text"
              required
              value={name}
              onChange={e => setName(e.target.value)}
              className="mt-1 block w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 dark:text-white px-3 py-2 focus:border-primary-500 focus:ring-primary-500 outline-none"
              placeholder="Contoh: SD IT Yayasan"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Deskripsi</label>
            <textarea
              rows={3}
              value={description}
              onChange={e => setDescription(e.target.value)}
              className="mt-1 block w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 dark:text-white px-3 py-2 focus:border-primary-500 focus:ring-primary-500 outline-none"
            />
          </div>
          <div className="pt-4 flex justify-end gap-3">
            <button
              type="button"
              onClick={() => setIsModalOpen(false)}
              className="px-4 py-2 text-sm font-medium text-gray-700 dark:text-gray-300 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-md hover:bg-gray-50 dark:hover:bg-gray-600"
            >
              Batal
            </button>
            <button
              type="submit"
              disabled={loading}
              className="px-4 py-2 text-sm font-medium text-white bg-primary-600 rounded-md hover:bg-primary-700 disabled:opacity-50"
            >
              {loading ? 'Menyimpan...' : 'Simpan'}
            </button>
          </div>
        </form>
      </Modal>

      {/* --- MODAL MANAGEMENT EDUCATOR --- */}
      <Modal 
        isOpen={educatorModal.isOpen} 
        onClose={() => setEducatorModal({isOpen: false, org: null})} 
        title={`Manajemen Pendidik: ${educatorModal.org?.name || ''}`}
      >
        {educatorView === 'LIST' ? (
            <div className="space-y-4">
                <div className="flex justify-between items-center">
                    <p className="text-sm text-gray-600 dark:text-gray-400">Daftar guru dan staf di organisasi ini.</p>
                    <button 
                        onClick={() => openEducatorForm()}
                        className="bg-primary-600 text-white text-xs px-3 py-2 rounded-lg flex items-center gap-2 hover:bg-primary-700 transition"
                    >
                        <UserPlus size={14} /> Tambah Guru
                    </button>
                </div>

                <div className="max-h-[50vh] overflow-y-auto border border-gray-200 dark:border-gray-700 rounded-lg">
                    <table className="w-full text-left">
                        <thead className="bg-gray-50 dark:bg-gray-800 text-xs uppercase text-gray-500 dark:text-gray-400 sticky top-0">
                            <tr>
                                <th className="px-4 py-3">Nama</th>
                                <th className="px-4 py-3">Role</th>
                                <th className="px-4 py-3 text-right">Aksi</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100 dark:divide-dark-border text-sm">
                            {currentOrgEducators.map(m => (
                                <tr key={m.id} className="hover:bg-gray-50 dark:hover:bg-gray-800/50">
                                    <td className="px-4 py-3">
                                        <div className="font-medium text-gray-900 dark:text-white">{m.full_name}</div>
                                        <div className="text-xs text-gray-500">{m.email}</div>
                                    </td>
                                    <td className="px-4 py-3">
                                        <span className="bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-300 px-2 py-0.5 rounded text-xs">
                                            {m.roles?.name || '-'}
                                        </span>
                                    </td>
                                    <td className="px-4 py-3 text-right">
                                        <div className="flex justify-end gap-2">
                                            <button onClick={() => openEducatorForm(m)} className="text-blue-500 hover:text-blue-700"><Edit size={16}/></button>
                                            <button onClick={() => deleteEducator(m.id)} className="text-red-500 hover:text-red-700"><Trash2 size={16}/></button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                            {currentOrgEducators.length === 0 && (
                                <tr>
                                    <td colSpan={3} className="p-6 text-center text-gray-500 italic">Belum ada data tenaga pendidik.</td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
                <div className="flex justify-end">
                     <button
                        onClick={() => setEducatorModal({isOpen: false, org: null})}
                        className="text-sm text-gray-500 hover:text-gray-700 dark:text-gray-400 dark:hover:text-gray-200 px-3 py-1"
                     >
                        Tutup
                     </button>
                </div>
            </div>
        ) : (
            // FORM VIEW
            <form onSubmit={handleEducatorSubmit} className="space-y-4 animate-in slide-in-from-right-10 duration-200">
                <div className="flex items-center justify-between mb-2">
                    <h4 className="text-sm font-bold text-gray-800 dark:text-white">
                        {editingEducator ? 'Edit Pendidik' : 'Tambah Pendidik Baru'}
                    </h4>
                    <button 
                        type="button" 
                        onClick={() => setEducatorView('LIST')}
                        className="text-gray-400 hover:text-gray-600"
                    >
                        <X size={16} />
                    </button>
                </div>

                <div>
                    <label className="block text-xs font-medium text-gray-700 dark:text-gray-300 mb-1">Nama Lengkap</label>
                    <input type="text" required value={eduName} onChange={e => setEduName(e.target.value)} 
