                {isEducation && (
                    <div className="absolute top-0 right-0 bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300 px-3 py-1 rounded-bl-lg text-[10px] font-bold uppercase flex items-center gap-1">
