import React, { useMemo, useState } from 'react';
import { Member, Organization, Role } from '../types';
import { GraduationCap, Users, Building2, UserPlus, Search, AlertTriangle, School } from '../components/ui/Icons';
import { Modal } from '../components/Modal';

interface EducatorsProps {
  members: Member[];
  organizations: Organization[];
  roles: Role[];
}

export const Educators: React.FC<EducatorsProps> = ({ members, organizations, roles }) => {
  const [selectedOrg, setSelectedOrg] = useState<Organization | null>(null);
  const [isDetailOpen, setIsDetailOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  // 1. Only get Education Organizations
  const educationOrgs = useMemo(() => {
      return organizations.filter(org => org.type === 'Education');
  }, [organizations]);

  // 2. Filter Members to only get Educators (Role Name contains 'Guru' or 'Kepala Sekolah')
  const educatorMembers = useMemo(() => {
      return members.filter(m => {
          const roleName = m.roles?.name?.toLowerCase() || '';
          return roleName.includes('guru') || roleName.includes('kepala sekolah');
      });
  }, [members]);

  // 3. Group Educators by Organization
  const orgStats = useMemo(() => {
      return educationOrgs.map(org => {
          const orgEducators = educatorMembers.filter(m => m.organization_id === org.id);
          const principal = orgEducators.find(m => m.roles?.name?.toLowerCase().includes('kepala sekolah'));
          const teachers = orgEducators.filter(m => m.roles?.name?.toLowerCase().includes('guru'));

          return {
              org,
              principal,
              teacherCount: teachers.length,
              allEducators: orgEducators
          };
      });
  }, [educationOrgs, educatorMembers]);

  // 4. Detail List Logic
  const detailList = useMemo(() => {
      if (!selectedOrg) return [];
      const orgData = orgStats.find(s => s.org.id === selectedOrg.id);
      if (!orgData) return [];

      return orgData.allEducators.filter(m => 
        m.full_name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        m.email.toLowerCase().includes(searchQuery.toLowerCase())
      );
  }, [selectedOrg, orgStats, searchQuery]);

  const openDetail = (org: Organization) => {
      setSelectedOrg(org);
      setSearchQuery('');
      setIsDetailOpen(true);
  }

  return (
    <div className="space-y-6">
        <div className="flex justify-between items-center">
            <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
                <GraduationCap className="text-primary-600 dark:text-primary-400" /> Data Tenaga Pendidik
            </h2>
        </div>

        {educationOrgs.length === 0 ? (
             <div className="bg-blue-50 dark:bg-blue-900/20 p-6 rounded-xl border border-blue-100 dark:border-blue-800 text-center">
                 <School className="mx-auto text-blue-500 mb-2" size={32} />
                 <h3 className="font-semibold text-blue-800 dark:text-blue-300">Belum Ada Organisasi Pendidikan</h3>
                 <p className="text-sm text-blue-600 dark:text-blue-400 mt-1">
                     Silakan buat organisasi dengan tipe "Pendidikan" di menu Organisasi untuk melihat data tenaga pendidik.
                 </p>
             </div>
        ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
                {orgStats.map(({ org, principal, teacherCount }) => (
                    <div 
                        key={org.id} 
                        onClick={() => openDetail(org)}
                        className="bg-white dark:bg-dark-card rounded-xl shadow-sm border border-gray-100 dark:border-dark-border p-6 hover:shadow-md transition cursor-pointer group"
                    >
                        <div className="flex items-start justify-between mb-4">
                            <div className="p-3 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-lg group-hover:bg-blue-100 dark:group-hover:bg-blue-900/50 transition">
                                <School size={24} />
                            </div>
                            <div className="text-right">
                                <p className="text-xs text-gray-500 dark:text-gray-400">Total Guru</p>
                                <p className="text-2xl font-bold text-gray-900 dark:text-white">{teacherCount}</p>
                            </div>
                        </div>

                        <h3 className="text-lg font-bold text-gray-800 dark:text-white mb-3 line-clamp-1" title={org.name}>
                            {org.name}
                        </h3>

                        <div className="bg-gray-50 dark:bg-gray-800 rounded-lg p-3 border border-gray-100 dark:border-gray-700">
                            <p className="text-xs text-gray-500 dark:text-gray-400 mb-1 uppercase font-semibold">Kepala Sekolah</p>
                            {principal ? (
                                <div className="flex items-center gap-2">
                                    <div className="w-8 h-8 rounded-full bg-primary-100 dark:bg-primary-900 text-primary-600 dark:text-primary-300 flex items-center justify-center text-xs font-bold">
                                        {principal.full_name.charAt(0)}
                                    </div>
                                    <div className="overflow-hidden">
                                        <p className="text-sm font-medium text-gray-900 dark:text-white truncate">{principal.full_name}</p>
                                        <p className="text-sm text-gray-500 dark:text-gray-400 truncate">{principal.email}</p>
                                    </div>
                                </div>
                            ) : (
                                <p className="text-sm text-gray-400 italic flex items-center gap-1">
                                    <AlertTriangle size={12} /> Belum ada data
                                </p>
                            )}
                        </div>
                    </div>
                ))}
            </div>
        )}

        {/* --- DETAIL MODAL --- */}
        {selectedOrg && (
            <Modal
                isOpen={isDetailOpen}
                onClose={() => setIsDetailOpen(false)}
                title={`Tenaga Pendidik: ${selectedOrg.name}`}
            >
                <div className="space-y-4">
                    {/* Search */}
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                        <input 
                            type="text" 
                            placeholder="Cari guru..." 
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="w-full pl-9 pr-4 py-2 text-sm border border-gray-200 dark:border-gray-700 rounded-lg bg-gray-50 dark:bg-gray-800 dark:text-white focus:outline-none focus:ring-2 focus:ring-primary-500"
                        />
                    </div>

                    <div className="max-h-[60vh] overflow-y-auto">
                        <table className="w-full text-left">
                            <thead className="bg-gray-50 dark:bg-gray-800 text-gray-600 dark:text-gray-400 text-xs uppercase font-semibold sticky top-0">
                                <tr>
                                    <th className="px-4 py-3">Nama</th>
                                    <th className="px-4 py-3">Jabatan</th>
                                    <th className="px-4 py-3 text-right">Kontak</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-100 dark:divide-dark-border">
                                {detailList.map(m => (
                                    <tr key={m.id} className="hover:bg-gray-50 dark:hover:bg-gray-800/50">
                                        <td className="px-4 py-3">
                                            <div className="font-medium text-gray-900 dark:text-white">{m.full_name}</div>
                                            <div className="text-xs text-gray-500 dark:text-gray-400">{m.email}</div>
                                        </td>
                                        <td className="px-4 py-3">
                                            <span className={`text-xs px-2 py-1 rounded-full font-medium ${
                                                m.roles?.name?.toLowerCase().includes('kepala sekolah') 
                                                ? 'bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-300' 
                                                : 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300'
                                            }`}>
                                                {m.roles?.name || 'Guru'}
                                            </span>
                                        </td>
                                        <td className="px-4 py-3 text-right text-sm text-gray-600 dark:text-gray-400">
                                            {m.phone || '-'}
                                        </td>
                                    </tr>
                                ))}
                                {detailList.length === 0 && (
                                    <tr>
                                        <td colSpan={3} className="px-4 py-6 text-center text-gray-500 dark:text-gray-400 italic">
                                            Tidak ada data ditemukan.
                                        </td>
                                    </tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                    <div className="flex justify-end pt-2">
                        <button 
                            onClick={() => setIsDetailOpen(false)}
                            className="px-4 py-2 text-sm font-medium text-gray-700 dark:text-gray-300 bg-white dark:bg-gray-700 border border-gray-300 dark:border-gray-600 rounded-md hover:bg-gray-50 dark:hover:bg-gray-600"
                        >
                            Tutup
                        </button>
                    </div>
                </div>
            </Modal>
        )}
    </div>
  );
};

import React, { useState } from 'react';
import { supabase } from '../supabaseClient';
import { Foundation, ViewState } from '../types';
import { Globe, Edit, Trash2, Plus, CheckSquare, Square, Save, X } from '../components/ui/Icons';
import { Modal } from '../components/Modal';

interface FoundationsProps {
  data: Foundation[];
  onRefresh: () => void;
}

const AVAILABLE_FEATURES: {id: string, label: string}[] = [
    { id: 'DASHBOARD', label: 'Dashboard' },
    { id: 'EVENTS', label: 'Acara & Absensi' },
    { id: 'EDUCATORS', label: 'Tenaga Pendidik' },
    { id: 'FINANCE', label: 'Keuangan' },
    { id: 'ORGANIZATIONS', label: 'Organisasi' },
    { id: 'MEMBERS', label: 'Anggota' },
    { id: 'ROLES', label: 'Role & Akses' },
    { id: 'DIVISIONS', label: 'Bidang / Divisi' },
    { id: 'PROGRAMS', label: 'Program Kerja' },
];

export const Foundations: React.FC<FoundationsProps> = ({ data, onRefresh }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<Foundation | null>(null);
  const [name, setName] = useState('');
  const [address, setAddress] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);

  const handleOpen = (item?: Foundation) => {
    if (item) {
      setEditingItem(item);
      setName(item.name);
      setAddress(item.address || '');
      setFeatures(item.features || []);
    } else {
      setEditingItem(null);
      setName('');
      setAddress('');
      setFeatures(AVAILABLE_FEATURES.map(f => f.id)); // Default enable all
    }
    setIsModalOpen(true);
  };

  const toggleFeature = (id: string) => {
    setFeatures(prev => prev.includes(id) ? prev.filter(f => f !== id) : [...prev, id]);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    const payload = { name, address, features };
    try {
      if (editingItem) {
        const { error } = await supabase.from('foundations').update(payload).eq('id', editingItem.id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from('foundations').insert([payload]);
        if (error) throw error;
      }
      onRefresh();
      setIsModalOpen(false);
    } catch (error: any) {
      alert(error.message);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
      if(!confirm("Hapus Yayasan? Data terkait mungkin akan error atau hilang.")) return;
      try {
          const { error } = await supabase.from('foundations').delete().eq('id', id);
          if (error) throw error;
          onRefresh();
      } catch (error: any) {
          alert(error.message);
      }
  }

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
          <Globe className="text-primary-600 dark:text-primary-400" /> Master Yayasan
        </h2>
        <button
          onClick={() => handleOpen()}
          className="bg-primary-600 hover:bg-primary-700 text-white px-4 py-2 rounded-lg flex items-center gap-2 transition"
        >
          <Plus size={18} /> Tambah Yayasan
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {data.map(foundation => (
              <div key={foundation.id} className="bg-white dark:bg-dark-card p-6 rounded-xl shadow-sm border border-gray-100 dark:border-dark-border hover:shadow-md transition">
                  <div className="flex justify-between items-start mb-2">
                     <div className="bg-indigo-50 dark:bg-indigo-900/30 p-2 rounded-lg text-indigo-600 dark:text-indigo-400">
                         <Globe size={24} />
                     </div>
                     <div className="flex gap-2">
                         <button onClick={() => handleOpen(foundation)} className="text-gray-400 hover:text-blue-500"><Edit size={16}/></button>
                         <button onClick={() => handleDelete(foundation.id)} className="text-gray-400 hover:text-red-500"><Trash2 size={16}/></button>
                     </div>
                  </div>
                  <h3 className="text-lg font-bold text-gray-900 dark:text-white">{foundation.name}</h3>
                  <p className="text-sm text-gray-500 dark:text-gray-400 mb-4 truncate">{foundation.address || 'Tidak ada alamat'}</p>

                  <div className="border-t border-gray-100 dark:border-gray-700 pt-3">
                      <p className="text-xs text-gray-500 mb-2 font-semibold">Fitur Aktif:</p>
                      <div className="flex flex-wrap gap-1">
                          {foundation.features?.slice(0, 5).map(f => (
                              <span key={f} className="text-[10px] px-2 py-0.5 bg-gray-100 dark:bg-gray-800 rounded text-gray-600 dark:text-gray-300 border border-gray-200 dark:border-gray-700">
                                  {AVAILABLE_FEATURES.find(af => af.id === f)?.label || f}
                              </span>
                          ))}
                          {(foundation.features?.length || 0) > 5 && (
                              <span className="text-[10px] px-2 py-0.5 bg-gray-100 dark:bg-gray-800 rounded text-gray-500">+{foundation.features.length - 5} lainnya</span>
                          )}
                      </div>
                  </div>
              </div>
          ))}
      </div>

      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title={editingItem ? 'Edit Yayasan' : 'Tambah Yayasan Baru'}>
          <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Nama Yayasan</label>
                  <input type="text" required value={name} onChange={e => setName(e.target.value)} 
                        className="mt-1 block w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 dark:text-white px-3 py-2 outline-none focus:ring-2 focus:ring-primary-500"/>
              </div>
              <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Alamat</label>
                  <textarea rows={2} value={address} onChange={e => setAddress(e.target.value)} 
                        className="mt-1 block w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 dark:text-white px-3 py-2 outline-none focus:ring-2 focus:ring-primary-500"/>
              </div>

              <div className="bg-gray-50 dark:bg-gray-900/50 p-4 rounded-lg border border-gray-200 dark:border-gray-700">
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">Pilih Fitur / Modul Aktif</label>
                  <div className="grid grid-cols-2 gap-2">
                      {AVAILABLE_FEATURES.map(feat => (
                          <div 
                            key={feat.id}
                            onClick={() => toggleFeature(feat.id)}
                            className={`flex items-center gap-2 p-2 rounded border cursor-pointer transition ${features.includes(feat.id) ? 'bg-primary-50 border-primary-500 text-primary-700 dark:bg-primary-900/30' : 'bg-white border-gray-200 text-gray-500 dark:bg-gray-800 dark:border-gray-700'}`}
                          >
                             {features.includes(feat.id) ? <CheckSquare size={16}/> : <Square size={16}/>}
                             <span className="text-xs font-medium">{feat.label}</span>
                          </div>
                      ))}
                  </div>
              </div>

              <div className="pt-4 flex justify-end gap-3">
                    <button type="button" onClick={() => setIsModalOpen(false)} className="px-4 py-2 text-sm border rounded bg-white dark:bg-gray-700 dark:border-gray-600 text-gray-700 dark:text-gray-300">Batal</button>
                    <button type="submit" disabled={loading} className="px-4 py-2 text-sm bg-primary-600 text-white rounded hover:bg-primary-700">{loading ? 'Menyimpan...' : 'Simpan'}</button>
              </div>
          </form>
      </Modal>
    </div>
  );
};

import React, { useEffect, useState, useMemo } from 'react';
import { supabase } from './supabaseClient';
import { ViewState, Member, Role, Division, Program, Organization, Event, EventAttendance, Foundation } from './types';
import { Auth } from './components/Auth';
import { Dashboard } from './pages/Dashboard';
import { Members } from './pages/Members';
import { Divisions } from './pages/Divisions';
import { Organizations } from './pages/Organizations';
import { Programs } from './pages/Programs';
import { Events } from './pages/Events';
import { Finance } from './pages/Finance'; 
import { Educators } from './pages/Educators'; 
import { Roles } from './pages/Roles';
import { Foundations } from './pages/Foundations'; // New Page
import { Help } from './components/Help';
import { 
  LayoutDashboard, 
  Users, 
  Layers, 
  Briefcase, 
  LogOut, 
  Sun, 
  Moon, 
  Building2, 
  ShieldCheck,
  ChevronLeft,
  ChevronRight,
  CalendarDays,
  FileText,
  Maximize2,
  Minimize2,
  GraduationCap,
  Lock,
  Globe
} from './components/ui/Icons';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [view, setView] = useState<ViewState>('DASHBOARD');
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  const [isFullScreen, setIsFullScreen] = useState(false);

  // Theme State
  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('theme') as 'light' | 'dark' || 'light';
    }
    return 'light';
  });

  // Data State
  const [members, setMembers] = useState<Member[]>([]);
  const [roles, setRoles] = useState<Role[]>([]);
  const [divisions, setDivisions] = useState<Division[]>([]);
  const [organizations, setOrganizations] = useState<Organization[]>([]);
  const [programs, setPrograms] = useState<Program[]>([]);
  const [events, setEvents] = useState<Event[]>([]);
  const [attendance, setAttendance] = useState<EventAttendance[]>([]);
  const [foundations, setFoundations] = useState<Foundation[]>([]); // New State

  // Context State
  const [userPermissions, setUserPermissions] = useState<string[]>([]);
  const [activeFoundation, setActiveFoundation] = useState<Foundation | null>(null);
  const [isSuperAdmin, setIsSuperAdmin] = useState(false);

  const [loadingData, setLoadingData] = useState(false);
  const [dbError, setDbError] = useState(false);

  // Theme Effect
  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  // Full Screen Effect
  useEffect(() => {
    const handleFsChange = () => {
      setIsFullScreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFsChange);
    return () => document.removeEventListener('fullscreenchange', handleFsChange);
  }, []);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch((err) => {
        console.error(`Error attempting to enable full-screen mode: ${err.message}`);
      });
    } else {
      document.exitFullscreen();
    }
  };

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
    });

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
    });

    return () => subscription.unsubscribe();
  }, []);

  // --- FETCH DATA & DETERMINE PERMISSIONS ---
  const fetchData = async () => {
    if (!session) return;
    setDbError(false);

    try {
      const [membersRes, rolesRes, divisionsRes, programsRes, orgsRes, eventsRes, attendRes, foundRes] = await Promise.all([
        supabase.from('members').select('*, divisions(name), roles(name, permissions)'), 
        supabase.from('roles').select('*'),
        supabase.from('divisions').select('*'),
        supabase.from('programs').select('*'),
        supabase.from('organizations').select('*'),
        supabase.from('events').select('*'),
        supabase.from('event_attendance').select('*'),
        supabase.from('foundations').select('*') // Fetch Foundations
      ]);

      if (membersRes.error || rolesRes.error || divisionsRes.error || programsRes.error || orgsRes.error) {
        throw new Error('Database Error');
      }

      setMembers(membersRes.data || []);
      setRoles(rolesRes.data || []);
      setDivisions(divisionsRes.data || []);
      setPrograms(programsRes.data || []);
      setOrganizations(orgsRes.data || []);
      setEvents(eventsRes.data || []);
      setAttendance(attendRes.data || []);
      const fData = foundRes.data || [];
      setFoundations(fData);

      // --- DETERMINE CONTEXT ---
      const currentUserEmail = session.user.email;
      const currentUser = membersRes.data?.find((m: any) => m.email === currentUserEmail);

      // Check Super Admin
      let isSuper = false;
      if (currentUserEmail === 'super@yayasan.org') {
          isSuper = true;
      } else if (currentUser && currentUser.roles?.name?.toLowerCase().includes('super')) {
          isSuper = true;
      }
      setIsSuperAdmin(isSuper);

      // Set Permissions
      if (currentUser && currentUser.roles && currentUser.roles.permissions) {
          setUserPermissions(currentUser.roles.permissions);
      } else if (isSuper) {
          // Super Admin gets everything + MASTER_FOUNDATION
          setUserPermissions(['DASHBOARD', 'MEMBERS', 'DIVISIONS', 'ORGANIZATIONS', 'PROGRAMS', 'ROLES', 'EVENTS', 'FINANCE', 'EDUCATORS', 'MASTER_FOUNDATION']);
      } else {
          setUserPermissions(['DASHBOARD']); 
      }

      // Set Active Foundation
      // 1. If user has foundation_id, use that.
      // 2. If Super Admin, default to first one or specific logic (here just first one for simplicity)
      if (currentUser && currentUser.foundation_id) {
          const myFoundation = fData.find((f: Foundation) => f.id === currentUser.foundation_id);
          setActiveFoundation(myFoundation || null);
      } else if (fData.length > 0) {
          setActiveFoundation(fData[0]); // Default fallback
      }

    } catch (error) {
      console.error('Error fetching data:', error);
      setDbError(true); 
    } finally {
      setLoadingData(false);
    }
  };

  useEffect(() => {
    if (session) {
      setLoadingData(true); 
      fetchData();
    }
  }, [session]);

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  if (!session) {
    return <Auth onLogin={() => {}} />;
  }

  // Permission Checker
  const canAccess = (viewId: ViewState) => {
      // 1. Basic User Permission Check
      if (userPermissions.length === 0) return false;
      if (!userPermissions.includes(viewId)) return false;

      // 2. Foundation Feature Check (Toggle Features)
      // If viewId is in the list of configurable features, check if activeFoundation has it enabled.
      // Super Admin bypasses this check if they are in Master view, but generally should reflect the org context.
      // NOTE: MASTER_FOUNDATION is only for Super Admin and not a "Foundation Feature".
      if (viewId === 'MASTER_FOUNDATION') return isSuperAdmin;

      if (activeFoundation && activeFoundation.features) {
          // If the foundation features list exists, strictly check it.
          // Unless it's Dashboard (always allowed usually)
          if (viewId === 'DASHBOARD') return true;
          return activeFoundation.features.includes(viewId);
      }

      return true; // Fallback if no foundation config found
  }

  const NavItem = ({ id, label, icon: Icon }: { id: ViewState; label: string; icon: any }) => {
    if (!canAccess(id)) return null;

    return (
        <button
        onClick={() => setView(id)}
        title={isSidebarCollapsed ? label : ''}
        className={`w-full flex items-center ${isSidebarCollapsed ? 'justify-center px-2' : 'space-x-3 px-4'} py-3 rounded-lg transition text-sm font-medium ${
            view === id 
            ? 'bg-primary-50 dark:bg-primary-900/30 text-primary-700 dark:text-primary-400' 
            : 'text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 hover:text-gray-900 dark:hover:text-gray-200'
        }`}
        >
        <Icon size={20} className="shrink-0" />
        {!isSidebarCollapsed && <span>{label}</span>}
        </button>
    );
  };

  return (
    <div className="flex min-h-screen bg-gray-50 dark:bg-dark-bg transition-colors duration-200">
      {/* Sidebar (Desktop) */}
      <aside 
        className={`${isSidebarCollapsed ? 'w-20' : 'w-64'} bg-white dark:bg-dark-card border-r border-gray-200 dark:border-dark-border fixed inset-y-0 left-0 z-20 hidden md:flex flex-col transition-all duration-300 ease-in-out`}
      >
        <div className={`p-6 border-b border-gray-100 dark:border-dark-border flex items-center ${isSidebarCollapsed ? 'justify-center' : 'justify-between'}`}>
          {!isSidebarCollapsed && (
            <div className="flex items-center space-x-2 text-primary-600 dark:text-primary-400 animate-in fade-in duration-300">
              <div className="bg-primary-600 dark:bg-primary-500 p-1.5 rounded-lg text-white">
                <Layers size={20} />
              </div>
              <span className="text-xl font-bold tracking-tight text-gray-900 dark:text-white">E-Rapi</span>
            </div>
          )}
          {isSidebarCollapsed && (
             <div className="bg-primary-600 dark:bg-primary-500 p-1.5 rounded-lg text-white">
                <Layers size={20} />
             </div>
          )}
        </div>

        {/* Toggle Button */}
        <button 
            onClick={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
            className="absolute -right-3 top-20 bg-white dark:bg-gray-700 border border-gray-200 dark:border-gray-600 rounded-full p-1 shadow-sm hover:bg-gray-50 dark:hover:bg-gray-600 text-gray-500 dark:text-gray-300"
        >
            {isSidebarCollapsed ? <ChevronRight size={14} /> : <ChevronLeft size={14} />}
        </button>

        <nav className="flex-1 p-3 space-y-2 overflow-y-auto overflow-x-hidden mt-4">
          {!isSidebarCollapsed && (
            <div className="text-xs font-semibold text-gray-400 dark:text-gray-500 uppercase tracking-wider mb-2 px-4 transition-opacity duration-300">
              Menu Utama
            </div>
          )}
          <NavItem id="DASHBOARD" label="Dashboard" icon={LayoutDashboard} />

          {/* Menu Dinamis berdasarkan Fitur Yayasan */}
          <NavItem id="EVENTS" label="Acara & Absensi" icon={CalendarDays} />
          <NavItem id="EDUCATORS" label="Tenaga Pendidik" icon={GraduationCap} />
          <NavItem id="FINANCE" label="Pengajuan Keuangan" icon={FileText} />
          <NavItem id="ORGANIZATIONS" label="Organisasi" icon={Building2} />
          <NavItem id="MEMBERS" label="Anggota" icon={Users} />
          <NavItem id="ROLES" label="Role & Akses" icon={ShieldCheck} />
          <NavItem id="DIVISIONS" label="Bidang" icon={Layers} />
          <NavItem id="PROGRAMS" label="Program Kerja" icon={Briefcase} />

          {/* Super Admin Menu */}
          {canAccess('MASTER_FOUNDATION') && (
              <>
                 <div className="my-2 border-t border-gray-100 dark:border-gray-700"></div>
                 <NavItem id="MASTER_FOUNDATION" label="Master Yayasan" icon={Globe} />
              </>
          )}
        </nav>

        <div className="p-4 border-t border-gray-100 dark:border-dark-border space-y-2">
          {activeFoundation && !isSidebarCollapsed && (
             <div className="mb-2 px-2 text-xs text-gray-400 text-center border-b border-gray-100 dark:border-gray-700 pb-2">
                 Yayasan Aktif:<br/>
                 <strong className="text-gray-600 dark:text-gray-300">{activeFoundation.name}</strong>
             </div>
          )}

          <button
            onClick={toggleFullScreen}
            title={isSidebarCollapsed ? (isFullScreen ? 'Keluar Full Screen' : 'Full Screen') : ''}
            className={`w-full flex items-center ${isSidebarCollapsed ? 'justify-center px-2' : 'space-x-3 px-4'} py-2 text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded-lg transition text-sm font-medium`}
          >
            {isFullScreen ? <Minimize2 size={20} /> : <Maximize2 size={20} />}
            {!isSidebarCollapsed && <span>{isFullScreen ? 'Exit Full Screen' : 'Full Screen'}</span>}
          </button>

          <button
            onClick={toggleTheme}
            title={isSidebarCollapsed ? (theme === 'light' ? 'Mode Gelap' : 'Mode Terang') : ''}
            className={`w-full flex items-center ${isSidebarCollapsed ? 'justify-center px-2' : 'space-x-3 px-4'} py-2 text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-gray-800 rounded-lg transition text-sm font-medium`}
          >
            {theme === 'light' ? <Moon size={20} /> : <Sun size={20} />}
            {!isSidebarCollapsed && <span>{theme === 'light' ? 'Mode Gelap' : 'Mode Terang'}</span>}
          </button>

          <button
            onClick={handleLogout}
            title={isSidebarCollapsed ? 'Keluar' : ''}
            className={`w-full flex items-center ${isSidebarCollapsed ? 'justify-center px-2' : 'space-x-3 px-4'} py-2 text-gray-600 dark:text-gray-400 hover:text-red-600 dark:hover:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition text-sm font-medium`}
          >
            <LogOut size={20} />
            {!isSidebarCollapsed && <span>Keluar</span>}
          </button>
        </div>
      </aside>

      {/* Mobile Header (Visible only on small screens) */}
      <div className="md:hidden fixed top-0 w-full bg-white dark:bg-dark-card border-b border-gray-200 dark:border-dark-border z-20 px-4 py-3 flex justify-between items-center transition-colors duration-200">
        <span className="font-bold text-gray-900 dark:text-white">E-Rapi</span>
        <div className="flex gap-2">
           <button onClick={toggleFullScreen} className="text-gray-500 dark:text-gray-400">
             {isFullScreen ? <Minimize2 size={20} /> : <Maximize2 size={20} />}
           </button>
           <button onClick={toggleTheme} className="text-gray-500 dark:text-gray-400">
             {theme === 'light' ? <Moon size={20} /> : <Sun size={20} />}
           </button>
           <button onClick={handleLogout} className="text-gray-500 dark:text-gray-400">
            <LogOut size={20} />
          </button>
        </div>
      </div>

      {/* Main Content */}
      <main className={`flex-1 ${isSidebarCollapsed ? 'md:ml-20' : 'md:ml-64'} p-4 md:p-8 mt-12 md:mt-0 overflow-y-auto transition-all duration-300 ease-in-out`}>
        {dbError && (
           <div className="mb-6 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 text-red-700 dark:text-red-400 px-4 py-3 rounded-lg">
             <div className="flex justify-between items-start">
                <div>
                    <p className="font-bold">Koneksi Database Gagal</p>
                    <p className="text-sm">Gagal mengambil data dari Supabase. Pastikan tabel telah dibuat.</p>
                </div>
                <button 
                    onClick={handleLogout}
                    className="bg-red-600 text-white px-3 py-1.5 rounded text-xs hover:bg-red-700 transition flex items-center gap-1"
                >
                    <LogOut size={12} /> Force Logout
                </button>
             </div>
             <Help />
           </div>
        )}

        {!dbError && loadingData ? (
          <div className="flex items-center justify-center h-64 text-gray-400">
            Memuat data...
          </div>
        ) : (
          <div className="max-w-7xl mx-auto animate-in fade-in duration-300 relative">

            {/* View Rendering with Permission Checks */}

            {view === 'DASHBOARD' && canAccess('DASHBOARD') && (
              <Dashboard 
                members={members} 
                programs={programs} 
                divisions={divisions} 
                events={events}
                attendance={attendance}
                isDarkMode={theme === 'dark'} 
              />
            )}
            {view === 'EVENTS' && canAccess('EVENTS') && (
              <Events 
                events={events}
                members={members}
                attendance={attendance}
                onRefresh={fetchData}
              />
            )}
            {view === 'EDUCATORS' && canAccess('EDUCATORS') && (
              <Educators 
                members={members}
                organizations={organizations}
                roles={roles}
              />
            )}
            {view === 'FINANCE' && canAccess('FINANCE') && (
              <Finance 
                programs={programs}
                divisions={divisions}
                organizations={organizations}
              />
            )}
            {view === 'ORGANIZATIONS' && canAccess('ORGANIZATIONS') && (
              <Organizations 
                data={organizations} 
                members={members}
                roles={roles}
                onRefresh={fetchData} 
              />
            )}
            {view === 'MEMBERS' && canAccess('MEMBERS') && (
              <Members 
                data={members} 
                roles={roles} 
                divisions={divisions} 
                organizations={organizations}
                onRefresh={fetchData} 
                currentUserEmail={session?.user?.email}
              />
            )}
            {view === 'ROLES' && canAccess('ROLES') && (
              <Roles 
                data={roles} 
                onRefresh={fetchData} 
              />
            )}
            {view === 'DIVISIONS' && canAccess('DIVISIONS') && (
              <Divisions 
                data={divisions} 
                members={members}
                programs={programs}
                onRefresh={fetchData} 
              />
            )}
            {view === 'PROGRAMS' && canAccess('PROGRAMS') && (
              <Programs 
                data={programs} 
                divisions={divisions} 
                organizations={organizations}
                members={members}
                onRefresh={fetchData} 
              />
            )}
            {view === 'MASTER_FOUNDATION' && canAccess('MASTER_FOUNDATION') && (
              <Foundations 
                data={foundations} 
                onRefresh={fetchData} 
              />
            )}

            {/* Access Denied / Fallback */}
            {!canAccess(view) && (
                <div className="flex flex-col items-center justify-center h-64 text-gray-400">
                    <Lock size={48} className="mb-4 text-gray-300 dark:text-gray-600" />
                    <h2 className="text-lg font-bold text-gray-600 dark:text-gray-300">Akses Ditolak / Fitur Nonaktif</h2>
                    <p className="text-center text-sm">
                        Anda tidak memiliki izin untuk melihat halaman ini, atau fitur ini belum diaktifkan untuk Yayasan ini.<br/>
                        Hubungi Super Admin jika ini kesalahan.
                    </p>
                </div>
            )}
          </div>
        )}
      </main>

      {/* Mobile Bottom Nav */}
      <div className="md:hidden fixed bottom-0 w-full bg-white dark:bg-dark-card border-t border-gray-200 dark:border-dark-border z-20 flex justify-around p-2 transition-colors duration-200 overflow-x-auto">
        {canAccess('DASHBOARD') && <button onClick={() => setView('DASHBOARD')} className={`p-2 rounded ${view === 'DASHBOARD' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><LayoutDashboard size={20}/></button>}
        {canAccess('EVENTS') && <button onClick={() => setView('EVENTS')} className={`p-2 rounded ${view === 'EVENTS' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><CalendarDays size={20}/></button>}
        {canAccess('FINANCE') && <button onClick={() => setView('FINANCE')} className={`p-2 rounded ${view === 'FINANCE' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><FileText size={20}/></button>}
        <button onClick={() => setView('MEMBERS')} className={`p-2 rounded ${view === 'MEMBERS' ? 'text-primary-600 dark:text-primary-400' : 'text-gray-400'}`}><Users size={20}/></button>
      </div>
    </div>
  );
};

export default App;
